static void RequestWorkViewRegenerate(NXOpen::Part* part)
{
	if (part == NULL || part->Views() == NULL || part->Views()->WorkView() == NULL)
	{
		return;
	}

	if (g_deferWorkViewRegenerate)
	{
		g_workViewRegeneratePending = true;
		return;
	}

	part->Views()->WorkView()->Regenerate();
}

static void FlushPendingWorkViewRegenerate(NXOpen::Part* part)
{
	if (!g_workViewRegeneratePending || part == NULL || part->Views() == NULL || part->Views()->WorkView() == NULL)
	{
		g_workViewRegeneratePending = false;
		return;
	}

	g_workViewRegeneratePending = false;
	part->Views()->WorkView()->Regenerate();
}

static void FlushAaaaWorkViewRegenerate(NXOpen::Part* part)
{
	if (g_suppressAaaaWorkViewFlush)
	{
		return;
	}

	FlushPendingWorkViewRegenerate(part);
}

static int UpdateDraftingViewsOnSheet(NXOpen::Part* part, NXOpen::Drawings::DrawingSheet* sheet)
{
	if (part == NULL || sheet == NULL)
	{
		return 0;
	}
	std::ostringstream perfLabel;
	perfLabel << "UpdateDraftingViewsOnSheet sheetTag=" << sheet->Tag();
	ScopedPerfTimer perfTimer(perfLabel.str());

	std::vector<NXOpen::Drawings::DraftingView*> draftingViews;
	try
	{
		sheet->Open();
		draftingViews = sheet->GetDraftingViews();
	}
	catch (...)
	{
		LayerDebugLog("[UpdateAllDraftingViews] get drafting views failed");
		return 0;
	}

	int updatedCount = 0;
	for (size_t i = 0; i < draftingViews.size(); ++i)
	{
		NXOpen::Drawings::DraftingView* draftingView = draftingViews[i];
		if (draftingView == NULL)
		{
			continue;
		}
		try
		{
			draftingView->Update();
			++updatedCount;
		}
		catch (...)
		{
			std::ostringstream oss;
			oss << "[UpdateAllDraftingViews] viewTag=" << draftingView->Tag()
				<< " result=failed";
			LayerDebugLog(oss.str());
		}
	}

	if (part->Views() != NULL && part->Views()->WorkView() != NULL)
	{
		try
		{
			part->Views()->WorkView()->Regenerate();
		}
		catch (...)
		{
		}
	}

	std::ostringstream oss;
	oss << "[UpdateAllDraftingViews] sheetTag=" << sheet->Tag()
		<< " viewCount=" << draftingViews.size()
		<< " updatedCount=" << updatedCount;
	LayerDebugLog(oss.str());
	return updatedCount;
}

static void UpdateAllDraftingViewsOnCurrentSheet(NXOpen::Part* part)
{
	if (part == NULL || part->DrawingSheets() == NULL)
	{
		return;
	}

	NXOpen::Drawings::DrawingSheet* currentSheet = part->DrawingSheets()->CurrentDrawingSheet();
	UpdateDraftingViewsOnSheet(part, currentSheet);
}

static void UpdateAllDraftingViewsOnAllSheets(NXOpen::Part* part)
{
	if (part == NULL || part->DrawingSheets() == NULL)
	{
		return;
	}
	ScopedPerfTimer perfTimer("UpdateAllDraftingViewsOnAllSheets");

	int sheetCount = 0;
	int updatedCount = 0;
	for (NXOpen::Drawings::DrawingSheetCollection::iterator it = part->DrawingSheets()->begin();
		it != part->DrawingSheets()->end();
		++it)
	{
		NXOpen::Drawings::DrawingSheet* sheet = *it;
		if (sheet == NULL)
		{
			continue;
		}
		++sheetCount;
		updatedCount += UpdateDraftingViewsOnSheet(part, sheet);
	}

	std::ostringstream oss;
	oss << "[UpdateAllDraftingViewsOnAllSheets] sheetCount=" << sheetCount
		<< " updatedCount=" << updatedCount;
	LayerDebugLog(oss.str());
}

