static bool GetToggleBlockValue(NXOpen::BlockStyler::Toggle* toggleBlock, bool fallback)
{
	if (toggleBlock == NULL)
	{
		return fallback;
	}

	PropertyList* toggleProps = toggleBlock->GetProperties();
	if (toggleProps == NULL)
	{
		return fallback;
	}

	const bool value = toggleProps->GetLogical("Value") != 0;
	delete toggleProps;
	toggleProps = NULL;
	return value;
}

static std::string GetStringBlockValue(NXOpen::BlockStyler::StringBlock* stringBlock, const std::string& fallback)
{
	if (stringBlock == NULL)
	{
		return fallback;
	}

	PropertyList* stringProps = stringBlock->GetProperties();
	if (stringProps == NULL)
	{
		return fallback;
	}

	const NXString nxValue = stringProps->GetString("Value");
	delete stringProps;
	stringProps = NULL;
	std::string value = nxValue.GetLocaleText();
	while (!value.empty() && std::isspace(static_cast<unsigned char>(value.front())))
	{
		value.erase(value.begin());
	}
	while (!value.empty() && std::isspace(static_cast<unsigned char>(value.back())))
	{
		value.pop_back();
	}
	return value.empty() ? fallback : value;
}

static double GetDoubleBlockValue(NXOpen::BlockStyler::DoubleBlock* doubleBlock, double fallback)
{
	if (doubleBlock == NULL)
	{
		return fallback;
	}

	PropertyList* doubleProps = doubleBlock->GetProperties();
	if (doubleProps == NULL)
	{
		return fallback;
	}

	const double value = doubleProps->GetDouble("Value");
	delete doubleProps;
	doubleProps = NULL;
	return value >= 0.0 ? value : fallback;
}

