static void CachePreparedIsoLayoutRect(NXOpen::Drawings::BaseView* isoView, const LayoutRect& rect)
{
	if (isoView == NULL)
	{
		return;
	}
	const tag_t viewTag = isoView->Tag();
	for (size_t i = 0; i < g_preparedIsoLayoutRects.size(); ++i)
	{
		if (g_preparedIsoLayoutRects[i].first == viewTag)
		{
			g_preparedIsoLayoutRects[i].second = rect;
			return;
		}
	}
	g_preparedIsoLayoutRects.push_back(std::make_pair(viewTag, rect));
}

static bool AskPreparedIsoLayoutRect(NXOpen::Drawings::BaseView* isoView, LayoutRect& rect)
{
	if (isoView == NULL)
	{
		return false;
	}
	const tag_t viewTag = isoView->Tag();
	for (size_t i = 0; i < g_preparedIsoLayoutRects.size(); ++i)
	{
		if (g_preparedIsoLayoutRects[i].first == viewTag)
		{
			rect = g_preparedIsoLayoutRects[i].second;
			return true;
		}
	}
	return false;
}

static double OverlapExtent(double aMin, double aMax, double bMin, double bMax)
{
	return std::max(0.0, std::min(aMax, bMax) - std::max(aMin, bMin));
}

static double RectOverlapArea(const LayoutRect& first, const LayoutRect& second)
{
	return OverlapExtent(first.minX, first.maxX, second.minX, second.maxX) *
		OverlapExtent(first.minY, first.maxY, second.minY, second.maxY);
}

static LayoutRect InflateRect(const LayoutRect& rect, double padding)
{
	return LayoutRect{
		rect.minX - padding,
		rect.minY - padding,
		rect.maxX + padding,
		rect.maxY + padding
	};
}

