static bool HasNonEmptyText(const char* text)
{
	if (text == NULL)
	{
		return false;
	}

	std::string value(text);
	value.erase(value.begin(), std::find_if(value.begin(), value.end(), [](unsigned char ch) {
		return !std::isspace(ch);
		}));
	value.erase(std::find_if(value.rbegin(), value.rend(), [](unsigned char ch) {
		return !std::isspace(ch);
		}).base(), value.end());
	return !value.empty();
}

static std::string TrimText(std::string value)
{
	value.erase(value.begin(), std::find_if(value.begin(), value.end(), [](unsigned char ch) {
		return !std::isspace(ch);
		}));
	value.erase(std::find_if(value.rbegin(), value.rend(), [](unsigned char ch) {
		return !std::isspace(ch);
		}).base(), value.end());
	return value;
}

static std::string RemoveUtf8Bom(const std::string& value)
{
	if (value.size() >= 3 &&
		static_cast<unsigned char>(value[0]) == 0xEF &&
		static_cast<unsigned char>(value[1]) == 0xBB &&
		static_cast<unsigned char>(value[2]) == 0xBF)
	{
		return value.substr(3);
	}
	return value;
}

static void ReplaceAllText(std::string& text, const std::string& from, const std::string& to)
{
	if (from.empty())
	{
		return;
	}

	size_t pos = 0;
	while ((pos = text.find(from, pos)) != std::string::npos)
	{
		text.replace(pos, from.size(), to);
		pos += to.size();
	}
}

static std::string DecodeConfigEscapes(const std::string& value)
{
	std::string result;
	bool escape = false;
	for (size_t i = 0; i < value.size(); ++i)
	{
		const char ch = value[i];
		if (escape)
		{
			switch (ch)
			{
			case 'n':
				result += '\n';
				break;
			case 'r':
				break;
			case 't':
				result += '\t';
				break;
			case '\\':
				result += '\\';
				break;
			case '"':
				result += '"';
				break;
			default:
				result += ch;
				break;
			}
			escape = false;
			continue;
		}

		if (ch == '\\')
		{
			escape = true;
			continue;
		}
		result += ch;
	}

	if (escape)
	{
		result += '\\';
	}
	return result;
}

static bool TryReadBodyNoteFormatLine(const std::string& rawLine, std::string& formatText)
{
	std::string line = TrimText(RemoveUtf8Bom(rawLine));
	if (line.empty() || line[0] == '#' || line[0] == ';')
	{
		return false;
	}
	if (line.front() == '[' && line.back() == ']')
	{
		return false;
	}

	const std::string key = "body_note_format";
	if (line.compare(0, key.size(), key) == 0)
	{
		const size_t equalPos = line.find('=');
		if (equalPos != std::string::npos)
		{
			line = TrimText(line.substr(equalPos + 1));
		}
	}

	if (line.empty())
	{
		return false;
	}

	formatText = DecodeConfigEscapes(line);
	return !formatText.empty();
}

static std::string LoadBodyNoteFormat()
{
	try
	{
		const std::wstring path = BodyNoteConfigFilePath();
		EnsureDefaultBodyNoteConfigFile(path);

		std::ifstream file(path, std::ios::binary);
		if (!file)
		{
			return kDefaultBodyNoteFormat;
		}

		std::string line;
		std::string formatText;
		std::string multiLineFormat;
		while (std::getline(file, line))
		{
			if (TryReadBodyNoteFormatLine(line, formatText))
			{
				if (!multiLineFormat.empty())
				{
					multiLineFormat += '\n';
				}
				multiLineFormat += formatText;
			}
		}
		if (!multiLineFormat.empty())
		{
			return multiLineFormat;
		}
	}
	catch (...)
	{
	}

	return kDefaultBodyNoteFormat;
}

static int BodyNoteFormatLineCount()
{
	const std::string format = LoadBodyNoteFormat();
	int lineCount = 1;
	for (size_t i = 0; i < format.size(); ++i)
	{
		if (format[i] == '\n')
		{
			++lineCount;
		}
	}
	return lineCount < 1 ? 1 : lineCount;
}

static double BodyNoteExtraDownOffset()
{
	const int lineCount = BodyNoteFormatLineCount();
	if (lineCount <= 1)
	{
		return 0.0;
	}
	return static_cast<double>(lineCount - 1) * 4.0;
}

static NXOpen::Point3d AdjustBodyNotePointForLineCount(const NXOpen::Point3d& point)
{
	NXOpen::Point3d adjusted = point;
	adjusted.Y -= BodyNoteExtraDownOffset();
	return adjusted;
}

static NXOpen::Point3d AdjustBodyNotePointForLineCount(const NXOpen::Point3d& point, bool hasBottomView)
{
	if (hasBottomView)
	{
		return point;
	}
	return AdjustBodyNotePointForLineCount(point);
}

static double BodyNoteBottomViewExtraGap()
{
	const int lineCount = BodyNoteFormatLineCount();
	if (lineCount <= 1)
	{
		return 0.0;
	}
	const double textHeight = 3.5;
	const double lineSpaceFactor = 1.5;
	const double noteBlockHeight = textHeight + static_cast<double>(lineCount - 1) * textHeight * lineSpaceFactor;
	const double noteSafetyGap = textHeight * 3.0;
	const double bottomViewDimensionBand = textHeight * 5.0;
	return noteBlockHeight + noteSafetyGap + bottomViewDimensionBand;
}

static double BodyNoteBottomViewGap()
{
	return BodyNoteBottomViewExtraGap();
}

static std::string FormatRealForNote(double value)
{
	std::ostringstream stream;
	if (std::fabs(value - std::round(value)) < 1.0e-6)
	{
		stream << static_cast<long long>(std::llround(value));
	}
	else
	{
		stream.setf(std::ios::fixed);
		stream.precision(3);
		stream << value;
		std::string text = stream.str();
		while (!text.empty() && text[text.size() - 1] == '0')
		{
			text.erase(text.size() - 1);
		}
		if (!text.empty() && text[text.size() - 1] == '.')
		{
			text.erase(text.size() - 1);
		}
		return text;
	}
	return stream.str();
}

static std::string LocaleTextToUtf8(const char* text)
{
	if (text == NULL || text[0] == '\0')
	{
		return "";
	}

	const int wideLength = MultiByteToWideChar(CP_ACP, 0, text, -1, NULL, 0);
	if (wideLength <= 0)
	{
		return text;
	}

	std::wstring wideText(static_cast<size_t>(wideLength), L'\0');
	if (MultiByteToWideChar(CP_ACP, 0, text, -1, &wideText[0], wideLength) <= 0)
	{
		return text;
	}

	const int utf8Length = WideCharToMultiByte(CP_UTF8, 0, wideText.c_str(), -1, NULL, 0, NULL, NULL);
	if (utf8Length <= 0)
	{
		return text;
	}

	std::string utf8Text(static_cast<size_t>(utf8Length), '\0');
	if (WideCharToMultiByte(CP_UTF8, 0, wideText.c_str(), -1, &utf8Text[0], utf8Length, NULL, NULL) <= 0)
	{
		return text;
	}
	if (!utf8Text.empty() && utf8Text[utf8Text.size() - 1] == '\0')
	{
		utf8Text.erase(utf8Text.size() - 1);
	}
	return utf8Text;
}

static std::string ReadAttributeText(NXOpen::NXObject* object, const char* title)
{
	if (object == NULL || title == NULL)
	{
		return "";
	}

	try
	{
		if (object->HasUserAttribute(title, NXObject::AttributeType::AttributeTypeString, -1))
		{
			return TrimText(LocaleTextToUtf8(object->GetStringAttribute(title).GetLocaleText()));
		}
		if (object->HasUserAttribute(title, NXObject::AttributeType::AttributeTypeInteger, -1))
		{
			return std::to_string(object->GetIntegerAttribute(title));
		}
		if (object->HasUserAttribute(title, NXObject::AttributeType::AttributeTypeReal, -1))
		{
			return FormatRealForNote(object->GetRealAttribute(title));
		}
	}
	catch (...)
	{
		return "";
	}
	return "";
}

