static std::string BuildBodyDraftNoteText(
	NXOpen::Annotations::TextWithSymbolsBuilder* textBlock,
	NXOpen::Part* part,
	NXOpen::Body* body)
{
	const std::string fileName = ReadPartFileNameReferenceText(textBlock, part);
	const std::string material = ReadMaterialDraftText(textBlock, part, body);
	std::string thickness = DraftAttributeReferenceText(textBlock, body, "Z");
	if (thickness.empty() && part != NULL && body != NULL)
	{
		try
		{
			const double bodyThickness = part->Features()->SheetmetalManager()->GetBodyThickness(body);
			if (bodyThickness > 1.0e-6)
			{
				SetStringUserAttribute(body, "Z", FormatRealForNote(bodyThickness));
				thickness = DraftAttributeReferenceText(textBlock, body, "Z");
			}
		}
		catch (...)
		{
		}
	}
	if (thickness.empty())
	{
		thickness = ReadAttributeText(body, "Z");
	}
	const std::string quantity = ReadBodyTotalQuantityDraftText(textBlock, part, body);
	std::string mirror = DraftAttributeReferenceText(textBlock, body, "MIRR");
	if (mirror.empty())
	{
		mirror = ReadAttributeText(body, "MIRR");
	}
	std::string number = DraftAttributeReferenceText(textBlock, body, "bianhao");
	if (number.empty())
	{
		number = ReadAttributeText(body, "bianhao");
	}

	std::string line = LoadBodyNoteFormat();
	ReplaceAllText(line, "{\xE6\x96\x87\xE4\xBB\xB6\xE5\x90\x8D}", fileName);
	ReplaceAllText(line, "{\xE7\xBC\x96\xE5\x8F\xB7=}", number.empty() ? "" : number + "=");
	ReplaceAllText(line, "{\xE7\xBC\x96\xE5\x8F\xB7}", number);
	ReplaceAllText(line, "{\xE6\x9D\x90\xE6\x96\x99}", material);
	ReplaceAllText(line, "{\xE5\x8E\x9A\xE5\xBA\xA6}", thickness);
	ReplaceAllText(line, "{\xE6\x95\xB0\xE9\x87\x8F}", quantity.empty() ? "1" : quantity);
	ReplaceAllText(line, "{\xE9\x95\x9C\xE5\x83\x8F}", mirror);
	return line;
}

static std::vector<NXOpen::NXString> BuildDraftNoteLines(const std::string& noteText)
{
	std::vector<NXOpen::NXString> lines;
	lines.push_back("");

	std::string current;
	for (size_t i = 0; i < noteText.size(); ++i)
	{
		const char ch = noteText[i];
		if (ch == '\r')
		{
			continue;
		}
		if (ch == '\n')
		{
			lines.push_back(NXOpen::NXString(current.c_str(), NXOpen::NXString::UTF8));
			current.clear();
			continue;
		}
		current += ch;
	}
	lines.push_back(NXOpen::NXString(current.c_str(), NXOpen::NXString::UTF8));
	return lines;
}

