static bool AppendDraftPlaceholderNxString(
	const std::string& format,
	size_t& index,
	NXOpen::NXString& line,
	const NXOpen::NXString& fileName,
	const NXOpen::NXString& material,
	const NXOpen::NXString& thickness,
	const NXOpen::NXString& quantity,
	const NXOpen::NXString& mirror,
	const NXOpen::NXString& number,
	bool hasNumber)
{
	const std::string fileToken = "{\xE6\x96\x87\xE4\xBB\xB6\xE5\x90\x8D}";
	const std::string numberEqToken = "{\xE7\xBC\x96\xE5\x8F\xB7=}";
	const std::string numberToken = "{\xE7\xBC\x96\xE5\x8F\xB7}";
	const std::string materialToken = "{\xE6\x9D\x90\xE6\x96\x99}";
	const std::string thicknessToken = "{\xE5\x8E\x9A\xE5\xBA\xA6}";
	const std::string quantityToken = "{\xE6\x95\xB0\xE9\x87\x8F}";
	const std::string mirrorToken = "{\xE9\x95\x9C\xE5\x83\x8F}";

	if (format.compare(index, fileToken.size(), fileToken) == 0)
	{
		line = line + fileName;
		index += fileToken.size();
		return true;
	}
	if (format.compare(index, numberEqToken.size(), numberEqToken) == 0)
	{
		if (hasNumber)
		{
			line = line + number + NXOpen::NXString("=", NXOpen::NXString::UTF8);
		}
		index += numberEqToken.size();
		return true;
	}
	if (format.compare(index, numberToken.size(), numberToken) == 0)
	{
		if (hasNumber)
		{
			line = line + number;
		}
		index += numberToken.size();
		return true;
	}
	if (format.compare(index, materialToken.size(), materialToken) == 0)
	{
		line = line + material;
		index += materialToken.size();
		return true;
	}
	if (format.compare(index, thicknessToken.size(), thicknessToken) == 0)
	{
		line = line + thickness;
		index += thicknessToken.size();
		return true;
	}
	if (format.compare(index, quantityToken.size(), quantityToken) == 0)
	{
		line = line + quantity;
		index += quantityToken.size();
		return true;
	}
	if (format.compare(index, mirrorToken.size(), mirrorToken) == 0)
	{
		line = line + mirror;
		index += mirrorToken.size();
		return true;
	}
	return false;
}

static std::vector<NXOpen::NXString> BuildBodyDraftNoteLines(
	NXOpen::Annotations::TextWithSymbolsBuilder* textBlock,
	NXOpen::Part* part,
	NXOpen::Body* body)
{
	NXOpen::NXString fileName("");
	NXOpen::NXString material("");
	NXOpen::NXString thickness("");
	NXOpen::NXString quantity("1");
	NXOpen::NXString mirror("");
	NXOpen::NXString number("");

	ReadPartFileNameDraftNxString(textBlock, part, fileName);
	ReadMaterialDraftNxString(textBlock, part, body, material);
	ReadBodyThicknessDraftNxString(textBlock, part, body, thickness);
	ReadBodyTotalQuantityDraftNxString(textBlock, part, body, quantity);
	ReadMirrorDraftNxString(textBlock, body, mirror);
	const bool hasNumber = ReadNumberDraftNxString(textBlock, body, number);

	std::vector<NXOpen::NXString> lines;
	lines.push_back("");

	const std::string format = LoadBodyNoteFormat();
	NXOpen::NXString currentLine("");
	std::string literal;
	for (size_t i = 0; i < format.size();)
	{
		if (format[i] == '\r')
		{
			++i;
			continue;
		}
		if (format[i] == '\n')
		{
			if (!literal.empty())
			{
				currentLine = currentLine + NXOpen::NXString(literal.c_str(), NXOpen::NXString::UTF8);
				literal.clear();
			}
			lines.push_back(currentLine);
			currentLine = NXOpen::NXString("");
			++i;
			continue;
		}

		size_t tokenIndex = i;
		NXOpen::NXString tokenLine = currentLine;
		if (AppendDraftPlaceholderNxString(format, tokenIndex, tokenLine, fileName, material, thickness, quantity, mirror, number, hasNumber))
		{
			if (!literal.empty())
			{
				currentLine = currentLine + NXOpen::NXString(literal.c_str(), NXOpen::NXString::UTF8);
				literal.clear();
			}
			AppendDraftPlaceholderNxString(format, i, currentLine, fileName, material, thickness, quantity, mirror, number, hasNumber);
			continue;
		}

		literal += format[i];
		++i;
	}
	if (!literal.empty())
	{
		currentLine = currentLine + NXOpen::NXString(literal.c_str(), NXOpen::NXString::UTF8);
	}
	lines.push_back(currentLine);
	return lines;
}

struct DraftNoteReferenceInsert
{
	enum Kind
	{
		KindAttribute,
		KindExpression
	};

	Kind kind;
	NXOpen::NXObject* owner;
	std::string title;
	std::string expressionName;
	int lineNo;
	int cursorPos;
};

static int Utf8CodePointCount(const std::string& text)
{
	int count = 0;
	for (size_t i = 0; i < text.size(); ++i)
	{
		const unsigned char ch = static_cast<unsigned char>(text[i]);
		if ((ch & 0xC0) != 0x80)
		{
			++count;
		}
	}
	return count;
}

static bool FindMaterialReferenceOwner(NXOpen::Part* part, NXOpen::Body* body, NXOpen::NXObject*& owner, std::string& title)
{
	const char* titles[] = {
		"cailiao",
		"\xE6\x9D\x90\xE6\x96\x99",
		"\xE6\x9D\x90\xE8\xB4\xA8"
	};
	for (size_t i = 0; i < sizeof(titles) / sizeof(titles[0]); ++i)
	{
		if (HasAnyUserAttribute(body, titles[i]))
		{
			owner = body;
			title = titles[i];
			return true;
		}
	}
	for (size_t i = 1; i < sizeof(titles) / sizeof(titles[0]); ++i)
	{
		if (HasAnyUserAttribute(part, titles[i]))
		{
			owner = part;
			title = titles[i];
			return true;
		}
	}
	if (HasAnyUserAttribute(part, "cailiao"))
	{
		owner = part;
		title = "cailiao";
		return true;
	}
	return false;
}

static bool EnsureBodyThicknessAttribute(NXOpen::Part* part, NXOpen::Body* body)
{
	if (HasAnyUserAttribute(body, "Z"))
	{
		return true;
	}
	if (part == NULL || body == NULL)
	{
		return false;
	}
	try
	{
		const double bodyThickness = part->Features()->SheetmetalManager()->GetBodyThickness(body);
		if (bodyThickness > 1.0e-6)
		{
			SetStringUserAttribute(body, "Z", FormatRealForNote(bodyThickness));
			return HasAnyUserAttribute(body, "Z");
		}
	}
	catch (...)
	{
	}
	return false;
}

static bool FindQuantityReference(NXOpen::Part* part, NXOpen::Body* body, DraftNoteReferenceInsert& insert)
{
	if (part != NULL && body != NULL)
	{
		try
		{
			const int bodyId = body->GetIntegerAttribute("BodyID");
			char expressionName[256] = {};
			sprintf(expressionName, "ZSuLian_%d", bodyId);
			if (part->Expressions()->FindObject(expressionName) != NULL)
			{
				insert.kind = DraftNoteReferenceInsert::KindExpression;
				insert.owner = NULL;
				insert.expressionName = expressionName;
				return true;
			}
		}
		catch (...)
		{
		}
	}
	if (HasAnyUserAttribute(body, "sulian"))
	{
		insert.kind = DraftNoteReferenceInsert::KindAttribute;
		insert.owner = body;
		insert.title = "sulian";
		return true;
	}
	if (HasAnyUserAttribute(body, "\xE6\x95\xB0\xE9\x87\x8F"))
	{
		insert.kind = DraftNoteReferenceInsert::KindAttribute;
		insert.owner = body;
		insert.title = "\xE6\x95\xB0\xE9\x87\x8F";
		return true;
	}
	return false;
}

static bool PrepareDraftNoteReferenceForToken(
	const std::string& token,
	NXOpen::Part* part,
	NXOpen::Body* body,
	DraftNoteReferenceInsert& insert,
	std::string& fallbackText,
	bool& appendEqual)
{
	appendEqual = false;
	fallbackText.clear();

	if (token == "{\xE6\x96\x87\xE4\xBB\xB6\xE5\x90\x8D}")
	{
		const std::string fileName = ReadPartFileNameText(part);
		if (!fileName.empty())
		{
			const char* title = "\xE6\x96\x87\xE4\xBB\xB6\xE5\x90\x8D";
			SetStringUserAttribute(part, title, fileName);
			if (HasAnyUserAttribute(part, title))
			{
				insert.kind = DraftNoteReferenceInsert::KindAttribute;
				insert.owner = part;
				insert.title = title;
				return true;
			}
			fallbackText = fileName;
		}
		return false;
	}

	if (token == "{\xE7\xBC\x96\xE5\x8F\xB7=}" || token == "{\xE7\xBC\x96\xE5\x8F\xB7}")
	{
		if (HasAnyUserAttribute(body, "bianhao"))
		{
			insert.kind = DraftNoteReferenceInsert::KindAttribute;
			insert.owner = body;
			insert.title = "bianhao";
			appendEqual = (token == "{\xE7\xBC\x96\xE5\x8F\xB7=}");
			return true;
		}
		return false;
	}

	if (token == "{\xE6\x9D\x90\xE6\x96\x99}")
	{
		NXOpen::NXObject* owner = NULL;
		std::string title;
		if (FindMaterialReferenceOwner(part, body, owner, title))
		{
			insert.kind = DraftNoteReferenceInsert::KindAttribute;
			insert.owner = owner;
			insert.title = title;
			return true;
		}
		fallbackText = ReadMaterialText(part, body);
		return false;
	}

	if (token == "{\xE5\x8E\x9A\xE5\xBA\xA6}")
	{
		if (EnsureBodyThicknessAttribute(part, body))
		{
			insert.kind = DraftNoteReferenceInsert::KindAttribute;
			insert.owner = body;
			insert.title = "Z";
			return true;
		}
		fallbackText = ReadAttributeText(body, "Z");
		return false;
	}

	if (token == "{\xE6\x95\xB0\xE9\x87\x8F}")
	{
		if (FindQuantityReference(part, body, insert))
		{
			return true;
		}
		fallbackText = ReadBodyTotalQuantityText(part, body);
		if (fallbackText.empty())
		{
			fallbackText = "1";
		}
		return false;
	}

	if (token == "{\xE9\x95\x9C\xE5\x83\x8F}")
	{
		if (HasAnyUserAttribute(body, "MIRR"))
		{
			insert.kind = DraftNoteReferenceInsert::KindAttribute;
			insert.owner = body;
			insert.title = "MIRR";
			return true;
		}
		fallbackText = ReadAttributeText(body, "MIRR");
		return false;
	}

	return false;
}

static bool MatchDraftNoteToken(const std::string& format, size_t index, std::string& token)
{
	const char* tokens[] = {
		"{\xE6\x96\x87\xE4\xBB\xB6\xE5\x90\x8D}",
		"{\xE7\xBC\x96\xE5\x8F\xB7=}",
		"{\xE7\xBC\x96\xE5\x8F\xB7}",
		"{\xE6\x9D\x90\xE6\x96\x99}",
		"{\xE5\x8E\x9A\xE5\xBA\xA6}",
		"{\xE6\x95\xB0\xE9\x87\x8F}",
		"{\xE9\x95\x9C\xE5\x83\x8F}"
	};
	for (size_t i = 0; i < sizeof(tokens) / sizeof(tokens[0]); ++i)
	{
		const std::string current = tokens[i];
		if (format.compare(index, current.size(), current) == 0)
		{
			token = current;
			return true;
		}
	}
	return false;
}

static void SetBodyDraftNoteTextFromConfig(
	NXOpen::Annotations::TextWithSymbolsBuilder* textBlock,
	NXOpen::Part* part,
	NXOpen::Body* body)
{
	if (textBlock == NULL)
	{
		return;
	}

	std::vector<NXOpen::NXString> emptyText(1);
	emptyText[0] = "";
	textBlock->SetText(emptyText);

	std::vector<NXOpen::NXString> lines;
	std::vector<DraftNoteReferenceInsert> inserts;
	std::string currentLine;
	int currentLineNo = 1;
	const std::string format = LoadBodyNoteFormat();

	for (size_t i = 0; i < format.size();)
	{
		if (format[i] == '\r')
		{
			++i;
			continue;
		}
		if (format[i] == '\n')
		{
			lines.push_back(NXOpen::NXString(currentLine.c_str(), NXOpen::NXString::UTF8));
			currentLine.clear();
			++currentLineNo;
			++i;
			continue;
		}

		std::string token;
		if (MatchDraftNoteToken(format, i, token))
		{
			DraftNoteReferenceInsert insert;
			std::string fallback;
			bool appendEqual = false;
			const int cursorPos = Utf8CodePointCount(currentLine) + 1;
			if (PrepareDraftNoteReferenceForToken(token, part, body, insert, fallback, appendEqual))
			{
				insert.lineNo = currentLineNo;
				insert.cursorPos = cursorPos;
				inserts.push_back(insert);
				if (appendEqual)
				{
					currentLine += "=";
				}
			}
			else
			{
				currentLine += fallback;
			}
			i += token.size();
			continue;
		}

		currentLine += format[i];
		++i;
	}
	lines.push_back(NXOpen::NXString(currentLine.c_str(), NXOpen::NXString::UTF8));
	if (lines.empty())
	{
		lines.push_back("");
	}

	textBlock->SetText(lines);

	std::sort(inserts.begin(), inserts.end(), [](const DraftNoteReferenceInsert& a, const DraftNoteReferenceInsert& b) {
		if (a.lineNo != b.lineNo)
		{
			return a.lineNo > b.lineNo;
		}
		return a.cursorPos > b.cursorPos;
	});

	for (size_t i = 0; i < inserts.size(); ++i)
	{
		try
		{
			const DraftNoteReferenceInsert& insert = inserts[i];
			if (insert.kind == DraftNoteReferenceInsert::KindAttribute)
			{
				textBlock->AddAttributeReference(insert.owner, insert.title.c_str(), false, insert.lineNo, insert.cursorPos);
			}
			else
			{
				textBlock->AddExpressionReference(insert.expressionName.c_str(), "0.2", insert.lineNo, insert.cursorPos);
			}
		}
		catch (...)
		{
		}
	}
}

static bool HasMeaningfulAttribute(NXOpen::NXObject* object, const char* title)
{
	if (object == NULL || title == NULL)
	{
		return false;
	}

	try
	{
		if (object->HasUserAttribute(title, NXObject::AttributeType::AttributeTypeString, -1))
		{
			NXString text = object->GetStringAttribute(title);
			return HasNonEmptyText(text.GetLocaleText());
		}
		if (object->HasUserAttribute(title, NXObject::AttributeType::AttributeTypeInteger, -1))
		{
			object->GetIntegerAttribute(title);
			return true;
		}
		if (object->HasUserAttribute(title, NXObject::AttributeType::AttributeTypeReal, -1))
		{
			object->GetRealAttribute(title);
			return true;
		}
	}
	catch (...)
	{
		return false;
	}

	return false;
}

static NXOpen::Body* FindLargestSolidBody(NXOpen::Part* part)
{
	if (part == NULL || part->Bodies() == NULL)
	{
		return NULL;
	}

	NXOpen::Body* largestBody = NULL;
	double largestScore = -1.0;
	for (NXOpen::BodyCollection::iterator bodyIt = part->Bodies()->begin(); bodyIt != part->Bodies()->end(); ++bodyIt)
	{
		NXOpen::Body* body = *bodyIt;
		if (body == NULL)
		{
			continue;
		}

		try
		{
			if (!body->IsSolidBody())
			{
				continue;
			}
		}
		catch (...)
		{
			continue;
		}

		const double score = EstimateBodySheetSizeScore(body);
		if (score > largestScore)
		{
			largestScore = score;
			largestBody = body;
		}
	}

	return largestBody;
}

static bool HasRequiredPartDrawingAttributes(NXOpen::Part* part)
{
	if (part == NULL)
	{
		return false;
	}

	const bool hasQuantity = HasMeaningfulAttribute(part, "数量");
	const bool hasMaterial = HasMeaningfulAttribute(part, "材料") || HasMeaningfulAttribute(part, "材质");
	return hasQuantity && hasMaterial;
}

static bool HasBodyQuantityAttribute(NXOpen::Body* body)
{
	return HasMeaningfulAttribute(body, "sulian") || HasMeaningfulAttribute(body, "数量");
}

static bool HasRequiredLargestBodyAttributes(NXOpen::Body* body)
{
	if (body == NULL)
	{
		return false;
	}

	return HasMeaningfulAttribute(body, "cailiao") && HasBodyQuantityAttribute(body);
}

static int CountSheetMetalBodies(NXOpen::Part* part)
{
	if (part == NULL || part->Bodies() == NULL)
	{
		return 0;
	}

	int count = 0;
	for (NXOpen::BodyCollection::iterator bodyIt = part->Bodies()->begin(); bodyIt != part->Bodies()->end(); ++bodyIt)
	{
		NXOpen::Body* body = *bodyIt;
		if (body != NULL && IsSheetMetalBody(body))
		{
			++count;
		}
	}

	return count;
}

static bool IsTaggedObjectDirectlyOnBody(NXOpen::TaggedObject* object, NXOpen::Body* targetBody)
{
	if (object == NULL || targetBody == NULL)
	{
		return false;
	}

	try
	{
		NXOpen::Body* body = dynamic_cast<NXOpen::Body*>(object);
		if (body != NULL)
		{
			return body == targetBody;
		}

		NXOpen::Face* face = dynamic_cast<NXOpen::Face*>(object);
		if (face != NULL)
		{
			return face->GetBody() == targetBody;
		}

		NXOpen::Edge* edge = dynamic_cast<NXOpen::Edge*>(object);
		if (edge != NULL)
		{
			return edge->GetBody() == targetBody;
		}
	}
	catch (...)
	{
		return false;
	}

	return false;
}

static bool IsTaggedObjectOnBody(NXOpen::TaggedObject* object, NXOpen::Body* targetBody)
{
	if (object == NULL || targetBody == NULL)
	{
		return false;
	}

	if (IsTaggedObjectDirectlyOnBody(object, targetBody))
	{
		return true;
	}

	int parentCount = 0;
	tag_t* parentTags = NULL;
	const int parentOptions = UF_SO_ASK_ALL_PARENTS |
		UF_SO_ASK_SO_PARENTS |
		UF_SO_ASK_WIREFRAME_PARENTS |
		UF_SO_ASK_PARENTS_RECURSIVELY;
	if (UF_SO_ask_parents(object->Tag(), parentOptions, &parentCount, &parentTags) != 0 || parentCount <= 0 || parentTags == NULL)
	{
		return false;
	}

	bool matched = false;
	for (int i = 0; i < parentCount; ++i)
	{
		if (parentTags[i] == NULL_TAG)
		{
			continue;
		}
		try
		{
			NXOpen::TaggedObject* parentObject = dynamic_cast<NXOpen::TaggedObject*>(NXOpen::NXObjectManager::Get(parentTags[i]));
			if (IsTaggedObjectDirectlyOnBody(parentObject, targetBody))
			{
				matched = true;
				break;
			}
		}
		catch (...)
		{
		}
	}

	UF_free(parentTags);
	return matched;
}

static bool AnyFlatPatternFaceDataReferencesBody(
	const std::vector<NXOpen::Features::FlatPattern::ObjectDataFace>& objects,
	NXOpen::Body* targetBody)
{
	for (size_t i = 0; i < objects.size(); ++i)
	{
		if (IsTaggedObjectOnBody(objects[i].FormedBodyObject, targetBody))
		{
			return true;
		}
	}
	return false;
}

static bool AnyFlatPatternGeneralDataReferencesBody(
	const std::vector<NXOpen::Features::FlatPattern::ObjectDataGeneral>& objects,
	NXOpen::Body* targetBody)
{
	for (size_t i = 0; i < objects.size(); ++i)
	{
		if (IsTaggedObjectOnBody(objects[i].FormedBodyObject, targetBody))
		{
			return true;
		}
	}
	return false;
}

static bool FlatPatternReferencesBody(NXOpen::Features::FlatPattern* flatPattern, NXOpen::Body* targetBody)
{
	if (flatPattern == NULL || targetBody == NULL)
	{
		return false;
	}

	try
	{
		std::vector<NXOpen::Features::FlatPattern::ObjectDataFace> faceObjects;
		flatPattern->GetBendUpCenterLines(faceObjects);
		if (AnyFlatPatternFaceDataReferencesBody(faceObjects, targetBody)) return true;

		faceObjects.clear();
		flatPattern->GetBendDownCenterLines(faceObjects);
		if (AnyFlatPatternFaceDataReferencesBody(faceObjects, targetBody)) return true;

		faceObjects.clear();
		flatPattern->GetInnerMoldLines(faceObjects);
		if (AnyFlatPatternFaceDataReferencesBody(faceObjects, targetBody)) return true;

		faceObjects.clear();
		flatPattern->GetOuterMoldLines(faceObjects);
		if (AnyFlatPatternFaceDataReferencesBody(faceObjects, targetBody)) return true;

		faceObjects.clear();
		flatPattern->GetLighteningHoleCenters(faceObjects);
		if (AnyFlatPatternFaceDataReferencesBody(faceObjects, targetBody)) return true;
	}
	catch (...)
	{
	}

	try
	{
		std::vector<NXOpen::Features::FlatPattern::ObjectDataGeneral> generalObjects;
		flatPattern->GetAddedTopGeometry(generalObjects);
		if (AnyFlatPatternGeneralDataReferencesBody(generalObjects, targetBody)) return true;

		generalObjects.clear();
		flatPattern->GetAddedBottomGeometry(generalObjects);
		if (AnyFlatPatternGeneralDataReferencesBody(generalObjects, targetBody)) return true;
	}
	catch (...)
	{
	}

	return false;
}

static bool FeatureOutputReferencesBody(NXOpen::Features::Feature* feature, NXOpen::Body* targetBody)
{
	if (feature == NULL || targetBody == NULL)
	{
		return false;
	}

	try
	{
		std::vector<NXOpen::Body*> bodies = feature->GetBodies();
		for (size_t i = 0; i < bodies.size(); ++i)
		{
			if (bodies[i] == targetBody)
			{
				return true;
			}
		}
	}
	catch (...)
	{
	}

	try
	{
		std::vector<NXOpen::Face*> faces = feature->GetFaces();
		for (size_t i = 0; i < faces.size(); ++i)
		{
			if (faces[i] != NULL && faces[i]->GetBody() == targetBody)
			{
				return true;
			}
		}
	}
	catch (...)
	{
	}

	try
	{
		std::vector<NXOpen::Edge*> edges = feature->GetEdges();
		for (size_t i = 0; i < edges.size(); ++i)
		{
			if (edges[i] != NULL && edges[i]->GetBody() == targetBody)
			{
				return true;
			}
		}
	}
	catch (...)
	{
	}

	return false;
}

static bool FlatPatternParentsReferenceBodyWithinDepth(
	NXOpen::Features::Feature* feature,
	NXOpen::Body* targetBody,
	int depth,
	std::unordered_set<tag_t>& visited)
{
	if (feature == NULL || targetBody == NULL || depth <= 0)
	{
		return false;
	}

	const tag_t featureTag = feature->Tag();
	if (featureTag == NULL_TAG || !visited.insert(featureTag).second)
	{
		return false;
	}

	try
	{
		std::vector<NXOpen::Features::Feature*> parents = feature->GetParents();
		for (size_t i = 0; i < parents.size(); ++i)
		{
			NXOpen::Features::Feature* parent = parents[i];
			if (FeatureOutputReferencesBody(parent, targetBody) ||
				FlatPatternParentsReferenceBodyWithinDepth(parent, targetBody, depth - 1, visited))
			{
				return true;
			}
		}
	}
	catch (...)
	{
		return false;
	}

	return false;
}

static bool FlatPatternParentsReferenceBodyWithinDepth(
	NXOpen::Features::Feature* feature,
	NXOpen::Body* targetBody,
	int depth)
{
	std::unordered_set<tag_t> visited;
	return FlatPatternParentsReferenceBodyWithinDepth(feature, targetBody, depth, visited);
}

static NXOpen::Body* GetFlatPatternUpwardBody(NXOpen::Features::SheetMetal::FlatPatternBuilder* flatPatternBuilder)
{
	if (flatPatternBuilder == NULL || flatPatternBuilder->UpwardFace() == NULL)
	{
		return NULL;
	}

	NXOpen::Face* upwardFace = flatPatternBuilder->UpwardFace()->Value();
	return upwardFace != NULL ? upwardFace->GetBody() : NULL;
}

static void ClearFlatPatternDraftingInfoCache()
{
	g_flatPatternDraftingInfoPartTag = NULL_TAG;
	g_flatPatternDraftingInfoFeatureCount = 0;
	g_flatPatternDraftingInfos.clear();
}

static const std::vector<FlatPatternDraftingInfo>& GetFlatPatternDraftingInfos(NXOpen::Part* part)
{
	static const std::vector<FlatPatternDraftingInfo> emptyInfos;
	if (part == NULL || part->Features() == NULL || part->Features()->SheetmetalManager() == NULL)
	{
		ClearFlatPatternDraftingInfoCache();
		return emptyInfos;
	}

	std::vector<Features::Feature*> features = part->Features()->GetFeatures();
	if (g_flatPatternDraftingInfoPartTag == part->Tag() &&
		g_flatPatternDraftingInfoFeatureCount == features.size() &&
		!g_flatPatternDraftingInfos.empty())
	{
		return g_flatPatternDraftingInfos;
	}

	g_flatPatternDraftingInfoPartTag = part->Tag();
	g_flatPatternDraftingInfoFeatureCount = features.size();
	g_flatPatternDraftingInfos.clear();
	for (size_t i = 0; i < features.size(); ++i)
	{
		NXOpen::Features::Feature* feature = features[i];
		if (feature == NULL || strcmp(feature->FeatureType().GetLocaleText(), "FLAT_PATTERN") != 0)
		{
			continue;
		}

		NXOpen::Features::SheetMetal::FlatPatternBuilder* flatPatternBuilder = NULL;
		try
		{
			NXOpen::Features::FlatPattern* flatPattern =
				dynamic_cast<NXOpen::Features::FlatPattern*>(NXOpen::NXObjectManager::Get(feature->Tag()));
			if (flatPattern == NULL)
			{
				continue;
			}

			flatPatternBuilder = part->Features()->SheetmetalManager()->CreateFlatPatternBuilder(flatPattern);
			if (flatPatternBuilder == NULL ||
				flatPatternBuilder->UpwardFace() == NULL ||
				flatPatternBuilder->UpwardFace()->Value() == NULL)
			{
			}
			else
			{
				FlatPatternDraftingInfo info{};
				info.feature = feature;
				info.flatPattern = flatPattern;
				info.upwardFace = flatPatternBuilder->UpwardFace()->Value();
				info.upwardBody = info.upwardFace != NULL ? info.upwardFace->GetBody() : NULL;
				info.xAxisEdge = flatPatternBuilder->XAxisEdge() != NULL ? flatPatternBuilder->XAxisEdge()->Value() : NULL;
				info.minimumX = 0.0;
				info.minimumY = 0.0;
				TryReadRealAttribute(flatPattern, "Minimum X", info.minimumX);
				TryReadRealAttribute(flatPattern, "Minimum Y", info.minimumY);
				info.flatPatternViewName = flatPatternBuilder->FlatPatternViewName();
				if (info.upwardBody != NULL)
				{
					g_flatPatternDraftingInfos.push_back(info);
				}
			}
		}
		catch (...)
		{
		}

		if (flatPatternBuilder != NULL)
		{
			try
			{
				flatPatternBuilder->Destroy();
			}
			catch (...)
			{
			}
		}
	}

	std::ostringstream oss;
	oss << "[FlatPatternDraftingInfoCache] partTag=" << part->Tag()
		<< " featureCount=" << features.size()
		<< " flatPatternCount=" << g_flatPatternDraftingInfos.size();
	PerfDebugLog(oss.str());
	return g_flatPatternDraftingInfos;
}

static bool IsDrawableSheetMetalBody(NXOpen::Body* body)
{
	if (body == NULL)
	{
		return false;
	}

	try
	{
		if (!body->IsSolidBody())
		{
			return false;
		}
	}
	catch (...)
	{
		return false;
	}

	return IsSheetMetalBody(body);
}

static bool FlatPatternFeatureReferencesBodyForDrawing(
	NXOpen::Features::Feature* feature,
	NXOpen::Features::FlatPattern* flatPattern,
	NXOpen::Body* targetBody)
{
	return FlatPatternReferencesBody(flatPattern, targetBody) ||
		FlatPatternParentsReferenceBodyWithinDepth(feature, targetBody, 2);
}

static NXOpen::Body* ChooseBodyForFlatPatternFeature(
	NXOpen::Part* part,
	NXOpen::Features::Feature* feature,
	NXOpen::Features::FlatPattern* flatPattern,
	NXOpen::Body* upwardBody)
{
	if (part == NULL || part->Bodies() == NULL || feature == NULL || flatPattern == NULL)
	{
		return NULL;
	}

	NXOpen::Body* bestBody = NULL;
	int bestScore = -1;
	for (NXOpen::BodyCollection::iterator bodyIt = part->Bodies()->begin(); bodyIt != part->Bodies()->end(); ++bodyIt)
	{
		NXOpen::Body* body = *bodyIt;
		if (!IsDrawableSheetMetalBody(body))
		{
			continue;
		}

		const bool directReference = FlatPatternReferencesBody(flatPattern, body);
		const bool parentReference = FlatPatternParentsReferenceBodyWithinDepth(feature, body, 2);
		if (!directReference && !parentReference)
		{
			continue;
		}

		int score = 0;
		if (directReference) score += 100;
		if (parentReference) score += 50;
		if (body != upwardBody) score += 20;
		if (HasRequiredLargestBodyAttributes(body)) score += 10;

		if (score > bestScore)
		{
			bestScore = score;
			bestBody = body;
		}
	}

	return bestBody;
}

static bool HasAnyFlatPatternFeature(NXOpen::Part* part)
{
	if (part == NULL || part->Features() == NULL)
	{
		return false;
	}

	try
	{
		std::vector<Features::Feature*> features = part->Features()->GetFeatures();
		for (size_t i = 0; i < features.size(); ++i)
		{
			NXOpen::Features::Feature* feature = features[i];
			if (feature == NULL)
			{
				continue;
			}

			if (strcmp(feature->FeatureType().GetLocaleText(), "FLAT_PATTERN") == 0)
			{
				return true;
			}
		}
	}
	catch (...)
	{
		return false;
	}

	return false;
}

static std::vector<NXOpen::TaggedObject*> CollectDrawableBodiesForPart(NXOpen::Part* part)
{
	std::vector<NXOpen::TaggedObject*> bodies;
	if (part == NULL || part->Features() == NULL || part->Features()->SheetmetalManager() == NULL || !HasAnyFlatPatternFeature(part))
	{
		return bodies;
	}

	std::set<tag_t> seenBodyTags;
	const std::vector<FlatPatternDraftingInfo>& flatPatternInfos = GetFlatPatternDraftingInfos(part);
	for (size_t i = 0; i < flatPatternInfos.size(); ++i)
	{
		NXOpen::Body* body = flatPatternInfos[i].upwardBody;
		if (body != NULL && seenBodyTags.insert(body->Tag()).second)
		{
			bodies.push_back(body);
		}
	}

	return bodies;
}

static void CollectChildPrototypePartsForDrawing(
	NXOpen::Assemblies::Component* component,
	std::vector<NXOpen::Part*>& parts,
	std::set<tag_t>& seenParts)
{
	if (component == NULL)
	{
		return;
	}

	std::vector<NXOpen::Assemblies::Component*> children = component->GetChildren();
	for (size_t i = 0; i < children.size(); ++i)
	{
		NXOpen::Assemblies::Component* child = children[i];
		if (child == NULL)
		{
			continue;
		}

		try
		{
			if (child->IsComponentOrAncestorSuppressed())
			{
				continue;
			}
		}
		catch (...)
		{
		}

		try
		{
			NXOpen::Part* prototypePart = dynamic_cast<NXOpen::Part*>(child->Prototype());
			if (prototypePart != NULL &&
				HasAnyFlatPatternFeature(prototypePart) &&
				seenParts.insert(prototypePart->Tag()).second)
			{
				parts.push_back(prototypePart);
			}
		}
		catch (...)
		{
		}

		CollectChildPrototypePartsForDrawing(child, parts, seenParts);
	}
}

static std::vector<NXOpen::Part*> CollectDrawableAssemblyParts(NXOpen::Part* assemblyPart)
{
	std::vector<NXOpen::Part*> parts;
	if (assemblyPart == NULL || assemblyPart->ComponentAssembly() == NULL)
	{
		return parts;
	}

	NXOpen::Assemblies::Component* root = assemblyPart->ComponentAssembly()->RootComponent();
	if (root == NULL || root->GetChildren().empty())
	{
		return parts;
	}

	std::set<tag_t> seenParts;
	CollectChildPrototypePartsForDrawing(root, parts, seenParts);
	return parts;
}

static std::string GetLaunchPrerequisiteMessage(NXOpen::Part* part)
{
	if (HasAnyFlatPatternFeature(part))
	{
		return "";
	}

	if (!CollectDrawableAssemblyParts(part).empty())
	{
		return "";
	}

	return "请先转钣金并展开";
}

static double RectOutOfBoundsPenalty(const LayoutRect& rect, const LayoutRect& bounds)
{
	double penalty = 0.0;
	if (rect.minX < bounds.minX) penalty += bounds.minX - rect.minX;
	if (rect.maxX > bounds.maxX) penalty += rect.maxX - bounds.maxX;
	if (rect.minY < bounds.minY) penalty += bounds.minY - rect.minY;
	if (rect.maxY > bounds.maxY) penalty += rect.maxY - bounds.maxY;
	return penalty;
}

static void AccumulateRectPoint(LayoutRect& rect, double x, double y, bool& initialized)
{
	if (!initialized)
	{
		rect.minX = x;
		rect.maxX = x;
		rect.minY = y;
		rect.maxY = y;
		initialized = true;
		return;
	}
	rect.minX = std::min(rect.minX, x);
	rect.maxX = std::max(rect.maxX, x);
	rect.minY = std::min(rect.minY, y);
	rect.maxY = std::max(rect.maxY, y);
}

static bool ExpandRectWithCurveInDrawing(tag_t viewTag, tag_t curveTag, LayoutRect& rect, bool& initialized)
{
	if (viewTag == NULL_TAG || curveTag == NULL_TAG)
	{
		return false;
	}

	UF_EVAL_p_t evaluator = NULL;
	if (UF_EVAL_initialize(curveTag, &evaluator) != 0 || evaluator == NULL)
	{
		return false;
	}

	bool expanded = false;
	double limits[2]{ 0.0, 0.0 };
	if (UF_EVAL_ask_limits(evaluator, limits) == 0)
	{
		const int sampleCount = 24;
		double derivatives[3]{ 0.0, 0.0, 0.0 };
		for (int i = 0; i <= sampleCount; ++i)
		{
			double t = (sampleCount == 0) ? limits[0] : (static_cast<double>(i) / static_cast<double>(sampleCount));
			double parm = limits[0] + (limits[1] - limits[0]) * t;
			double modelPoint[3]{ 0.0, 0.0, 0.0 };
			if (UF_EVAL_evaluate(evaluator, 0, parm, modelPoint, derivatives) == 0)
			{
				double drawingPoint[2]{ 0.0, 0.0 };
				if (UF_VIEW_map_model_to_drawing(viewTag, modelPoint, drawingPoint) == 0)
				{
					AccumulateRectPoint(rect, drawingPoint[0], drawingPoint[1], initialized);
					expanded = true;
				}
			}
		}
	}

	UF_EVAL_free(evaluator);
	return expanded;
}

static bool CurveBelongsToBody(NXOpen::Drawings::DraftingCurve* draftingCurve, NXOpen::Body* targetBody)
{
	if (draftingCurve == NULL || targetBody == NULL)
	{
		return false;
	}

	NXOpen::Drawings::DraftingCurveInfo* curveInfo = draftingCurve->GetDraftingCurveInfo();
	if (curveInfo == NULL)
	{
		return false;
	}

	std::vector<NXOpen::NXObject*> parents = curveInfo->GetParents();
	for (size_t i = 0; i < parents.size(); ++i)
	{
		NXOpen::NXObject* parent = parents[i];
		if (parent == NULL)
		{
			continue;
		}

		if (parent->Tag() == targetBody->Tag())
		{
			return true;
		}

		NXOpen::Body* parentBody = dynamic_cast<NXOpen::Body*>(parent);
		if (parentBody != NULL && parentBody->Tag() == targetBody->Tag())
		{
			return true;
		}

		NXOpen::Face* parentFace = dynamic_cast<NXOpen::Face*>(parent);
		if (parentFace != NULL && parentFace->GetBody() == targetBody)
		{
			return true;
		}

		NXOpen::Edge* parentEdge = dynamic_cast<NXOpen::Edge*>(parent);
		if (parentEdge != NULL && parentEdge->GetBody() == targetBody)
		{
			return true;
		}
	}

	return false;
}

static bool BodyMatchesTargetOrDraftingSource(NXOpen::Body* candidateBody, NXOpen::Body* targetBody)
{
	if (candidateBody == NULL || targetBody == NULL)
	{
		return false;
	}
	if (candidateBody->Tag() == targetBody->Tag())
	{
		return true;
	}
	std::unordered_map<tag_t, NXOpen::Body*>::const_iterator it = g_bodyDraftingSourceBodies.find(targetBody->Tag());
	if (it != g_bodyDraftingSourceBodies.end() && it->second != NULL && candidateBody->Tag() == it->second->Tag())
	{
		return true;
	}
	return false;
}

static NXOpen::Drawings::DraftingBody* FindDraftingBodyForTargetBody(
	NXOpen::Drawings::BaseView* baseView,
	NXOpen::Body* targetBody)
{
	if (baseView == NULL || targetBody == NULL)
	{
		return NULL;
	}
	const tag_t viewTag = baseView->Tag();
	const tag_t bodyTag = targetBody->Tag();
	for (size_t i = 0; i < g_draftingBodyCache.size(); ++i)
	{
		if (g_draftingBodyCache[i].viewTag == viewTag && g_draftingBodyCache[i].bodyTag == bodyTag)
		{
			return g_draftingBodyCache[i].draftingBody;
		}
	}

	NXOpen::Drawings::DraftingBodyCollection* draftingBodies = baseView->DraftingBodies();
	if (draftingBodies == NULL)
	{
		return NULL;
	}

	for (NXOpen::Drawings::DraftingBodyCollection::iterator bodyIt = draftingBodies->begin(); bodyIt != draftingBodies->end(); ++bodyIt)
	{
		NXOpen::Drawings::DraftingBody* draftingBody = (*bodyIt);
		if (draftingBody == NULL)
		{
			continue;
		}

		NXOpen::Drawings::DraftingCurveCollection* draftingCurves = draftingBody->DraftingCurves();
		if (draftingCurves == NULL)
		{
			continue;
		}

		for (NXOpen::Drawings::DraftingCurveCollection::iterator curveIt = draftingCurves->begin(); curveIt != draftingCurves->end(); ++curveIt)
		{
			NXOpen::Drawings::DraftingCurve* draftingCurve = (*curveIt);
			if (draftingCurve == NULL)
			{
				continue;
			}

			NXOpen::Drawings::DraftingCurveInfo* curveInfo = draftingCurve->GetDraftingCurveInfo();
			if (curveInfo == NULL)
			{
				continue;
			}

			std::vector<NXOpen::NXObject*> parents = curveInfo->GetParents();
			if (IsLayoutDebugEnabled())
			{
				std::ostringstream oss;
				oss << "[包围盒曲线父项数量]"
					<< " 视图Tag=" << baseView->Tag()
					<< " 视图BodyTag=" << draftingBody->Tag()
					<< " 曲线Tag=" << draftingCurve->Tag()
					<< " 父项数量=" << parents.size()
					<< " 目标实体BodyTag=" << targetBody->Tag();
				AppendLayoutDebug(oss.str());
			}
			for (size_t parentIndex = 0; parentIndex < parents.size(); ++parentIndex)
			{
				NXOpen::NXObject* parent = parents[parentIndex];
				if (parent == NULL)
				{
					if (IsLayoutDebugEnabled())
					{
						std::ostringstream oss;
						oss << "[包围盒父项空]"
							<< " 视图Tag=" << baseView->Tag()
							<< " 视图BodyTag=" << draftingBody->Tag()
							<< " 曲线Tag=" << draftingCurve->Tag()
							<< " 父项序号=" << parentIndex;
						AppendLayoutDebug(oss.str());
					}
					continue;
				}

				int type = 0;
				int subtype = 0;
				if (UF_OBJ_ask_type_and_subtype(parent->Tag(), &type, &subtype) != 0)
				{
					if (IsLayoutDebugEnabled())
					{
						std::ostringstream oss;
						oss << "[包围盒父项类型失败]"
							<< " 视图Tag=" << baseView->Tag()
							<< " 视图BodyTag=" << draftingBody->Tag()
							<< " 曲线Tag=" << draftingCurve->Tag()
							<< " 父项序号=" << parentIndex
							<< " 父项Tag=" << parent->Tag();
						AppendLayoutDebug(oss.str());
					}
					continue;
				}

				if (IsLayoutDebugEnabled())
				{
					std::ostringstream oss;
					oss << "[包围盒父项类型]"
						<< " 视图Tag=" << baseView->Tag()
						<< " 视图BodyTag=" << draftingBody->Tag()
						<< " 曲线Tag=" << draftingCurve->Tag()
						<< " 父项序号=" << parentIndex
						<< " 父项Tag=" << parent->Tag()
						<< " type=" << type
						<< " subtype=" << subtype;
					AppendLayoutDebug(oss.str());
				}

				if (subtype == UF_solid_face_subtype)
				{
					NXOpen::Face* face = dynamic_cast<NXOpen::Face*>(NXOpen::NXObjectManager::Get(parent->Tag()));
					if (IsLayoutDebugEnabled())
					{
						std::ostringstream oss;
						oss << "[包围盒父项检查]"
							<< " 视图Tag=" << baseView->Tag()
							<< " 视图BodyTag=" << draftingBody->Tag()
							<< " 曲线Tag=" << draftingCurve->Tag()
							<< " 父项序号=" << parentIndex
							<< " 父项Tag=" << parent->Tag()
							<< " 父项类型=面"
							<< " 目标实体BodyTag=" << targetBody->Tag()
							<< " 父项对应BodyTag=" << (face != NULL && face->GetBody() != NULL ? face->GetBody()->Tag() : NULL_TAG);
						AppendLayoutDebug(oss.str());
					}
					if (face != NULL && BodyMatchesTargetOrDraftingSource(face->GetBody(), targetBody))
					{
						if (IsLayoutDebugEnabled())
						{
							std::ostringstream hitOss;
							hitOss << "[包围盒Body命中]"
								<< " 视图Tag=" << baseView->Tag()
								<< " 视图BodyTag=" << draftingBody->Tag()
								<< " 曲线Tag=" << draftingCurve->Tag()
								<< " 父项Tag=" << parent->Tag()
								<< " 父项序号=" << parentIndex
								<< " 命中类型=面";
							AppendLayoutDebug(hitOss.str());
						}
						DraftingBodyCacheItem cacheItem{ viewTag, bodyTag, draftingBody };
						g_draftingBodyCache.push_back(cacheItem);
						return draftingBody;
					}
				}
				else if (subtype == UF_solid_edge_subtype)
				{
					NXOpen::Edge* edge = dynamic_cast<NXOpen::Edge*>(NXOpen::NXObjectManager::Get(parent->Tag()));
					if (IsLayoutDebugEnabled())
					{
						std::ostringstream oss;
						oss << "[包围盒父项检查]"
							<< " 视图Tag=" << baseView->Tag()
							<< " 视图BodyTag=" << draftingBody->Tag()
							<< " 曲线Tag=" << draftingCurve->Tag()
							<< " 父项序号=" << parentIndex
							<< " 父项Tag=" << parent->Tag()
							<< " 父项类型=边"
							<< " 目标实体BodyTag=" << targetBody->Tag()
							<< " 父项对应BodyTag=" << (edge != NULL && edge->GetBody() != NULL ? edge->GetBody()->Tag() : NULL_TAG);
						AppendLayoutDebug(oss.str());
					}
					if (edge != NULL && BodyMatchesTargetOrDraftingSource(edge->GetBody(), targetBody))
					{
						if (IsLayoutDebugEnabled())
						{
							std::ostringstream hitOss;
							hitOss << "[包围盒Body命中]"
								<< " 视图Tag=" << baseView->Tag()
								<< " 视图BodyTag=" << draftingBody->Tag()
								<< " 曲线Tag=" << draftingCurve->Tag()
								<< " 父项Tag=" << parent->Tag()
								<< " 父项序号=" << parentIndex
								<< " 命中类型=边";
							AppendLayoutDebug(hitOss.str());
						}
						DraftingBodyCacheItem cacheItem{ viewTag, bodyTag, draftingBody };
						g_draftingBodyCache.push_back(cacheItem);
						return draftingBody;
					}
				}
			}
		}
	}

	if (IsLayoutDebugEnabled())
	{
		std::ostringstream missOss;
		missOss << "[包围盒Body未命中] viewTag=" << baseView->Tag()
			<< " targetBodyTag=" << targetBody->Tag();
		AppendLayoutDebug(missOss.str());
	}
	return NULL;
}

static bool AskDisplayedCurveRect(NXOpen::Drawings::BaseView* baseView, NXOpen::Body* targetBody, LayoutRect& rect)
{
	if (baseView == NULL || targetBody == NULL)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << (baseView != NULL ? baseView->Tag() : NULL_TAG)
				<< " targetBodyTag=" << (targetBody != NULL ? targetBody->Tag() : NULL_TAG)
				<< " 原因=视图或实体为空";
			AppendLayoutDebug(oss.str());
		}
		return false;
	}

	NXOpen::Drawings::DraftingBody* draftingBody = FindDraftingBodyForTargetBody(baseView, targetBody);
	if (draftingBody == NULL)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << (baseView != NULL ? baseView->Tag() : NULL_TAG)
				<< " targetBodyTag=" << (targetBody != NULL ? targetBody->Tag() : NULL_TAG)
				<< " 原因=未找到对应DraftingBody";
			AppendLayoutDebug(oss.str());
		}
		return false;
	}

	bool initialized = false;
	NXOpen::Drawings::DraftingCurveCollection* draftingCurves = draftingBody->DraftingCurves();
	if (draftingCurves == NULL)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << baseView->Tag()
				<< " targetBodyTag=" << targetBody->Tag()
				<< " draftingBodyTag=" << draftingBody->Tag()
				<< " 原因=DraftingCurves为空";
			AppendLayoutDebug(oss.str());
		}
		return false;
	}

	for (NXOpen::Drawings::DraftingCurveCollection::iterator curveIt = draftingCurves->begin(); curveIt != draftingCurves->end(); ++curveIt)
	{
		NXOpen::Drawings::DraftingCurve* draftingCurve = (*curveIt);
		if (draftingCurve == NULL)
		{
			continue;
		}

		NXOpen::DisplayableObject* displayableCurve = dynamic_cast<NXOpen::DisplayableObject*>(draftingCurve);
		if (displayableCurve != NULL && displayableCurve->IsBlanked())
		{
			continue;
		}

		ExpandRectWithCurveInDrawing(baseView->Tag(), draftingCurve->Tag(), rect, initialized);
	}

	const bool valid = initialized && rect.maxX > rect.minX && rect.maxY > rect.minY;
	if (!valid)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << baseView->Tag()
				<< " targetBodyTag=" << targetBody->Tag()
				<< " draftingBodyTag=" << draftingBody->Tag()
				<< " initialized=" << (initialized ? "true" : "false")
				<< " rect=" << RectToString(rect)
				<< " 原因=包围盒退化";
			AppendLayoutDebug(oss.str());
		}
	}
	else
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒成功] viewTag=" << baseView->Tag()
				<< " targetBodyTag=" << targetBody->Tag()
				<< " draftingBodyTag=" << draftingBody->Tag()
				<< " rect=" << RectToString(rect);
			AppendLayoutDebug(oss.str());
		}
	}
	return valid;
}

static bool AskDisplayedCurveRectFromWholeView(NXOpen::Drawings::BaseView* baseView, LayoutRect& rect)
{
	if (baseView == NULL)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << NULL_TAG
				<< " 原因=主视图为空";
			AppendLayoutDebug(oss.str());
		}
		return false;
	}

	bool initialized = false;
	NXOpen::Drawings::DraftingBodyCollection* draftingBodies = baseView->DraftingBodies();
	if (draftingBodies == NULL)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << baseView->Tag()
				<< " 原因=主视图DraftingBodies为空";
			AppendLayoutDebug(oss.str());
		}
		return false;
	}

	for (NXOpen::Drawings::DraftingBodyCollection::iterator bodyIt = draftingBodies->begin(); bodyIt != draftingBodies->end(); ++bodyIt)
	{
		NXOpen::Drawings::DraftingBody* draftingBody = (*bodyIt);
		if (draftingBody == NULL)
		{
			continue;
		}

		NXOpen::Drawings::DraftingCurveCollection* draftingCurves = draftingBody->DraftingCurves();
		if (draftingCurves == NULL)
		{
			continue;
		}

		for (NXOpen::Drawings::DraftingCurveCollection::iterator curveIt = draftingCurves->begin(); curveIt != draftingCurves->end(); ++curveIt)
		{
			NXOpen::Drawings::DraftingCurve* draftingCurve = (*curveIt);
			if (draftingCurve == NULL)
			{
				continue;
			}

			NXOpen::DisplayableObject* displayableCurve = dynamic_cast<NXOpen::DisplayableObject*>(draftingCurve);
			if (displayableCurve != NULL && displayableCurve->IsBlanked())
			{
				continue;
			}

			ExpandRectWithCurveInDrawing(baseView->Tag(), draftingCurve->Tag(), rect, initialized);
		}
	}

	const bool valid = initialized && rect.maxX > rect.minX && rect.maxY > rect.minY;
	if (!valid)
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒失败] viewTag=" << baseView->Tag()
				<< " 原因=主视图整视图包围盒退化"
				<< " rect=" << RectToString(rect);
			AppendLayoutDebug(oss.str());
		}
	}
	else
	{
		if (IsLayoutDebugEnabled())
		{
			std::ostringstream oss;
			oss << "[包围盒成功] viewTag=" << baseView->Tag()
				<< " 模式=主视图整视图"
				<< " rect=" << RectToString(rect);
			AppendLayoutDebug(oss.str());
		}
	}
	return valid;
}

static bool AskDisplayedCurveRectForLayout(NXOpen::Drawings::BaseView* baseView, NXOpen::Body* targetBody, LayoutRect& rect)
{
	if (AskDisplayedCurveRect(baseView, targetBody, rect))
	{
		return true;
	}
	std::ostringstream oss;
	oss << "[LayoutRectMissing] viewTag=" << (baseView != NULL ? baseView->Tag() : NULL_TAG)
		<< " targetBodyTag=" << (targetBody != NULL ? targetBody->Tag() : NULL_TAG);
	LayerDebugLog(oss.str());
	return false;
}

