struct CurveAssocCandidate
{
	NXOpen::Drawings::DraftingCurve* curve;
	NXOpen::InferSnapType::SnapType snapType;
	NXOpen::Point3d modelPoint;
};

static bool FindOverallDimensionCurvePair(
	NXOpen::Drawings::BaseView* baseView,
	const std::vector<NXOpen::Drawings::DraftingCurve*>& curves,
	const LayoutRect& rect,
	bool horizontalDimension,
	CurveAssocCandidate& first,
	CurveAssocCandidate& second)
{
	if (baseView == NULL || curves.empty())
	{
		return false;
	}

	const double tolerance = 0.2;
	bool firstFound = false;
	bool secondFound = false;
	double firstMetric = horizontalDimension ? -1.0e99 : 1.0e99;
	double secondMetric = horizontalDimension ? -1.0e99 : 1.0e99;

	for (size_t i = 0; i < curves.size(); ++i)
	{
		NXOpen::Drawings::DraftingCurve* curve = curves[i];
		if (curve == NULL)
		{
			continue;
		}

		UF_EVAL_p_t evaluator = NULL;
		if (UF_EVAL_initialize(curve->Tag(), &evaluator) != 0 || evaluator == NULL)
		{
			continue;
		}

		bool isLine = false;
		if (UF_EVAL_is_line(evaluator, &isLine) == 0 && isLine)
		{
			UF_CURVE_line_t lineData;
			if (UF_CURVE_ask_line_data(curve->Tag(), &lineData) == 0)
			{
				double p1[2] = { 0.0, 0.0 };
				double p2[2] = { 0.0, 0.0 };
				UF_VIEW_map_model_to_drawing(baseView->Tag(), lineData.start_point, p1);
				UF_VIEW_map_model_to_drawing(baseView->Tag(), lineData.end_point, p2);
				const bool verticalLine = fabs(p1[0] - p2[0]) < tolerance;
				const bool horizontalLine = fabs(p1[1] - p2[1]) < tolerance;
				const bool diagonalLine = fabs(p1[0] - p2[0]) > tolerance && fabs(p1[1] - p2[1]) > tolerance;

				if (horizontalDimension)
				{
					if (verticalLine && fabs(p1[0] - rect.maxX) < tolerance)
					{
						const bool useStart = p1[1] > p2[1];
						const double metric = useStart ? p1[1] : p2[1];
						if (!firstFound || metric > firstMetric)
						{
							firstFound = true;
							firstMetric = metric;
							first.curve = curve;
							first.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							first.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
					else if (!firstFound && diagonalLine)
					{
						if (fabs(p1[0] - rect.maxX) < tolerance)
						{
							firstFound = true;
							first.curve = curve;
							first.snapType = NXOpen::InferSnapType::SnapTypeStart;
							first.modelPoint = { lineData.start_point[0], lineData.start_point[1], lineData.start_point[2] };
						}
						if (fabs(p2[0] - rect.maxX) < tolerance)
						{
							firstFound = true;
							first.curve = curve;
							first.snapType = NXOpen::InferSnapType::SnapTypeEnd;
							first.modelPoint = { lineData.end_point[0], lineData.end_point[1], lineData.end_point[2] };
						}
					}

					if (verticalLine && fabs(p1[0] - rect.minX) < tolerance)
					{
						const bool useStart = p1[1] > p2[1];
						const double metric = useStart ? p1[1] : p2[1];
						if (!secondFound || metric > secondMetric)
						{
							secondFound = true;
							secondMetric = metric;
							second.curve = curve;
							second.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							second.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
					else if (!secondFound && diagonalLine)
					{
						if (fabs(p1[0] - rect.minX) < tolerance)
						{
							secondFound = true;
							second.curve = curve;
							second.snapType = NXOpen::InferSnapType::SnapTypeStart;
							second.modelPoint = { lineData.start_point[0], lineData.start_point[1], lineData.start_point[2] };
						}
						if (fabs(p2[0] - rect.minX) < tolerance)
						{
							secondFound = true;
							second.curve = curve;
							second.snapType = NXOpen::InferSnapType::SnapTypeEnd;
							second.modelPoint = { lineData.end_point[0], lineData.end_point[1], lineData.end_point[2] };
						}
					}
				}
				else
				{
					if (horizontalLine && fabs(p1[1] - rect.maxY) < tolerance)
					{
						const bool useStart = p1[0] < p2[0];
						const double metric = useStart ? p1[0] : p2[0];
						if (!firstFound || metric < firstMetric)
						{
							firstFound = true;
							firstMetric = metric;
							first.curve = curve;
							first.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							first.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
					else if (!firstFound && diagonalLine)
					{
						if (fabs(p1[1] - rect.maxY) < tolerance)
						{
							firstFound = true;
							first.curve = curve;
							first.snapType = NXOpen::InferSnapType::SnapTypeStart;
							first.modelPoint = { lineData.start_point[0], lineData.start_point[1], lineData.start_point[2] };
						}
						if (fabs(p2[1] - rect.maxY) < tolerance)
						{
							firstFound = true;
							first.curve = curve;
							first.snapType = NXOpen::InferSnapType::SnapTypeEnd;
							first.modelPoint = { lineData.end_point[0], lineData.end_point[1], lineData.end_point[2] };
						}
					}

					if (horizontalLine && fabs(p1[1] - rect.minY) < tolerance)
					{
						const bool useStart = p1[0] < p2[0];
						const double metric = useStart ? p1[0] : p2[0];
						if (!secondFound || metric < secondMetric)
						{
							secondFound = true;
							secondMetric = metric;
							second.curve = curve;
							second.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							second.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
					else if (!secondFound && diagonalLine)
					{
						if (fabs(p1[1] - rect.minY) < tolerance)
						{
							secondFound = true;
							second.curve = curve;
							second.snapType = NXOpen::InferSnapType::SnapTypeStart;
							second.modelPoint = { lineData.start_point[0], lineData.start_point[1], lineData.start_point[2] };
						}
						if (fabs(p2[1] - rect.minY) < tolerance)
						{
							secondFound = true;
							second.curve = curve;
							second.snapType = NXOpen::InferSnapType::SnapTypeEnd;
							second.modelPoint = { lineData.end_point[0], lineData.end_point[1], lineData.end_point[2] };
						}
					}
				}
			}
		}
		UF_EVAL_free(evaluator);
	}

	if (firstFound && secondFound)
	{
		return true;
	}

	double firstFallbackMetric = horizontalDimension ? 1.0e99 : -1.0e99;
	double secondFallbackMetric = horizontalDimension ? 1.0e99 : -1.0e99;
	bool firstArcFound = false;
	bool secondArcFound = false;

	for (size_t i = 0; i < curves.size(); ++i)
	{
		NXOpen::Drawings::DraftingCurve* curve = curves[i];
		if (curve == NULL)
		{
			continue;
		}

		UF_EVAL_p_t evaluator = NULL;
		if (UF_EVAL_initialize(curve->Tag(), &evaluator) != 0 || evaluator == NULL)
		{
			continue;
		}

		bool isArc = false;
		if (UF_EVAL_is_arc(evaluator, &isArc) == 0 && isArc)
		{
			UF_EVAL_arc_t arcData;
			if (UF_EVAL_ask_arc(evaluator, &arcData) == 0)
			{
				double center2d[2] = { 0.0, 0.0 };
				UF_VIEW_map_model_to_drawing(baseView->Tag(), arcData.center, center2d);
				const double radius2d = arcData.radius;
				const double aMaxX = center2d[0] + radius2d;
				const double aMinX = center2d[0] - radius2d;
				const double aMaxY = center2d[1] + radius2d;
				const double aMinY = center2d[1] - radius2d;

				double limits[2] = { 0.0, 0.0 };
				double p1[3] = { 0.0, 0.0, 0.0 };
				double p2[3] = { 0.0, 0.0, 0.0 };
				double d1[2] = { 0.0, 0.0 };
				double d2[2] = { 0.0, 0.0 };
				if (UF_EVAL_ask_limits(evaluator, limits) == 0)
				{
					double junk[3] = { 0.0, 0.0, 0.0 };
					double deriv[9] = { 0.0 };
					UF_EVAL_evaluate(evaluator, 0, limits[0], p1, deriv);
					UF_EVAL_evaluate(evaluator, 0, limits[1], p2, deriv);
					UF_VIEW_map_model_to_drawing(baseView->Tag(), p1, d1);
					UF_VIEW_map_model_to_drawing(baseView->Tag(), p2, d2);
				}

				if (horizontalDimension)
				{
					if ((!firstFound) &&
						((fabs(aMaxX - rect.maxX) < tolerance && center2d[1] > firstFallbackMetric) ||
						 fabs(d1[0] - rect.maxX) < tolerance ||
						 fabs(d2[0] - rect.maxX) < tolerance))
					{
						firstArcFound = true;
						firstFallbackMetric = center2d[1];
						first.curve = curve;
						first.snapType = NXOpen::InferSnapType::SnapTypeDrfTangent;
						first.modelPoint = { 999999.0, center2d[1], 0.0 };
					}
					if ((!secondFound) &&
						((fabs(aMinX - rect.minX) < tolerance && center2d[1] > secondFallbackMetric) ||
						 fabs(d1[0] - rect.minX) < tolerance ||
						 fabs(d2[0] - rect.minX) < tolerance))
					{
						secondArcFound = true;
						secondFallbackMetric = center2d[1];
						second.curve = curve;
						second.snapType = NXOpen::InferSnapType::SnapTypeDrfTangent;
						second.modelPoint = { -999999.0, center2d[1], 0.0 };
					}
				}
				else
				{
					if ((!firstFound) && fabs(aMaxY - rect.maxY) < tolerance && center2d[0] < firstFallbackMetric)
					{
						firstArcFound = true;
						firstFallbackMetric = center2d[0];
						first.curve = curve;
						first.snapType = NXOpen::InferSnapType::SnapTypeDrfTangent;
						first.modelPoint = { center2d[0], 999999.0, 0.0 };
					}
					if ((!secondFound) && fabs(aMinY - rect.minY) < tolerance && center2d[0] < secondFallbackMetric)
					{
						secondArcFound = true;
						secondFallbackMetric = center2d[0];
						second.curve = curve;
						second.snapType = NXOpen::InferSnapType::SnapTypeDrfTangent;
						second.modelPoint = { center2d[0], -999999.0, 0.0 };
					}
				}
			}
		}

		UF_EVAL_free(evaluator);
	}

	if (!firstFound && firstArcFound)
	{
		firstFound = true;
	}
	if (!secondFound && secondArcFound)
	{
		secondFound = true;
	}
	return firstFound && secondFound;
}

static bool FindOverallDimensionCurvePairFallback(
	NXOpen::Drawings::BaseView* baseView,
	const std::vector<NXOpen::Drawings::DraftingCurve*>& curves,
	const LayoutRect& rect,
	bool horizontalDimension,
	CurveAssocCandidate& first,
	CurveAssocCandidate& second)
{
	if (baseView == NULL || curves.empty())
	{
		return false;
	}

	const double tolerance = 0.3;
	bool firstFound = false;
	bool secondFound = false;
	double firstScore = -1.0e99;
	double secondScore = -1.0e99;

	for (size_t i = 0; i < curves.size(); ++i)
	{
		NXOpen::Drawings::DraftingCurve* curve = curves[i];
		if (curve == NULL)
		{
			continue;
		}

		UF_EVAL_p_t evaluator = NULL;
		if (UF_EVAL_initialize(curve->Tag(), &evaluator) != 0 || evaluator == NULL)
		{
			continue;
		}

		bool isLine = false;
		if (UF_EVAL_is_line(evaluator, &isLine) == 0 && isLine)
		{
			UF_CURVE_line_t lineData;
			if (UF_CURVE_ask_line_data(curve->Tag(), &lineData) == 0)
			{
				double p1[2] = { 0.0, 0.0 };
				double p2[2] = { 0.0, 0.0 };
				UF_VIEW_map_model_to_drawing(baseView->Tag(), lineData.start_point, p1);
				UF_VIEW_map_model_to_drawing(baseView->Tag(), lineData.end_point, p2);

				if (horizontalDimension)
				{
					if (fabs(p1[0] - rect.maxX) < tolerance || fabs(p2[0] - rect.maxX) < tolerance)
					{
						const bool useStart = fabs(p1[0] - rect.maxX) <= fabs(p2[0] - rect.maxX);
						const double score = useStart ? p1[1] : p2[1];
						if (!firstFound || score > firstScore)
						{
							firstFound = true;
							firstScore = score;
							first.curve = curve;
							first.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							first.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
					if (fabs(p1[0] - rect.minX) < tolerance || fabs(p2[0] - rect.minX) < tolerance)
					{
						const bool useStart = fabs(p1[0] - rect.minX) <= fabs(p2[0] - rect.minX);
						const double score = useStart ? p1[1] : p2[1];
						if (!secondFound || score > secondScore)
						{
							secondFound = true;
							secondScore = score;
							second.curve = curve;
							second.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							second.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
				}
				else
				{
					if (fabs(p1[1] - rect.maxY) < tolerance || fabs(p2[1] - rect.maxY) < tolerance)
					{
						const bool useStart = fabs(p1[1] - rect.maxY) <= fabs(p2[1] - rect.maxY);
						const double score = useStart ? -p1[0] : -p2[0];
						if (!firstFound || score > firstScore)
						{
							firstFound = true;
							firstScore = score;
							first.curve = curve;
							first.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							first.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
					if (fabs(p1[1] - rect.minY) < tolerance || fabs(p2[1] - rect.minY) < tolerance)
					{
						const bool useStart = fabs(p1[1] - rect.minY) <= fabs(p2[1] - rect.minY);
						const double score = useStart ? -p1[0] : -p2[0];
						if (!secondFound || score > secondScore)
						{
							secondFound = true;
							secondScore = score;
							second.curve = curve;
							second.snapType = useStart ? NXOpen::InferSnapType::SnapTypeStart : NXOpen::InferSnapType::SnapTypeEnd;
							second.modelPoint = useStart ?
								NXOpen::Point3d(lineData.start_point[0], lineData.start_point[1], lineData.start_point[2]) :
								NXOpen::Point3d(lineData.end_point[0], lineData.end_point[1], lineData.end_point[2]);
						}
					}
				}
			}
		}
		UF_EVAL_free(evaluator);
	}

	return firstFound && secondFound;
}

static int CreateDraftNoteForBodyView(
	NXOpen::Part* workPart,
	NXOpen::Body* body,
	const NXOpen::Point3d& notePoint,
	NXOpen::Drawings::BaseView* baseView)
{
	if (workPart == NULL || body == NULL || baseView == NULL)
	{
		return 1;
	}

	try
	{
		NXOpen::Annotations::SimpleDraftingAid* nullAid(NULL);
		NXOpen::Annotations::DraftingNoteBuilder* builder = workPart->Annotations()->CreateDraftingNoteBuilder(nullAid);
		builder->Origin()->Plane()->SetPlaneMethod(NXOpen::Annotations::PlaneBuilder::PlaneMethodTypeXyPlane);
		builder->Origin()->SetAnchor(NXOpen::Annotations::OriginBuilder::AlignmentPositionMidCenter);
		builder->Origin()->SetInferRelativeToGeometry(false);
		builder->Style()->LetteringStyle()->SetGeneralTextColor(workPart->Colors()->Find("Emerald"));
		builder->Style()->LetteringStyle()->SetGeneralTextLineSpaceFactor(1.5);

		SetBodyDraftNoteTextFromConfig(builder->Text()->TextBlock(), workPart, body);

		NXOpen::Annotations::Annotation::AssociativeOriginData assocOrigin;
		assocOrigin.OriginType = NXOpen::Annotations::AssociativeOriginTypeRelativeToView;
		assocOrigin.View = baseView;
		assocOrigin.StackAlignmentPosition = NXOpen::Annotations::StackAlignmentPositionAbove;
		NXOpen::View* nullView(NULL);
		builder->Origin()->SetAssociativeOrigin(assocOrigin);
		const NXOpen::Point3d adjustedNotePoint = AdjustBodyNotePointForLineCount(notePoint);
		builder->Origin()->Origin()->SetValue(NULL, nullView, adjustedNotePoint);
		builder->Commit();
		builder->Destroy();
		return 0;
	}
	catch (...)
	{
		return 1;
	}
}

static bool CreateOverallDimensionForView(
	NXOpen::Part* workPart,
	NXOpen::Drawings::BaseView* baseView,
	const std::vector<NXOpen::Drawings::DraftingCurve*>& curves,
	const LayoutRect& rect,
	bool horizontalDimension)
{
	if (workPart == NULL || baseView == NULL || curves.empty())
	{
		return false;
	}

	CurveAssocCandidate first{};
	CurveAssocCandidate second{};
	if (!FindOverallDimensionCurvePair(baseView, curves, rect, horizontalDimension, first, second))
	{
		if (!FindOverallDimensionCurvePairFallback(baseView, curves, rect, horizontalDimension, first, second))
		{
			return false;
		}
	}

	NXOpen::View* nullView(NULL);
	NXOpen::Annotations::Dimension* nullDimension(NULL);
	NXOpen::Annotations::RapidDimensionBuilder* rapidDimensionBuilder = workPart->Dimensions()->CreateRapidDimensionBuilder(nullDimension);
	NXOpen::Point3d assistPoint(0.0, 0.0, 0.0);
	rapidDimensionBuilder->Style()->DimensionStyle()->SetTextCentered(true);
	rapidDimensionBuilder->Style()->DimensionStyle()->SetNarrowDisplayType(NXOpen::Annotations::NarrowDisplayOptionNone);
	rapidDimensionBuilder->Measurement()->SetMethod(
		horizontalDimension ?
		NXOpen::Annotations::DimensionMeasurementBuilder::MeasurementMethodHorizontal :
		NXOpen::Annotations::DimensionMeasurementBuilder::MeasurementMethodVertical);

	rapidDimensionBuilder->FirstAssociativity()->SetValue(
		first.snapType,
		first.curve,
		baseView,
		first.modelPoint,
		NULL,
		nullView,
		assistPoint);
	rapidDimensionBuilder->SecondAssociativity()->SetValue(
		second.snapType,
		second.curve,
		baseView,
		second.modelPoint,
		NULL,
		nullView,
		assistPoint);

	NXOpen::Point3d origin;
	if (horizontalDimension)
	{
		origin = { rect.maxX - 8.0, rect.maxY + 8.0, 0.0 };
	}
	else
	{
		origin = { rect.minX - 8.0, rect.minY - 8.0, 0.0 };
	}
	rapidDimensionBuilder->Origin()->Origin()->SetValue(NULL, nullView, origin);

	try
	{
		rapidDimensionBuilder->Commit();
		rapidDimensionBuilder->Destroy();
		return true;
	}
	catch (...)
	{
		rapidDimensionBuilder->Destroy();
		return false;
	}
}

static bool TryCreateOuterCircleDiameterForView(
	NXOpen::Drawings::BaseView* baseView,
	const std::vector<NXOpen::Drawings::DraftingCurve*>& curves,
	const LayoutRect& rect)
{
	if (workPart == NULL || baseView == NULL || curves.empty())
	{
		return false;
	}

	NXOpen::Drawings::DraftingCurve* circleCurve = NULL;
	NXOpen::Point3d circleCenter(0.0, 0.0, 0.0);
	double bestRadius = 0.0;
	const double rectWidth = rect.maxX - rect.minX;
	const double rectHeight = rect.maxY - rect.minY;
	const double rectTolerance = std::max(0.5, std::max(rectWidth, rectHeight) * 0.08);
	if (rectWidth <= 0.0 || rectHeight <= 0.0 || fabs(rectWidth - rectHeight) > rectTolerance)
	{
		return false;
	}

	for (size_t i = 0; i < curves.size(); ++i)
	{
		NXOpen::Drawings::DraftingCurve* curve = curves[i];
		if (curve == NULL)
		{
			continue;
		}
		NXOpen::DisplayableObject* displayableCurve = dynamic_cast<NXOpen::DisplayableObject*>(curve);
		if (displayableCurve != NULL && displayableCurve->IsBlanked())
		{
			continue;
		}

		UF_EVAL_p_t evaluator = NULL;
		if (UF_EVAL_initialize(curve->Tag(), &evaluator) != 0 || evaluator == NULL)
		{
			continue;
		}

		logical isArc = false;
		UF_EVAL_is_arc(evaluator, &isArc);
		if (isArc)
		{
			UF_EVAL_arc_t arcData;
			if (UF_EVAL_ask_arc(evaluator, &arcData) == 0)
			{
				const double span = fabs(arcData.limits[1] - arcData.limits[0]);
				const bool isFullCircle = (arcData.is_periodic != 0) || fabs(span - (2.0 * 3.14159265358979323846)) < 1.0e-3;
				if (isFullCircle && arcData.radius > bestRadius)
				{
					LayoutRect arcRect{};
					bool arcRectInitialized = false;
					ExpandRectWithCurveInDrawing(baseView->Tag(), curve->Tag(), arcRect, arcRectInitialized);
					if (arcRectInitialized &&
						fabs((arcRect.maxX - arcRect.minX) - rectWidth) <= rectTolerance &&
						fabs((arcRect.maxY - arcRect.minY) - rectHeight) <= rectTolerance)
					{
						circleCurve = curve;
						circleCenter = NXOpen::Point3d(arcData.center[0], arcData.center[1], arcData.center[2]);
						bestRadius = arcData.radius;
					}
				}
			}
		}
		UF_EVAL_free(evaluator);
	}

	if (circleCurve == NULL)
	{
		return false;
	}

	NXOpen::View* nullView(NULL);
	NXOpen::Annotations::Dimension* nullDimension(NULL);
	NXOpen::Annotations::RapidDimensionBuilder* rapidDimensionBuilder = workPart->Dimensions()->CreateRapidDimensionBuilder(nullDimension);
	NXOpen::Point3d assistPoint(0.0, 0.0, 0.0);
	rapidDimensionBuilder->Style()->DimensionStyle()->SetTextCentered(true);
	rapidDimensionBuilder->Style()->DimensionStyle()->SetNarrowDisplayType(NXOpen::Annotations::NarrowDisplayOptionNone);
	rapidDimensionBuilder->Measurement()->SetMethod(NXOpen::Annotations::DimensionMeasurementBuilder::MeasurementMethodDiametral);
	rapidDimensionBuilder->FirstAssociativity()->SetValue(
		NXOpen::InferSnapType::SnapTypeExist,
		circleCurve,
		baseView,
		circleCenter,
		NULL,
		nullView,
		assistPoint);
	NXOpen::Point3d origin(rect.maxX + 8.0, rect.maxY + 8.0, 0.0);
	rapidDimensionBuilder->Origin()->Origin()->SetValue(NULL, nullView, origin);

	try
	{
		rapidDimensionBuilder->Commit();
		rapidDimensionBuilder->Destroy();
		return true;
	}
	catch (...)
	{
		rapidDimensionBuilder->Destroy();
		return true;
	}
}

static void CreateSimpleDimensionsForPendingGroup(
	NXOpen::Part* workPart,
	const PendingScaleRefit& pending)
{
	if (workPart == NULL || pending.mainView == NULL || pending.targetBody == NULL)
	{
		return;
	}

	LayoutRect mainRect{};
	if (!AskDisplayedCurveRectFromWholeView(pending.mainView, mainRect))
	{
		return;
	}

	std::vector<NXOpen::Drawings::DraftingCurve*> mainCurves;
	CollectDisplayedCurvesFromWholeView(pending.mainView, mainCurves);
	CreateOverallDimensionForView(workPart, pending.mainView, mainCurves, mainRect, true);
	CreateOverallDimensionForView(workPart, pending.mainView, mainCurves, mainRect, false);

	NXOpen::Point3d notePoint(
		(mainRect.minX + mainRect.maxX) * 0.5,
		mainRect.minY - 5.0,
		0.0);
	CreateDraftNoteForBodyView(workPart, pending.targetBody, notePoint, pending.mainView);

	for (size_t i = 0; i < pending.sideViews.size(); ++i)
	{
		NXOpen::Drawings::BaseView* sideView = pending.sideViews[i];
		if (sideView == NULL)
		{
			continue;
		}
		LayoutRect sideRect{};
		if (!AskDisplayedCurveRect(sideView, pending.targetBody, sideRect))
		{
			continue;
		}
		std::vector<NXOpen::Drawings::DraftingCurve*> sideCurves;
		CollectDisplayedCurvesForTargetBody(sideView, pending.targetBody, sideCurves);
		CreateOverallDimensionForView(workPart, sideView, sideCurves, sideRect, true);
		CreateOverallDimensionForView(workPart, sideView, sideCurves, sideRect, false);
	}
}

static std::string RectToString(const LayoutRect& rect)
{
	std::ostringstream oss;
	oss << "(" << rect.minX << "," << rect.minY << ")-(" << rect.maxX << "," << rect.maxY << ")";
	return oss.str();
}

static NXOpen::Point3d RectCenter(const LayoutRect& rect)
{
	return NXOpen::Point3d{ (rect.minX + rect.maxX) * 0.5, (rect.minY + rect.maxY) * 0.5, 0.0 };
}

static NXOpen::Point3d GetViewReferencePoint(NXOpen::Drawings::BaseView* view)
{
	NXOpen::Drawings::DraftingView* draftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(view);
	if (draftingView == NULL)
	{
		return NXOpen::Point3d{ 0.0, 0.0, 0.0 };
	}
	return draftingView->GetDrawingReferencePoint();
}

static NXOpen::NXObject* TryRepositionBaseView(
	NXOpen::Part* workPart,
	NXOpen::Drawings::BaseView* existingView,
	const NXOpen::Point3d& placementPoint,
	bool useBuilderScale,
	double builderScaleNumerator,
	double builderScaleDenominator,
	bool useStyleScale,
	double styleScaleNumerator,
	double styleScaleDenominator);

static void MoveViewByDelta(NXOpen::Drawings::BaseView* view, double deltaX, double deltaY)
{
	NXOpen::Drawings::DraftingView* draftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(view);
	if (draftingView == NULL)
	{
		return;
	}

	NXOpen::Point3d refPoint = draftingView->GetDrawingReferencePoint();
	refPoint.X += deltaX;
	refPoint.Y += deltaY;
	draftingView->MoveView(refPoint);
}

static bool RescaleBaseViewAboutCenter(
	NXOpen::Part* workPart,
	NXOpen::Drawings::BaseView* view,
	double scaleFactor)
{
	if (workPart == NULL || view == NULL || scaleFactor <= 0.0)
	{
		return false;
	}

	NXOpen::Drawings::DrawingSheet* currentSheet = workPart->DrawingSheets()->CurrentDrawingSheet();
	if (currentSheet == NULL)
	{
		return false;
	}

	double currentNumerator = 1.0;
	double currentDenominator = 1.0;
	currentSheet->GetScale(&currentNumerator, &currentDenominator);
	if (currentNumerator <= 0.0 || currentDenominator <= 0.0)
	{
		return false;
	}

	NXOpen::Point3d center = GetViewReferencePoint(view);
	double newNumerator = currentNumerator;
	double newDenominator = currentDenominator / scaleFactor;
	if (newDenominator < 0.5)
	{
		newDenominator = 0.5;
	}

	return TryRepositionBaseView(
		workPart,
		view,
		center,
		true,
		newNumerator,
		newDenominator,
		true,
		newNumerator,
		newDenominator) != NULL;
}

static double RectWidth(const LayoutRect& rect)
{
	return std::max(0.0, rect.maxX - rect.minX);
}

static double RectHeight(const LayoutRect& rect)
{
	return std::max(0.0, rect.maxY - rect.minY);
}


static NXOpen::NXObject* TryRepositionBaseView(
	NXOpen::Part* workPart,
	NXOpen::Drawings::BaseView* existingView,
	const NXOpen::Point3d& placementPoint,
	bool useBuilderScale = false,
	double builderScaleNumerator = 1.0,
	double builderScaleDenominator = 1.0,
	bool useStyleScale = false,
	double styleScaleNumerator = 1.0,
	double styleScaleDenominator = 1.0)
{
	if (workPart == NULL || existingView == NULL)
	{
		return NULL;
	}

	NXOpen::Drawings::BaseViewBuilder* baseViewBuilder = NULL;
	try
	{
		baseViewBuilder = workPart->DraftingViews()->CreateBaseViewBuilder(existingView);
		if (useStyleScale)
		{
			baseViewBuilder->Style()->ViewStyleGeneral()->Scale()->SetNumerator(styleScaleNumerator);
			baseViewBuilder->Style()->ViewStyleGeneral()->Scale()->SetDenominator(styleScaleDenominator);
		}
		if (useBuilderScale)
		{
			baseViewBuilder->Scale()->SetNumerator(builderScaleNumerator);
			baseViewBuilder->Scale()->SetDenominator(builderScaleDenominator);
		}
		baseViewBuilder->Placement()->Placement()->SetValue(NULL, workPart->Views()->WorkView(), placementPoint);
		NXOpen::NXObject* committedObject = baseViewBuilder->Commit();
		baseViewBuilder->Destroy();
		return committedObject;
	}
	catch (const NXOpen::NXException&)
	{
		if (baseViewBuilder != NULL)
		{
			baseViewBuilder->Destroy();
		}
		return NULL;
	}
	catch (...)
	{
		if (baseViewBuilder != NULL)
		{
			baseViewBuilder->Destroy();
		}
		return NULL;
	}
}

static NXOpen::ModelingView* FindModelingViewSafe(NXOpen::Part* workPart, const char* preferredName, const char* fallbackName = "Top")
{
	if (workPart == NULL)
	{
		return NULL;
	}

	auto tryFind = [&](const char* viewName) -> NXOpen::ModelingView*
		{
			if (viewName == NULL || viewName[0] == '\0')
			{
				return NULL;
			}
			try
			{
				return dynamic_cast<NXOpen::ModelingView*>(workPart->ModelingViews()->FindObject(viewName));
			}
			catch (...)
			{
				return NULL;
			}
		};

	NXOpen::ModelingView* modelingView = tryFind(preferredName);
	if (modelingView != NULL)
	{
		return modelingView;
	}

	modelingView = tryFind(fallbackName);
	if (modelingView != NULL)
	{
		return modelingView;
	}

	try
	{
		return dynamic_cast<NXOpen::ModelingView*>(workPart->Views()->WorkView());
	}
	catch (...)
	{
		return NULL;
	}
}

static double VectorLength(const NXOpen::Vector3d& value)
{
	return sqrt(value.X * value.X + value.Y * value.Y + value.Z * value.Z);
}

static NXOpen::Vector3d ScaleVector(const NXOpen::Vector3d& value, double scale)
{
	return NXOpen::Vector3d(value.X * scale, value.Y * scale, value.Z * scale);
}

static NXOpen::Vector3d AddVector(const NXOpen::Vector3d& lhs, const NXOpen::Vector3d& rhs)
{
	return NXOpen::Vector3d(lhs.X + rhs.X, lhs.Y + rhs.Y, lhs.Z + rhs.Z);
}

static NXOpen::Vector3d CrossVector(const NXOpen::Vector3d& lhs, const NXOpen::Vector3d& rhs)
{
	return NXOpen::Vector3d(
		lhs.Y * rhs.Z - lhs.Z * rhs.Y,
		lhs.Z * rhs.X - lhs.X * rhs.Z,
		lhs.X * rhs.Y - lhs.Y * rhs.X);
}

static double DotVector(const NXOpen::Vector3d& lhs, const NXOpen::Vector3d& rhs)
{
	return lhs.X * rhs.X + lhs.Y * rhs.Y + lhs.Z * rhs.Z;
}

static NXOpen::Point3d GetAutoPlacementPointForSheetSlot(int slotIndex)
{
	if (slotIndex <= 0)
	{
		return { 82.0, 132.0, 0.0 };
	}
	return { 215.0, 132.0, 0.0 };
}

static BodyViewFootprint EstimateBodyViewFootprint(double mainWidth, double mainHeight, const char* layoutMode)
{
	BodyViewFootprint footprint{};
	if (mainWidth <= 0.0 || mainHeight <= 0.0)
	{
		footprint.valid = false;
		return footprint;
	}

	const double rightWidth = mainWidth * 0.55;
	const double rightHeight = mainHeight * 0.85;
	const double bottomWidth = mainWidth * 0.85;
	const double bottomHeight = mainHeight * 0.55;
	double width = mainWidth;
	double height = mainHeight;

	if (layoutMode != NULL && strcmp(layoutMode, "左下") == 0)
	{
		width = mainWidth + 20.0 + rightWidth;
		height = mainHeight + 20.0 + bottomHeight;
	}
	else if (layoutMode != NULL && strcmp(layoutMode, "左") == 0)
	{
		width = mainWidth + 30.0 + rightWidth;
		height = std::max(mainHeight, rightHeight);
	}
	else if (layoutMode != NULL && strcmp(layoutMode, "下") == 0)
	{
		width = std::max(mainWidth, bottomWidth);
		height = mainHeight + 30.0 + bottomHeight;
	}

	footprint.width = width + 18.0;
	footprint.height = height + 18.0;
	footprint.valid = true;
	return footprint;
}

static BodyViewFootprint CaptureCurrentBodyFootprint(NXOpen::BlockStyler::Enumeration* enum0Block)
{
	NXString layoutMode("左");
	if (enum0Block != NULL)
	{
		PropertyList* enum0Props = enum0Block->GetProperties();
		layoutMode = enum0Props->GetEnumAsString("Value");
		delete enum0Props;
		enum0Props = NULL;
	}
	return EstimateBodyViewFootprint(doubleX / 20.0, doubleY / 20.0, layoutMode.GetLocaleText());
}

static double EstimateBodySheetScale(NXOpen::BlockStyler::Enumeration* enum0Block)
{
	NXString layoutMode("左");
	if (enum0Block != NULL)
	{
		PropertyList* enum0Props = enum0Block->GetProperties();
		layoutMode = enum0Props->GetEnumAsString("Value");
		delete enum0Props;
		enum0Props = NULL;
	}

	double scaleX = doubleX / 200.0;
	double scaleY = doubleY / 130.0;
	const char* layoutText = layoutMode.GetLocaleText();
	if (layoutText != NULL && strcmp(layoutText, "下") == 0)
	{
		scaleX = doubleX / 220.0;
		scaleY = doubleY / 110.0;
	}
	else if (layoutText != NULL && strcmp(layoutText, "左下") == 0)
	{
		scaleX = doubleX / 200.0;
		scaleY = doubleY / 110.0;
	}

	double scale = std::max(scaleX, scaleY);
	if (scale > 0.5)
	{
		scale = ceil(scale);
	}
	else
	{
		scale = 0.5;
	}
	return scale;
}

static double ScorePairLayout(
	const BodyViewFootprint& first,
	const BodyViewFootprint& second,
	bool horizontal,
	double availableWidth,
	double availableHeight,
	double gap)
{
	double usedWidth = horizontal ? (first.width + gap + second.width) : std::max(first.width, second.width);
	double usedHeight = horizontal ? std::max(first.height, second.height) : (first.height + gap + second.height);
	double overflowX = std::max(0.0, usedWidth - availableWidth);
	double overflowY = std::max(0.0, usedHeight - availableHeight);
	double whitespace = std::max(0.0, availableWidth - usedWidth) + std::max(0.0, availableHeight - usedHeight);
	return overflowX * 1000.0 + overflowY * 1000.0 + whitespace;
}

static void ComputePairPlacementPoints(
	const BodyViewFootprint& first,
	const BodyViewFootprint& second,
	NXOpen::Point3d& firstPoint,
	NXOpen::Point3d& secondPoint)
{
	const LayoutRect safeBounds{ 24.0, 44.0, 248.0, 192.0 };
	const LayoutRect titleBlock{ 185.0, 0.0, 297.0, 40.0 };
	const double availableWidth = safeBounds.maxX - safeBounds.minX;
	const double availableHeight = safeBounds.maxY - safeBounds.minY;
	const double gap = 18.0;

	auto scorePlacement = [&](const NXOpen::Point3d& firstCenter, const NXOpen::Point3d& secondCenter) -> double
		{
			LayoutRect firstRect = MakeRect(firstCenter, first.width, first.height);
			LayoutRect secondRect = MakeRect(secondCenter, second.width, second.height);
			double score = 0.0;
			score += RectOutOfBoundsPenalty(firstRect, safeBounds) * 10000.0;
			score += RectOutOfBoundsPenalty(secondRect, safeBounds) * 10000.0;
			score += RectOverlapArea(firstRect, secondRect) * 20000.0;
			score += RectOverlapArea(firstRect, titleBlock) * 12000.0;
			score += RectOverlapArea(secondRect, titleBlock) * 12000.0;
			score += fabs((firstCenter.X + secondCenter.X) / 2.0 - 120.0) * 5.0;
			return score;
		};

	NXOpen::Point3d bestFirst{ safeBounds.minX + first.width / 2.0, safeBounds.maxY - first.height / 2.0, 0.0 };
	NXOpen::Point3d bestSecond{ safeBounds.minX + second.width / 2.0, safeBounds.maxY - second.height / 2.0, 0.0 };
	double bestScore = DBL_MAX;

	const double horizontalScore = ScorePairLayout(first, second, true, availableWidth, availableHeight, gap);
	const double verticalScore = ScorePairLayout(first, second, false, availableWidth, availableHeight, gap);
	const bool preferHorizontal = horizontalScore <= verticalScore;

	auto evaluateHorizontal = [&]()
		{
			const double minX = safeBounds.minX + first.width / 2.0;
			const double maxX = safeBounds.maxX - (first.width / 2.0 + gap + second.width);
			const std::vector<double> candidateStartX =
			{
				minX,
				std::max(minX, std::min(maxX, 42.0)),
				std::max(minX, std::min(maxX, safeBounds.minX + (availableWidth - (first.width + gap + second.width)) / 2.0 + first.width / 2.0))
			};
			const std::vector<double> candidateY =
			{
				safeBounds.maxY - std::max(first.height, second.height) / 2.0 - 8.0,
				safeBounds.minY + availableHeight / 2.0,
				safeBounds.minY + std::max(first.height, second.height) / 2.0 + 12.0
			};
			for (double firstCenterX : candidateStartX)
			{
				for (double centerY : candidateY)
				{
					NXOpen::Point3d currentFirst{ firstCenterX, centerY, 0.0 };
					NXOpen::Point3d currentSecond{ firstCenterX + first.width / 2.0 + gap + second.width / 2.0, centerY, 0.0 };
					double score = scorePlacement(currentFirst, currentSecond);
					if (score < bestScore)
					{
						bestScore = score;
						bestFirst = currentFirst;
						bestSecond = currentSecond;
					}
				}
			}
		};

	auto evaluateVertical = [&]()
		{
			const double usedHeight = first.height + gap + second.height;
			const std::vector<double> candidateCenterX =
			{
				safeBounds.minX + std::max(first.width, second.width) / 2.0 + 6.0,
				safeBounds.minX + availableWidth * 0.42,
				safeBounds.minX + availableWidth * 0.50
			};
			const std::vector<double> candidateTopY =
			{
				safeBounds.maxY - first.height / 2.0 - 8.0,
				safeBounds.minY + usedHeight - second.height / 2.0,
				safeBounds.minY + availableHeight - (availableHeight - usedHeight) / 2.0 - first.height / 2.0
			};
			for (double centerX : candidateCenterX)
			{
				for (double firstCenterY : candidateTopY)
				{
					NXOpen::Point3d currentFirst{ centerX, firstCenterY, 0.0 };
					NXOpen::Point3d currentSecond{ centerX, firstCenterY - first.height / 2.0 - gap - second.height / 2.0, 0.0 };
					double score = scorePlacement(currentFirst, currentSecond);
					if (score < bestScore)
					{
						bestScore = score;
						bestFirst = currentFirst;
						bestSecond = currentSecond;
					}
				}
			}
		};

	if (preferHorizontal)
	{
		evaluateHorizontal();
		evaluateVertical();
	}
	else
	{
		evaluateVertical();
		evaluateHorizontal();
	}

	firstPoint = bestFirst;
	secondPoint = bestSecond;
}

static int GetBodyLayer(NXOpen::Body* body)
{
	if (body == NULL)
	{
		return -1;
	}
	UF_OBJ_disp_props_t dispProps;
	if (UF_OBJ_ask_display_properties(body->Tag(), &dispProps) != 0)
	{
		return -1;
	}
	return dispProps.layer;
}

static std::unordered_map<tag_t, std::vector<int>> g_bodyDraftingLayers;

static void RememberBodyDraftingSourceBody(NXOpen::Body* targetBody, NXOpen::Body* sourceBody)
{
	if (targetBody == NULL || sourceBody == NULL)
	{
		return;
	}
	g_bodyDraftingSourceBodies[targetBody->Tag()] = sourceBody;
	std::ostringstream oss;
	oss << "[RememberBodyDraftingSourceBody] targetBodyTag=" << targetBody->Tag()
		<< " sourceBodyTag=" << sourceBody->Tag()
		<< " sourceBodyLayer=" << GetBodyLayer(sourceBody);
	LayerDebugLog(oss.str());
}

static void RememberBodyDraftingLayers(NXOpen::Body* body, const std::vector<int>& layers)
{
	if (body == NULL)
	{
		return;
	}
	std::vector<int> safeLayers;
	for (size_t i = 0; i < layers.size(); ++i)
	{
		if (layers[i] >= UF_LAYER_MIN_LAYER && layers[i] <= UF_LAYER_MAX_LAYER)
		{
			if (std::find(safeLayers.begin(), safeLayers.end(), layers[i]) == safeLayers.end())
			{
				safeLayers.push_back(layers[i]);
			}
		}
	}
	if (!safeLayers.empty())
	{
		g_bodyDraftingLayers[body->Tag()] = safeLayers;
		std::ostringstream oss;
		oss << "[RememberBodyDraftingLayers] bodyTag=" << body->Tag()
			<< " layers=" << DebugLayers(safeLayers);
		LayerDebugLog(oss.str());
	}
}

static std::vector<int> GetPreferredBodyDraftingLayers(NXOpen::Body* body)
{
	std::vector<int> layers;
	if (body != NULL)
	{
		std::unordered_map<tag_t, std::vector<int>>::const_iterator it = g_bodyDraftingLayers.find(body->Tag());
		if (it != g_bodyDraftingLayers.end())
		{
			layers = it->second;
			std::ostringstream oss;
			oss << "[GetPreferredBodyDraftingLayers] source=flatPatternFaceBody bodyTag=" << body->Tag()
				<< " layers=" << DebugLayers(layers);
			LayerDebugLog(oss.str());
		}
	}
	if (layers.empty())
	{
		const int bodyLayer = GetBodyLayer(body);
		if (bodyLayer >= UF_LAYER_MIN_LAYER && bodyLayer <= UF_LAYER_MAX_LAYER)
		{
			layers.push_back(bodyLayer);
			std::ostringstream oss;
			oss << "[GetPreferredBodyDraftingLayers] source=bodyFallback bodyTag=" << (body != NULL ? body->Tag() : NULL_TAG)
				<< " bodyLayer=" << bodyLayer;
			LayerDebugLog(oss.str());
		}
	}
	if (layers.empty())
	{
		layers.push_back(1);
		LayerDebugLog("[GetPreferredBodyDraftingLayers] source=default layer=1");
	}
	return layers;
}

struct LayerStateSnapshot
{
	bool valid;
	std::vector<int> status;
	LayerStateSnapshot() : valid(false), status(257, UF_LAYER_INACTIVE_LAYER) {}
};

static LayerStateSnapshot SaveCurrentLayerStates()
{
	LayerStateSnapshot snapshot;
	for (int layer = UF_LAYER_MIN_LAYER; layer <= UF_LAYER_MAX_LAYER; ++layer)
	{
		int status = UF_LAYER_INACTIVE_LAYER;
		if (UF_LAYER_ask_status(layer, &status) != 0)
		{
			snapshot.valid = false;
			return snapshot;
		}
		snapshot.status[layer] = status;
	}
	snapshot.valid = true;
	return snapshot;
}

static void ApplyManualBodyLayerIsolation(NXOpen::Body* body)
{
	const std::vector<int> draftingLayers = GetPreferredBodyDraftingLayers(body);
	{
		std::ostringstream oss;
		oss << "[ApplyManualBodyLayerIsolation] bodyTag=" << (body != NULL ? body->Tag() : NULL_TAG)
			<< " keepLayers=" << DebugLayers(draftingLayers)
			<< " plus=[1,230]";
		LayerDebugLog(oss.str());
	}

	UF_LAYER_set_status(1, UF_LAYER_WORK_LAYER);
	for (int layer = UF_LAYER_MIN_LAYER; layer <= UF_LAYER_MAX_LAYER; ++layer)
	{
		if (layer == 1)
		{
			continue;
		}
		const bool keepOpen = (std::find(draftingLayers.begin(), draftingLayers.end(), layer) != draftingLayers.end() || layer == 230);
		UF_LAYER_set_status(layer, keepOpen ? UF_LAYER_ACTIVE_LAYER : UF_LAYER_INACTIVE_LAYER);
	}
	if (workPart != NULL)
	{
		std::vector<NXOpen::Layer::StateInfo> stateArray(1);
		stateArray[0] = NXOpen::Layer::StateInfo(230, NXOpen::Layer::StateSelectable);
		workPart->Layers()->ChangeStates(stateArray, false);
	}
}

static bool TryReadSpecifyPoint(NXOpen::BlockStyler::SpecifyPoint* pointBlock, NXOpen::Point3d& pointValue)
{
	if (pointBlock == NULL)
	{
		return false;
	}
	PropertyList* pointProperties = pointBlock->GetProperties();
	if (pointProperties == NULL)
	{
		return false;
	}
	try
	{
		pointValue = pointProperties->GetPoint("Point");
		delete pointProperties;
		pointProperties = NULL;
		return true;
	}
	catch (...)
	{
		delete pointProperties;
		pointProperties = NULL;
		return false;
	}
}

static void ApplyBodyGroupLayerIsolation(const std::vector<NXOpen::Body*>& bodies)
{
	std::unordered_set<int> keepLayers;
	keepLayers.insert(1);
	keepLayers.insert(230);
	for (size_t i = 0; i < bodies.size(); ++i)
	{
		const std::vector<int> draftingLayers = GetPreferredBodyDraftingLayers(bodies[i]);
		for (size_t layerIndex = 0; layerIndex < draftingLayers.size(); ++layerIndex)
		{
			if (draftingLayers[layerIndex] >= UF_LAYER_MIN_LAYER && draftingLayers[layerIndex] <= UF_LAYER_MAX_LAYER)
			{
				keepLayers.insert(draftingLayers[layerIndex]);
			}
		}
	}
	{
		std::vector<int> debugLayers(keepLayers.begin(), keepLayers.end());
		std::sort(debugLayers.begin(), debugLayers.end());
		std::ostringstream oss;
		oss << "[ApplyBodyGroupLayerIsolation] bodyCount=" << bodies.size()
			<< " keepLayers=" << DebugLayers(debugLayers);
		LayerDebugLog(oss.str());
	}

	UF_LAYER_set_status(1, UF_LAYER_WORK_LAYER);
	for (int layer = UF_LAYER_MIN_LAYER; layer <= UF_LAYER_MAX_LAYER; ++layer)
	{
		if (layer == 1)
		{
			continue;
		}
		const bool keepOpen = (keepLayers.find(layer) != keepLayers.end());
		UF_LAYER_set_status(layer, keepOpen ? UF_LAYER_ACTIVE_LAYER : UF_LAYER_INACTIVE_LAYER);
	}
}

static void RestoreLayerStates(const LayerStateSnapshot& snapshot)
{
	if (!snapshot.valid)
	{
		LayerDebugLog("[RestoreLayerStates] skipped invalid snapshot");
		return;
	}

	int workLayer = 1;
	for (int layer = UF_LAYER_MIN_LAYER; layer <= UF_LAYER_MAX_LAYER; ++layer)
	{
		if (snapshot.status[layer] == UF_LAYER_WORK_LAYER)
		{
			workLayer = layer;
			break;
		}
	}

	UF_LAYER_set_status(workLayer, UF_LAYER_WORK_LAYER);
	for (int layer = UF_LAYER_MIN_LAYER; layer <= UF_LAYER_MAX_LAYER; ++layer)
	{
		if (layer == workLayer)
		{
			continue;
		}
		int status = snapshot.status[layer];
		if (status == UF_LAYER_WORK_LAYER)
		{
			status = UF_LAYER_ACTIVE_LAYER;
		}
		UF_LAYER_set_status(layer, status);
	}
	std::ostringstream oss;
	oss << "[RestoreLayerStates] restored workLayer=" << workLayer;
	LayerDebugLog(oss.str());
}

static AutoViewLayout ComputeAutomaticViewLayout(
	const char* layoutMode,
	double mainWidth,
	double mainHeight,
	double rightWidth,
	double rightHeight,
	double bottomWidth,
	double bottomHeight,
	bool includeIso,
	double sheetWidth,
	double sheetHeight)
{
	const bool hasRight = strcmp(layoutMode, "左") == 0 || strcmp(layoutMode, "左下") == 0;
	const bool hasBottom = strcmp(layoutMode, "下") == 0 || strcmp(layoutMode, "左下") == 0;
	const LayoutRect safeBounds{ 18.0, 32.0, sheetWidth - 18.0, sheetHeight - 12.0 };
	const double gapX = 0.0;
	const double gapY = hasBottom ? BodyNoteBottomViewGap() : 0.0;
	const double clusterWidth = mainWidth + (hasRight ? gapX + rightWidth : 0.0);
	const double clusterHeight = mainHeight + (hasBottom ? gapY + bottomHeight : 0.0);
	const double clusterCenterX = (safeBounds.minX + safeBounds.maxX) * 0.5;
	const double clusterCenterY = (safeBounds.minY + safeBounds.maxY) * 0.5;
	const double clusterMinX = clusterCenterX - clusterWidth * 0.5;
	const double clusterMaxX = clusterCenterX + clusterWidth * 0.5;
	const double clusterMinY = clusterCenterY - clusterHeight * 0.5;
	const double clusterMaxY = clusterCenterY + clusterHeight * 0.5;

	AutoViewLayout layout{};
	layout.hasRight = hasRight;
	layout.hasBottom = hasBottom;
	layout.hasIso = includeIso;
	layout.mainWidth = mainWidth;
	layout.mainHeight = mainHeight;
	layout.mainPos = { clusterCenterX, clusterCenterY, 0.0 };

	if (hasRight)
	{
		layout.rightPos = {
			clusterMaxX - rightWidth * 0.5,
			layout.mainPos.Y,
			0.0
		};
	}
	if (hasBottom)
	{
		layout.bottomPos = {
			layout.mainPos.X,
			clusterMinY + bottomHeight * 0.5,
			0.0
		};
	}
	if (includeIso)
	{
		const double isoWidth = std::max(28.0, std::min(48.0, mainWidth * 0.30));
		const double isoHeight = std::max(22.0, std::min(42.0, mainHeight * 0.30));
		layout.isoPos = {
			safeBounds.maxX - isoWidth * 0.5,
			safeBounds.maxY - isoHeight * 0.5,
			0.0
		};
	}

	return layout;
}

static bool GroupHasRight(const std::string& layoutMode)
{
	return layoutMode == "左" || layoutMode == "左下";
}

static bool GroupHasBottom(const std::string& layoutMode)
{
	return layoutMode == "下" || layoutMode == "左下";
}

static bool ComputePendingGroupMetrics(const PendingScaleRefit& pending, PendingGroupMetrics& metrics)
{
	metrics = PendingGroupMetrics{};
	if (pending.mainView == NULL || !AskDisplayedCurveRectFromWholeView(pending.mainView, metrics.mainRect))
	{
		std::ostringstream oss;
		oss << "[实体组失败] 布局=" << pending.layoutMode
			<< " mainViewTag=" << (pending.mainView != NULL ? pending.mainView->Tag() : NULL_TAG)
			<< " targetBodyTag=" << (pending.targetBody != NULL ? pending.targetBody->Tag() : NULL_TAG)
			<< " 原因=主视图包围盒失败";
		AppendLayoutDebug(oss.str());
		return false;
	}

	metrics.valid = true;
	metrics.hasRight = false;
	metrics.hasBottom = false;
	if (GroupHasRight(pending.layoutMode) && pending.sideViews.size() > 0 && pending.sideViews[0] != NULL)
	{
		metrics.hasRight = AskDisplayedCurveRectForLayout(pending.sideViews[0], pending.targetBody, metrics.rightRect);
	}
	if (GroupHasBottom(pending.layoutMode))
	{
		size_t bottomIndex = GroupHasRight(pending.layoutMode) ? 1 : 0;
		if (pending.sideViews.size() > bottomIndex && pending.sideViews[bottomIndex] != NULL)
		{
			metrics.hasBottom = AskDisplayedCurveRectForLayout(pending.sideViews[bottomIndex], pending.targetBody, metrics.bottomRect);
		}
	}

	const double mainWidth = RectWidth(metrics.mainRect);
	const double mainHeight = RectHeight(metrics.mainRect);
	const double rightWidth = metrics.hasRight ? RectWidth(metrics.rightRect) : 0.0;
	const double rightHeight = metrics.hasRight ? RectHeight(metrics.rightRect) : 0.0;
	const double bottomWidth = metrics.hasBottom ? RectWidth(metrics.bottomRect) : 0.0;
	const double bottomHeight = metrics.hasBottom ? RectHeight(metrics.bottomRect) : 0.0;

	const double topRowWidth = mainWidth + rightWidth;
	const double topRowHeight = metrics.hasRight ? std::max(mainHeight, rightHeight) : mainHeight;
	metrics.baseWidth = metrics.hasBottom ? std::max(topRowWidth, bottomWidth) : topRowWidth;
	metrics.baseHeight = topRowHeight + bottomHeight;
	metrics.fixedWidth = metrics.hasRight ? kViewHorizontalGap : 0.0;
	metrics.fixedHeight = metrics.hasBottom ? kViewVerticalGap : 0.0;
	return metrics.baseWidth > 0.0 && metrics.baseHeight > 0.0;
}

static std::vector<std::vector<int>> BuildCompactPackingOrders(const std::vector<double>& widths, const std::vector<double>& heights)
{
	std::vector<std::vector<int>> orders;
	const int count = static_cast<int>(widths.size());
	if (count <= 0)
	{
		return orders;
	}

	std::vector<int> identity(count);
	std::iota(identity.begin(), identity.end(), 0);

	auto appendSortedOrder = [&](auto comparator)
		{
			std::vector<int> order = identity;
			std::sort(order.begin(), order.end(), comparator);
			bool duplicate = false;
			for (size_t i = 0; i < orders.size(); ++i)
			{
				if (orders[i] == order)
				{
					duplicate = true;
					break;
				}
			}
			if (!duplicate)
			{
				orders.push_back(order);
			}
		};

	appendSortedOrder([&](int lhs, int rhs)
		{
			double lhsArea = widths[lhs] * heights[lhs];
			double rhsArea = widths[rhs] * heights[rhs];
			if (fabs(lhsArea - rhsArea) > 1.0e-6)
			{
				return lhsArea > rhsArea;
			}
			return lhs < rhs;
		});

	orders.push_back(identity);

	appendSortedOrder([&](int lhs, int rhs)
		{
			if (fabs(heights[lhs] - heights[rhs]) > 1.0e-6)
			{
				return heights[lhs] > heights[rhs];
			}
			return widths[lhs] > widths[rhs];
		});

	appendSortedOrder([&](int lhs, int rhs)
		{
			if (fabs(widths[lhs] - widths[rhs]) > 1.0e-6)
			{
				return widths[lhs] > widths[rhs];
			}
			return heights[lhs] > heights[rhs];
		});

	appendSortedOrder([&](int lhs, int rhs)
		{
			double lhsLong = std::max(widths[lhs], heights[lhs]);
			double rhsLong = std::max(widths[rhs], heights[rhs]);
			if (fabs(lhsLong - rhsLong) > 1.0e-6)
			{
				return lhsLong > rhsLong;
			}
			return lhs < rhs;
		});

	return orders;
}

static bool TryCompactPackOrder(
	const std::vector<double>& widths,
	const std::vector<double>& heights,
	const std::vector<int>& order,
	double safeWidth,
	double safeHeight,
	std::vector<LayoutRect>& packedRects,
	double& usedWidth,
	double& usedHeight)
{
	packedRects.assign(widths.size(), LayoutRect{ 0.0, 0.0, 0.0, 0.0 });
	usedWidth = 0.0;
	usedHeight = 0.0;
	std::vector<LayoutRect> placed;

	for (size_t orderIndex = 0; orderIndex < order.size(); ++orderIndex)
	{
		const int index = order[orderIndex];
		const double width = widths[index];
		const double height = heights[index];
		if (width <= 0.0 || height <= 0.0)
		{
			return false;
		}

		std::vector<double> candidateXs;
		std::vector<double> candidateYs;
		candidateXs.push_back(0.0);
		candidateYs.push_back(0.0);
		for (size_t i = 0; i < placed.size(); ++i)
		{
			candidateXs.push_back(placed[i].minX);
			candidateXs.push_back(placed[i].maxX + kBodyGroupHorizontalGap);
			candidateYs.push_back(placed[i].minY);
			candidateYs.push_back(placed[i].maxY + kBodyGroupVerticalGap);
		}
		std::sort(candidateXs.begin(), candidateXs.end());
		candidateXs.erase(std::unique(candidateXs.begin(), candidateXs.end(),
			[](double lhs, double rhs) { return fabs(lhs - rhs) < 1.0e-6; }), candidateXs.end());
		std::sort(candidateYs.begin(), candidateYs.end());
		candidateYs.erase(std::unique(candidateYs.begin(), candidateYs.end(),
			[](double lhs, double rhs) { return fabs(lhs - rhs) < 1.0e-6; }), candidateYs.end());

		bool found = false;
		LayoutRect bestRect{};
		double bestScore = DBL_MAX;
		for (size_t xIndex = 0; xIndex < candidateXs.size(); ++xIndex)
		{
			double x = candidateXs[xIndex];
			if (x + width > safeWidth + 1.0e-6)
			{
				continue;
			}

			for (size_t yIndex = 0; yIndex < candidateYs.size(); ++yIndex)
			{
				double y = candidateYs[yIndex];
				if (y + height > safeHeight + 1.0e-6)
				{
					continue;
				}

				LayoutRect candidate{ x, y, x + width, y + height };
				bool overlaps = false;
				for (size_t i = 0; i < placed.size(); ++i)
				{
					const LayoutRect inflatedPlaced = InflateRect(placed[i], 0.0);
					const bool overlapX =
						(candidate.minX < inflatedPlaced.maxX + kBodyGroupHorizontalGap - 1.0e-6) &&
						(candidate.maxX > inflatedPlaced.minX - kBodyGroupHorizontalGap + 1.0e-6);
					const bool overlapY =
						(candidate.minY < inflatedPlaced.maxY + kBodyGroupVerticalGap - 1.0e-6) &&
						(candidate.maxY > inflatedPlaced.minY - kBodyGroupVerticalGap + 1.0e-6);
					if (overlapX && overlapY)
					{
						overlaps = true;
						break;
					}
				}
				if (overlaps)
				{
					continue;
				}

				double candidateUsedWidth = std::max(usedWidth, candidate.maxX);
				double candidateUsedHeight = std::max(usedHeight, candidate.maxY);
				double score =
					candidateUsedHeight * 1000000.0 +
					candidateUsedWidth * 1000.0 +
					y * 10.0 +
					x;
				if (score < bestScore)
				{
					bestScore = score;
					bestRect = candidate;
					found = true;
				}
			}
		}

		if (!found)
		{
			return false;
		}

		packedRects[index] = bestRect;
		placed.push_back(bestRect);
		usedWidth = std::max(usedWidth, bestRect.maxX);
		usedHeight = std::max(usedHeight, bestRect.maxY);
	}

	return usedWidth <= safeWidth + 1.0e-6 && usedHeight <= safeHeight + 1.0e-6;
}

static bool BuildCompactSheetCenters(
	const std::vector<double>& widths,
	const std::vector<double>& heights,
	const LayoutRect& safeBounds,
	std::vector<NXOpen::Point3d>& centersOnSheet,
	double& usedWidth,
	double& usedHeight)
{
	centersOnSheet.assign(widths.size(), NXOpen::Point3d{ 0.0, 0.0, 0.0 });
	usedWidth = 0.0;
	usedHeight = 0.0;
	if (widths.empty() || widths.size() != heights.size())
	{
		return false;
	}

	std::vector<std::vector<int>> orders = BuildCompactPackingOrders(widths, heights);
	std::vector<LayoutRect> bestRects;
	double bestUsedWidth = 0.0;
	double bestUsedHeight = 0.0;
	double bestScore = DBL_MAX;
	size_t largestIndex = 0;
	double largestArea = -1.0;
	double totalArea = 0.0;
	for (size_t i = 0; i < widths.size(); ++i)
	{
		double area = widths[i] * heights[i];
		totalArea += area;
		if (area > largestArea)
		{
			largestArea = area;
			largestIndex = i;
		}
	}
	for (size_t orderIndex = 0; orderIndex < orders.size(); ++orderIndex)
	{
		std::vector<LayoutRect> packedRects;
		double packedWidth = 0.0;
		double packedHeight = 0.0;
		if (!TryCompactPackOrder(widths, heights, orders[orderIndex], RectWidth(safeBounds), RectHeight(safeBounds), packedRects, packedWidth, packedHeight))
		{
			continue;
		}

		double fillScore = packedWidth * packedHeight;
		double balancePenalty = fabs((packedWidth / RectWidth(safeBounds)) - (packedHeight / RectHeight(safeBounds))) * 10000.0;
		double largeLeftPenalty = packedRects[largestIndex].minX * 100.0;
		double largeTopPenalty = packedRects[largestIndex].minY * 100.0;
		double verticalOrderPenalty = 0.0;
		double horizontalOrderPenalty = 0.0;
		for (size_t i = 0; i < packedRects.size(); ++i)
		{
			double area = widths[i] * heights[i];
			double areaWeight = (largestArea > 1.0e-6) ? (area / largestArea) : 0.0;
			double centerY = (packedRects[i].minY + packedRects[i].maxY) * 0.5;
			double centerX = (packedRects[i].minX + packedRects[i].maxX) * 0.5;
			verticalOrderPenalty += areaWeight * centerY;
			horizontalOrderPenalty += areaWeight * centerX;
		}
		if (totalArea > 1.0e-6)
		{
			verticalOrderPenalty /= totalArea / largestArea;
			horizontalOrderPenalty /= totalArea / largestArea;
		}
		double score =
			fillScore +
			balancePenalty +
			largeLeftPenalty +
			largeTopPenalty +
			verticalOrderPenalty * 50.0 +
			horizontalOrderPenalty * 8.0;
		if (score < bestScore)
		{
			bestScore = score;
			bestRects = packedRects;
			bestUsedWidth = packedWidth;
			bestUsedHeight = packedHeight;
		}
	}

	if (bestRects.empty())
	{
		return false;
	}

	double offsetX = safeBounds.minX;
	for (size_t i = 0; i < bestRects.size(); ++i)
	{
		double localCenterX = (bestRects[i].minX + bestRects[i].maxX) * 0.5;
		double localCenterY = (bestRects[i].minY + bestRects[i].maxY) * 0.5;
		centersOnSheet[i] = NXOpen::Point3d{
			offsetX + localCenterX,
			safeBounds.maxY - localCenterY,
			0.0 };
	}
	usedWidth = bestUsedWidth;
	usedHeight = bestUsedHeight;
	return true;
}

static PendingGroupLayoutPlan BuildPendingGroupLayoutPlan(
	const std::vector<PendingGroupMetrics>& metrics,
	int columns,
	bool includeFixedGaps)
{
	PendingGroupLayoutPlan plan{};
	plan.columns = std::max(1, columns);
	plan.widthAtBaseScale = 0.0;
	plan.heightAtBaseScale = 0.0;
	plan.centersAtBaseScale.resize(metrics.size(), NXOpen::Point3d{ 0.0, 0.0, 0.0 });

	if (metrics.empty() || columns <= 0)
	{
		return plan;
	}

	std::vector<double> rowWidths;
	std::vector<double> rowHeights;
	for (size_t rowStart = 0; rowStart < metrics.size(); rowStart += columns)
	{
		double rowWidth = 0.0;
		double rowHeight = 0.0;
		for (int col = 0; col < columns; ++col)
		{
			size_t index = rowStart + col;
			if (index >= metrics.size())
			{
				break;
			}
			if (includeFixedGaps && col > 0)
			{
				rowWidth += kBodyGroupHorizontalGap;
			}
			rowWidth += metrics[index].baseWidth + (includeFixedGaps ? metrics[index].fixedWidth : 0.0);
			rowHeight = std::max(rowHeight, metrics[index].baseHeight + (includeFixedGaps ? metrics[index].fixedHeight : 0.0));
		}
		rowWidths.push_back(rowWidth);
		rowHeights.push_back(rowHeight);
		plan.widthAtBaseScale = std::max(plan.widthAtBaseScale, rowWidth);
		if (includeFixedGaps && rowStart > 0)
		{
			plan.heightAtBaseScale += kBodyGroupVerticalGap;
		}
		plan.heightAtBaseScale += rowHeight;
	}

	double top = plan.heightAtBaseScale * 0.5;
	for (size_t row = 0; row < rowHeights.size(); ++row)
	{
		double rowCenterY = top - rowHeights[row] * 0.5;
		size_t rowStart = row * columns;
		double x = -rowWidths[row] * 0.5;
		for (int col = 0; col < columns; ++col)
		{
			size_t index = rowStart + col;
			if (index >= metrics.size())
			{
				break;
			}
			const double groupWidth = metrics[index].baseWidth + (includeFixedGaps ? metrics[index].fixedWidth : 0.0);
			plan.centersAtBaseScale[index] = NXOpen::Point3d{ x + groupWidth * 0.5, rowCenterY, 0.0 };
			x += groupWidth + (includeFixedGaps ? kBodyGroupHorizontalGap : 0.0);
		}
		top -= rowHeights[row] + (includeFixedGaps ? kBodyGroupVerticalGap : 0.0);
	}
	return plan;
}

static bool FixedGapLayoutFits(
	const std::vector<PendingGroupMetrics>& metrics,
	int columns,
	double scaleFrom100,
	double safeWidth,
	double safeHeight)
{
	if (columns <= 0 || scaleFrom100 <= 0.0)
	{
		return false;
	}

	double totalHeight = 0.0;
	for (size_t rowStart = 0; rowStart < metrics.size(); rowStart += columns)
	{
		double rowWidth = 0.0;
		double rowHeight = 0.0;
		for (int col = 0; col < columns; ++col)
		{
			size_t index = rowStart + col;
			if (index >= metrics.size())
			{
				break;
			}
			if (col > 0)
			{
				rowWidth += kBodyGroupHorizontalGap;
			}
			rowWidth += metrics[index].baseWidth * scaleFrom100 + metrics[index].fixedWidth;
			rowHeight = std::max(rowHeight, metrics[index].baseHeight * scaleFrom100 + metrics[index].fixedHeight);
		}
		if (rowWidth > safeWidth || rowHeight > safeHeight)
		{
			return false;
		}
		if (rowStart > 0)
		{
			totalHeight += kBodyGroupVerticalGap;
		}
		totalHeight += rowHeight;
	}
	return totalHeight <= safeHeight;
}

static double ComputeDenominatorWithFixedGapCheck(
	const std::vector<PendingGroupMetrics>& metrics,
	int columns,
	const PendingGroupLayoutPlan& noGapPlan,
	double safeWidth,
	double safeHeight)
{
	double ratio = std::max(noGapPlan.widthAtBaseScale / safeWidth, noGapPlan.heightAtBaseScale / safeHeight);
	if (ratio <= 0.0)
	{
		ratio = 1.0;
	}

	double denominator = ceil(100.0 * ratio);
	if (denominator < 0.5)
	{
		denominator = 0.5;
	}

	for (int guard = 0; guard < 10000; ++guard)
	{
		double scaleFrom100 = 100.0 / denominator;
		if (FixedGapLayoutFits(metrics, columns, scaleFrom100, safeWidth, safeHeight))
		{
			return denominator;
		}
		denominator += 1.0;
	}
	return denominator;
}

static PendingGroupLayoutPlan ChoosePendingGroupLayoutPlan(
	const std::vector<PendingGroupMetrics>& metrics,
	double safeWidth,
	double safeHeight)
{
	PendingGroupLayoutPlan bestPlan{};
	bestPlan.columns = 0;
	bestPlan.widthAtBaseScale = 0.0;
	bestPlan.heightAtBaseScale = 0.0;
	bestPlan.usedWidth = 0.0;
	bestPlan.usedHeight = 0.0;
	bestPlan.denominator = 100.0;
	if (metrics.empty())
	{
		return bestPlan;
	}

	const LayoutRect safeBounds{ 0.0, 0.0, safeWidth, safeHeight };
	double startDenominator = 1.0;
	double sumAreaAt100 = 0.0;
	for (size_t i = 0; i < metrics.size(); ++i)
	{
		double widthLimit = safeWidth - metrics[i].fixedWidth;
		double heightLimit = safeHeight - metrics[i].fixedHeight;
		if (widthLimit <= 0.0 || heightLimit <= 0.0)
		{
			startDenominator = std::max(startDenominator, 10000.0);
		}
		else
		{
			startDenominator = std::max(startDenominator, ceil(metrics[i].baseWidth * 100.0 / widthLimit));
			startDenominator = std::max(startDenominator, ceil(metrics[i].baseHeight * 100.0 / heightLimit));
		}
		sumAreaAt100 += metrics[i].baseWidth * metrics[i].baseHeight;
	}
	startDenominator = std::max(startDenominator, ceil(sqrt(std::max(0.0, sumAreaAt100) / std::max(1.0, safeWidth * safeHeight)) * 100.0));

	for (double denominator = startDenominator; denominator < 10000.0; denominator += 1.0)
	{
		double scaleFrom100 = 100.0 / denominator;
		std::vector<double> widths(metrics.size(), 0.0);
		std::vector<double> heights(metrics.size(), 0.0);
		for (size_t i = 0; i < metrics.size(); ++i)
		{
			widths[i] = metrics[i].baseWidth * scaleFrom100 + metrics[i].fixedWidth;
			heights[i] = metrics[i].baseHeight * scaleFrom100 + metrics[i].fixedHeight;
		}

		std::vector<NXOpen::Point3d> centersOnSheet;
		double usedWidth = 0.0;
		double usedHeight = 0.0;
		if (!BuildCompactSheetCenters(widths, heights, safeBounds, centersOnSheet, usedWidth, usedHeight))
		{
			continue;
		}

		bestPlan.denominator = denominator;
		bestPlan.widthAtBaseScale = usedWidth / scaleFrom100;
		bestPlan.heightAtBaseScale = usedHeight / scaleFrom100;
		bestPlan.usedWidth = usedWidth;
		bestPlan.usedHeight = usedHeight;
		bestPlan.centersOnSheet = centersOnSheet;
		bestPlan.centersAtBaseScale.resize(centersOnSheet.size(), NXOpen::Point3d{ 0.0, 0.0, 0.0 });

		std::ostringstream oss;
		oss << "[紧凑排布命中]"
			<< " 组数=" << metrics.size()
			<< " 起算比例=1:" << startDenominator
			<< " 命中图纸比例=1:" << denominator
			<< " 实际占用宽=" << usedWidth
			<< " 实际占用高=" << usedHeight
			<< " 可用宽=" << safeWidth
			<< " 可用高=" << safeHeight;
		AppendLayoutDebug(oss.str());
		return bestPlan;
	}

	AppendLayoutDebug("[紧凑排布失败] 未找到可用摆放方案，回退默认比例");
	return bestPlan;
}

static void AccumulateRect(LayoutRect& target, const LayoutRect& source, bool& initialized)
{
	AccumulateRectPoint(target, source.minX, source.minY, initialized);
	AccumulateRectPoint(target, source.maxX, source.maxY, initialized);
}

static bool AskPendingGroupActualRect(const PendingScaleRefit& pending, LayoutRect& rect)
{
	bool initialized = false;
	LayoutRect viewRect{};
	if (pending.mainView != NULL && AskDisplayedCurveRectFromWholeView(pending.mainView, viewRect))
	{
		AccumulateRect(rect, viewRect, initialized);
	}
	for (size_t i = 0; i < pending.sideViews.size(); ++i)
	{
		if (pending.sideViews[i] != NULL && AskDisplayedCurveRectForLayout(pending.sideViews[i], pending.targetBody, viewRect))
	{
			AccumulateRect(rect, viewRect, initialized);
		}
	}
	return initialized && RectWidth(rect) > 0.0 && RectHeight(rect) > 0.0;
}

static bool AskPendingGroupActualRectWithIso(const PendingScaleRefit& pending, LayoutRect& rect)
{
	bool initialized = false;
	LayoutRect groupRect{};
	if (AskPendingGroupActualRect(pending, groupRect))
	{
		AccumulateRect(rect, groupRect, initialized);
	}
	if (pending.isoView != NULL)
	{
		LayoutRect isoRect{};
		if (AskDisplayedCurveRectFromWholeView(pending.isoView, isoRect))
		{
			AccumulateRect(rect, isoRect, initialized);
		}
	}
	return initialized && RectWidth(rect) > 0.0 && RectHeight(rect) > 0.0;
}

static void MovePendingGroupByDelta(const PendingScaleRefit& pending, double deltaX, double deltaY)
{
	MoveViewByDelta(pending.mainView, deltaX, deltaY);
	for (size_t i = 0; i < pending.sideViews.size(); ++i)
	{
		MoveViewByDelta(pending.sideViews[i], deltaX, deltaY);
	}
}

static bool HasPendingIsoView(const std::vector<PendingScaleRefit>& pendingItems)
{
	for (size_t i = 0; i < pendingItems.size(); ++i)
	{
		if (pendingItems[i].isoView != NULL)
		{
			return true;
		}
	}
	return false;
}

static void CenterPendingGroupsInSafeBounds(
	NXOpen::Part* workPart,
	const std::vector<PendingScaleRefit>& pendingItems,
	const LayoutRect& safeBounds)
{
	if (workPart == NULL || pendingItems.empty())
	{
		return;
	}

	LayoutRect totalRect{};
	bool initialized = false;
	for (size_t i = 0; i < pendingItems.size(); ++i)
	{
		LayoutRect groupRect{};
		if (AskPendingGroupActualRectWithIso(pendingItems[i], groupRect))
		{
			AccumulateRect(totalRect, groupRect, initialized);
		}
	}

	if (!initialized || RectWidth(totalRect) <= 0.0 || RectHeight(totalRect) <= 0.0)
	{
		AppendLayoutDebug("[最终居中] 跳过：无法获得实体组总包围盒");
		return;
	}

	NXOpen::Point3d currentCenter = RectCenter(totalRect);
	NXOpen::Point3d targetCenter = RectCenter(safeBounds);
	double deltaX = targetCenter.X - currentCenter.X;
	double deltaY = targetCenter.Y - currentCenter.Y;
	if (RectWidth(totalRect) <= RectWidth(safeBounds))
	{
		if (totalRect.minX + deltaX < safeBounds.minX)
		{
			deltaX = safeBounds.minX - totalRect.minX;
		}
		if (totalRect.maxX + deltaX > safeBounds.maxX)
		{
			deltaX = safeBounds.maxX - totalRect.maxX;
		}
	}
	else
	{
		deltaX = safeBounds.minX - totalRect.minX;
	}

	if (RectHeight(totalRect) <= RectHeight(safeBounds))
	{
		if (totalRect.minY + deltaY < safeBounds.minY)
		{
			deltaY = safeBounds.minY - totalRect.minY;
		}
		if (totalRect.maxY + deltaY > safeBounds.maxY)
		{
			deltaY = safeBounds.maxY - totalRect.maxY;
		}
	}
	else
	{
		deltaY = safeBounds.maxY - totalRect.maxY;
	}
	if (fabs(deltaX) <= 1.0e-6 && fabs(deltaY) <= 1.0e-6)
	{
		AppendLayoutDebug("[最终居中] 已经在可用图框中心，无需移动");
		return;
	}

	for (size_t i = 0; i < pendingItems.size(); ++i)
	{
		MovePendingGroupByDelta(pendingItems[i], deltaX, deltaY);
	}
	std::unordered_set<tag_t> movedIsoTags;
	for (size_t i = 0; i < pendingItems.size(); ++i)
	{
		if (pendingItems[i].isoView == NULL)
		{
			continue;
		}
		const tag_t isoTag = pendingItems[i].isoView->Tag();
		if (movedIsoTags.insert(isoTag).second)
		{
			MoveViewByDelta(pendingItems[i].isoView, deltaX, deltaY);
		}
	}
	RequestWorkViewRegenerate(workPart);

	std::ostringstream oss;
	oss << "[最终居中]"
		<< " 总包围盒=" << RectToString(totalRect)
		<< " 可用图框=" << RectToString(safeBounds)
		<< " 当前中心=(" << currentCenter.X << "," << currentCenter.Y << ")"
		<< " 目标中心=(" << targetCenter.X << "," << targetCenter.Y << ")"
		<< " 平移=(" << deltaX << "," << deltaY << ")";
	AppendLayoutDebug(oss.str());
}

static void PreparePendingIsoViewsForLayout(
	NXOpen::Part* workPart,
	const std::vector<PendingScaleRefit>& pendingItems)
{
	if (workPart == NULL || pendingItems.empty())
	{
		return;
	}

	for (size_t i = 0; i < pendingItems.size(); ++i)
	{
		if (pendingItems[i].isoView != NULL)
		{
			LayoutRect isoRect{};
			if (!AskDisplayedCurveRectFromWholeView(pendingItems[i].isoView, isoRect))
			{
				continue;
			}

			double isoWidth = RectWidth(isoRect);
			double isoHeight = RectHeight(isoRect);
			if (isoWidth <= 0.0 || isoHeight <= 0.0)
			{
				continue;
			}

			const double kIsoTargetScale = 0.70;
			if (RescaleBaseViewAboutCenter(workPart, pendingItems[i].isoView, kIsoTargetScale))
			{
				isoRect = LayoutRect{};
				if (!AskDisplayedCurveRectFromWholeView(pendingItems[i].isoView, isoRect))
				{
					continue;
				}
				isoWidth = RectWidth(isoRect);
				isoHeight = RectHeight(isoRect);
				if (isoWidth <= 0.0 || isoHeight <= 0.0)
				{
					continue;
				}
			}

			LayoutRect layoutRect = isoRect;
			if (isoHeight > isoWidth + 1.0e-6)
			{
				std::ostringstream rotateCheckOss;
				rotateCheckOss << "[轴测图换向判断]"
					<< " 换向前尺寸=(" << isoWidth << "," << isoHeight << ")"
					<< " 结果=需要换向";
				AppendLayoutDebug(rotateCheckOss.str());
				if (RotateIsoViewOnSheetIfNeeded(pendingItems[i].isoView, isoRect))
				{
					NXOpen::Point3d center = RectCenter(isoRect);
					layoutRect = MakeRect(center, isoHeight, isoWidth);
					std::swap(isoWidth, isoHeight);
				}
			}
			else
			{
				std::ostringstream rotateCheckOss;
				rotateCheckOss << "[轴测图换向判断]"
					<< " 换向前尺寸=(" << isoWidth << "," << isoHeight << ")"
					<< " 结果=不换向";
				AppendLayoutDebug(rotateCheckOss.str());
			}

			CachePreparedIsoLayoutRect(pendingItems[i].isoView, layoutRect);
			std::ostringstream isoOss;
			isoOss << "[轴测图预处理]"
				<< " 轴测图布局尺寸=(" << RectWidth(layoutRect) << "," << RectHeight(layoutRect) << ")"
				<< " 采用缩放=0.70"
				<< " 后续=作为普通视图参加紧凑排布";
			AppendLayoutDebug(isoOss.str());
		}
	}
}

static void ArrangePendingGroupsOnSheet(
	NXOpen::Part* workPart,
	const std::vector<PendingScaleRefit>& pendingItems,
	const PendingGroupLayoutPlan& plan)
{
	if (workPart == NULL || pendingItems.empty())
	{
		return;
	}

	const LayoutRect safeBounds{ 18.0, 32.0, 297.0 - 18.0, 210.0 - 20.0 };

	struct SheetPlacementItem
	{
		bool valid;
		bool isoOnly;
		size_t pendingIndex;
		LayoutRect rect;
	};

	std::vector<SheetPlacementItem> placements;
	placements.reserve(pendingItems.size() + 1);
	for (size_t i = 0; i < pendingItems.size(); ++i)
	{
		SheetPlacementItem item{};
		item.valid = AskPendingGroupActualRect(pendingItems[i], item.rect);
		item.isoOnly = false;
		item.pendingIndex = i;
		placements.push_back(item);
		if (pendingItems[i].isoView != NULL)
		{
			SheetPlacementItem isoItem{};
			isoItem.valid = AskPreparedIsoLayoutRect(pendingItems[i].isoView, isoItem.rect);
			if (!isoItem.valid)
			{
				isoItem.valid = AskDisplayedCurveRectFromWholeView(pendingItems[i].isoView, isoItem.rect);
			}
			isoItem.isoOnly = true;
			isoItem.pendingIndex = i;
			placements.push_back(isoItem);
		}
	}

	std::vector<double> widths(placements.size(), 0.0);
	std::vector<double> heights(placements.size(), 0.0);
	for (size_t i = 0; i < placements.size(); ++i)
	{
		if (!placements[i].valid)
		{
			return;
		}
		widths[i] = RectWidth(placements[i].rect);
		heights[i] = RectHeight(placements[i].rect);
	}

	std::vector<NXOpen::Point3d> targetCenters;
	double usedWidth = 0.0;
	double usedHeight = 0.0;
	if (!BuildCompactSheetCenters(widths, heights, safeBounds, targetCenters, usedWidth, usedHeight))
	{
		AppendLayoutDebug("[实体组排布失败] 实际尺寸紧凑排布失败");
		return;
	}

	for (size_t index = 0; index < placements.size(); ++index)
	{
		NXOpen::Point3d currentCenter = RectCenter(placements[index].rect);
		NXOpen::Point3d targetCenter = targetCenters[index];
		if (placements[index].isoOnly)
		{
			MoveViewByDelta(
				pendingItems[placements[index].pendingIndex].isoView,
				targetCenter.X - currentCenter.X,
				targetCenter.Y - currentCenter.Y);
		}
		else
		{
			MovePendingGroupByDelta(
				pendingItems[placements[index].pendingIndex],
				targetCenter.X - currentCenter.X,
				targetCenter.Y - currentCenter.Y);
		}
	}

	RequestWorkViewRegenerate(workPart);
	std::ostringstream oss;
	oss << "[实体组排布] 实体组数量=" << pendingItems.size()
		<< " 排版项数量=" << placements.size()
		<< " 模式=紧凑排布"
		<< " 100比例总宽=" << plan.widthAtBaseScale
		<< " 100比例总高=" << plan.heightAtBaseScale
		<< " 可用宽=" << RectWidth(safeBounds)
		<< " 可用高=" << RectHeight(safeBounds)
		<< " 最终实际总宽=" << usedWidth
		<< " 最终实际总高=" << usedHeight;
	AppendLayoutDebug(oss.str());
}

static void RefitCurrentBodyViewsToSheet(
	NXOpen::Part* workPart,
	NXOpen::Body* targetBody,
	NXOpen::Drawings::BaseView* mainView,
	const std::vector<NXOpen::Drawings::BaseView*>& sideViews,
	NXOpen::Drawings::BaseView* isoView,
	const char* layoutMode,
	bool adjustFirstBodyRightView,
	bool lockToCurrentSheetScale = false)
{
	if (workPart == NULL || mainView == NULL)
	{
		return;
	}

	LayoutRect mainRect{};
	if (!AskDisplayedCurveRectFromWholeView(mainView, mainRect))
	{
		return;
	}

	bool hasRight = false;
	bool hasBottom = false;
	NXOpen::Drawings::BaseView* rightView = NULL;
	NXOpen::Drawings::BaseView* bottomView = NULL;
	LayoutRect rightRect{};
	LayoutRect bottomRect{};

	if (layoutMode != NULL && strcmp(layoutMode, "左") == 0)
	{
		if (!sideViews.empty() && sideViews[0] != NULL && AskDisplayedCurveRectForLayout(sideViews[0], targetBody, rightRect))
		{
			hasRight = true;
			rightView = sideViews[0];
		}
	}
	else if (layoutMode != NULL && strcmp(layoutMode, "下") == 0)
	{
		if (!sideViews.empty() && sideViews[0] != NULL && AskDisplayedCurveRectForLayout(sideViews[0], targetBody, bottomRect))
		{
			hasBottom = true;
			bottomView = sideViews[0];
		}
	}
	else if (layoutMode != NULL && strcmp(layoutMode, "左下") == 0)
	{
		if (sideViews.size() > 0 && sideViews[0] != NULL && AskDisplayedCurveRectForLayout(sideViews[0], targetBody, rightRect))
		{
			hasRight = true;
			rightView = sideViews[0];
		}
		if (sideViews.size() > 1 && sideViews[1] != NULL && AskDisplayedCurveRectForLayout(sideViews[1], targetBody, bottomRect))
		{
			hasBottom = true;
			bottomView = sideViews[1];
		}
	}

	NXOpen::Drawings::DrawingSheet* currentSheet = workPart->DrawingSheets()->CurrentDrawingSheet();
	if (currentSheet == NULL)
	{
		return;
	}

	double currentNumerator = 1.0;
	double currentDenominator = 1.0;
	currentSheet->GetScale(&currentNumerator, &currentDenominator);
	if (currentNumerator <= 0.0 || currentDenominator <= 0.0)
	{
		return;
	}

	const double mainWidth = RectWidth(mainRect);
	const double mainHeight = RectHeight(mainRect);
	const double rightWidth = hasRight ? RectWidth(rightRect) : 0.0;
	const double rightHeight = hasRight ? RectHeight(rightRect) : 0.0;
	const double bottomWidth = hasBottom ? RectWidth(bottomRect) : 0.0;
	const double bottomHeight = hasBottom ? RectHeight(bottomRect) : 0.0;
	const NXOpen::Point3d mainLocalCenter = RectCenter(mainRect);
	const NXOpen::Point3d rightLocalCenter = hasRight ? RectCenter(rightRect) : NXOpen::Point3d{ 0.0, 0.0, 0.0 };
	const NXOpen::Point3d bottomLocalCenter = hasBottom ? RectCenter(bottomRect) : NXOpen::Point3d{ 0.0, 0.0, 0.0 };

	NXOpen::Drawings::DraftingView* mainDraftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(mainView);
	NXOpen::Point3d mainRef = mainDraftingView != NULL ? mainDraftingView->GetDrawingReferencePoint() : NXOpen::Point3d{ 0.0, 0.0, 0.0 };
	NXOpen::Point3d rightRef{ 0.0, 0.0, 0.0 };
	NXOpen::Point3d bottomRef{ 0.0, 0.0, 0.0 };
	if (rightView != NULL)
	{
		NXOpen::Drawings::DraftingView* rightDraftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(rightView);
		if (rightDraftingView != NULL)
		{
			rightRef = rightDraftingView->GetDrawingReferencePoint();
		}
	}
	if (bottomView != NULL)
	{
		NXOpen::Drawings::DraftingView* bottomDraftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(bottomView);
		if (bottomDraftingView != NULL)
		{
			bottomRef = bottomDraftingView->GetDrawingReferencePoint();
		}
	}

	const double sheetScale = currentNumerator / currentDenominator;
	const double mainWidthSheet = mainWidth;
	const double mainHeightSheet = mainHeight;
	const double rightWidthSheet = rightWidth;
	const double rightHeightSheet = rightHeight;
	const double bottomWidthSheet = bottomWidth;
	const double bottomHeightSheet = bottomHeight;

	double usedWidth = mainWidthSheet;
	double usedHeight = mainHeightSheet;
	double availableWidth = 220.0;
	double availableHeight = 140.0;
	if (layoutMode != NULL && strcmp(layoutMode, "左") == 0)
	{
		usedWidth = mainWidthSheet + rightWidthSheet;
		usedHeight = std::max(mainHeightSheet, rightHeightSheet);
		availableWidth = 200.0;
		availableHeight = 130.0;
	}
	else if (layoutMode != NULL && strcmp(layoutMode, "下") == 0)
	{
		usedWidth = std::max(mainWidthSheet, bottomWidthSheet);
		usedHeight = mainHeightSheet + bottomHeightSheet;
		availableWidth = 220.0;
		availableHeight = 110.0;
	}
	else if (layoutMode != NULL && strcmp(layoutMode, "左下") == 0)
	{
		usedWidth = mainWidthSheet + rightWidthSheet;
		usedHeight = mainHeightSheet + bottomHeightSheet;
		availableWidth = 200.0;
		availableHeight = 110.0;
	}

	double scaleRatio = std::max(usedWidth / availableWidth, usedHeight / availableHeight);
	if (scaleRatio <= 0.0)
	{
		scaleRatio = 1.0;
	}

	double newDenominator = currentDenominator;
	if (!lockToCurrentSheetScale)
	{
		newDenominator = currentDenominator * scaleRatio;
		if (newDenominator < 0.5)
		{
			newDenominator = 0.5;
		}
		else if (newDenominator > 0.5)
		{
			newDenominator = ceil(newDenominator);
		}
	}

	{
		std::ostringstream oss;
		oss << "[Refit] layout=" << (layoutMode != NULL ? layoutMode : "(null)")
			<< " mainRect=" << RectToString(mainRect)
			<< " mainRef=(" << mainRef.X << "," << mainRef.Y << ")"
			<< " mainLocalCenter=(" << mainLocalCenter.X << "," << mainLocalCenter.Y << ")"
			<< " rightRect=" << (hasRight ? RectToString(rightRect) : "(none)")
			<< " rightRef=(" << rightRef.X << "," << rightRef.Y << ")"
			<< " rightLocalCenter=(" << rightLocalCenter.X << "," << rightLocalCenter.Y << ")"
			<< " bottomRect=" << (hasBottom ? RectToString(bottomRect) : "(none)")
			<< " bottomRef=(" << bottomRef.X << "," << bottomRef.Y << ")"
			<< " bottomLocalCenter=(" << bottomLocalCenter.X << "," << bottomLocalCenter.Y << ")"
			<< " used=(" << usedWidth << "," << usedHeight << ")"
			<< " available=(" << availableWidth << "," << availableHeight << ")"
			<< " currentDen=" << currentDenominator
			<< " scaleRatio=" << scaleRatio
			<< " newDen=" << newDenominator;
		AppendLayoutDebug(oss.str());
	}

	NXOpen::Drawings::DraftingDrawingSheet* draftingSheet = dynamic_cast<NXOpen::Drawings::DraftingDrawingSheet*>(currentSheet);
	if (!lockToCurrentSheetScale && draftingSheet != NULL)
	{
		NXOpen::Drawings::DraftingDrawingSheetBuilder* sheetBuilder = workPart->DraftingDrawingSheets()->CreateDraftingDrawingSheetBuilder(draftingSheet);
		sheetBuilder->SetStandardMetricScale(NXOpen::Drawings::DrawingSheetBuilder::SheetStandardMetricScaleCustom);
		sheetBuilder->SetScaleNumerator(currentNumerator);
		sheetBuilder->SetScaleDenominator(newDenominator);
		sheetBuilder->Commit();
		sheetBuilder->Destroy();
	}

	const double newSheetScale = currentNumerator / newDenominator;
	const double scaleUpdateRatio = (sheetScale > 0.0) ? (newSheetScale / sheetScale) : 1.0;
	const NXOpen::Point3d mainCenterOffsetFromRef{
		mainLocalCenter.X - mainRef.X,
		mainLocalCenter.Y - mainRef.Y,
		0.0
	};
	const NXOpen::Point3d rightCenterOffsetFromRef{
		rightLocalCenter.X - rightRef.X,
		rightLocalCenter.Y - rightRef.Y,
		0.0
	};
	const NXOpen::Point3d bottomCenterOffsetFromRef{
		bottomLocalCenter.X - bottomRef.X,
		bottomLocalCenter.Y - bottomRef.Y,
		0.0
	};
	if (adjustFirstBodyRightView && hasRight && rightView != NULL)
	{
		NXOpen::Drawings::DraftingView* rightDraftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(rightView);
		if (rightDraftingView != NULL)
		{
			NXOpen::Point3d updatedMainRef = GetViewReferencePoint(mainView);
			NXOpen::Point3d updatedRightRef = rightDraftingView->GetDrawingReferencePoint();
			NXOpen::Point3d newRightRef = updatedRightRef;
			const double mainActualCenterX = updatedMainRef.X + mainCenterOffsetFromRef.X * scaleUpdateRatio;
			const double mainActualCenterY = updatedMainRef.Y + mainCenterOffsetFromRef.Y * scaleUpdateRatio;
			const double mainHalfWidthSheet = mainWidth * scaleUpdateRatio * 0.5;
			const double rightHalfWidthSheet = rightWidth * scaleUpdateRatio * 0.5;
			const double rightMidXSheet = rightCenterOffsetFromRef.X * scaleUpdateRatio;
			const double rightMidYSheet = rightCenterOffsetFromRef.Y * scaleUpdateRatio;
			const double desiredRightRefX =
				mainActualCenterX +
				mainHalfWidthSheet +
				kViewHorizontalGap +
				rightHalfWidthSheet -
				rightMidXSheet;
			const double desiredRightRefY = mainActualCenterY - rightMidYSheet;

			if (lockToCurrentSheetScale)
			{
				newRightRef.X = desiredRightRefX;
				newRightRef.Y = desiredRightRefY;
				rightDraftingView->MoveView(newRightRef);
				updatedRightRef = rightDraftingView->GetDrawingReferencePoint();
			}

			std::ostringstream moveOss;
			moveOss << "[RightMove] "
				<< " sheetScale=" << sheetScale
				<< " newSheetScale=" << newSheetScale
				<< " scaleUpdateRatio=" << scaleUpdateRatio
				<< " mainCenterOffsetX=" << mainCenterOffsetFromRef.X
				<< " rightCenterOffsetX=" << rightCenterOffsetFromRef.X
				<< "mainActualCenterX=" << mainActualCenterX
				<< " mainActualCenterY=" << mainActualCenterY
				<< " mainHalfWidthSheet=" << mainHalfWidthSheet
				<< " rightHalfWidthSheet=" << rightHalfWidthSheet
				<< " gapX=" << kViewHorizontalGap
				<< " rightMidXSheet=" << rightMidXSheet
				<< " rightMidYSheet=" << rightMidYSheet
				<< " updatedRightRefX=" << updatedRightRef.X
				<< " updatedRightRefY=" << updatedRightRef.Y
				<< " desiredRightRefX=" << desiredRightRefX;
			AppendLayoutDebug(moveOss.str());
		}
	}
	if (adjustFirstBodyRightView && hasBottom && bottomView != NULL)
	{
		NXOpen::Drawings::DraftingView* bottomDraftingView = dynamic_cast<NXOpen::Drawings::DraftingView*>(bottomView);
		if (bottomDraftingView != NULL)
		{
			NXOpen::Point3d updatedMainRef = GetViewReferencePoint(mainView);
			NXOpen::Point3d updatedBottomRef = bottomDraftingView->GetDrawingReferencePoint();
			NXOpen::Point3d newBottomRef = updatedBottomRef;
			const double mainActualCenterX = updatedMainRef.X + mainCenterOffsetFromRef.X * scaleUpdateRatio;
			const double mainActualCenterY = updatedMainRef.Y + mainCenterOffsetFromRef.Y * scaleUpdateRatio;
			const double mainHalfHeightSheet = mainHeight * scaleUpdateRatio * 0.5;
			const double bottomHalfHeightSheet = bottomHeight * scaleUpdateRatio * 0.5;
			const double bottomMidXSheet = bottomCenterOffsetFromRef.X * scaleUpdateRatio;
			const double bottomMidYSheet = bottomCenterOffsetFromRef.Y * scaleUpdateRatio;
			const double desiredBottomRefX = mainActualCenterX - bottomMidXSheet;
			const double desiredBottomRefY =
				mainActualCenterY -
				mainHalfHeightSheet -
				kViewVerticalGap -
				bottomHalfHeightSheet -
				bottomMidYSheet;

			if (lockToCurrentSheetScale)
			{
				newBottomRef.X = desiredBottomRefX;
				newBottomRef.Y = desiredBottomRefY;
				bottomDraftingView->MoveView(newBottomRef);
				updatedBottomRef = bottomDraftingView->GetDrawingReferencePoint();
			}

			std::ostringstream moveOss;
			moveOss << "[BottomMove] "
				<< " sheetScale=" << sheetScale
				<< " newSheetScale=" << newSheetScale
				<< " scaleUpdateRatio=" << scaleUpdateRatio
				<< " mainCenterOffsetY=" << mainCenterOffsetFromRef.Y
				<< " bottomCenterOffsetY=" << bottomCenterOffsetFromRef.Y
				<< " mainActualCenterX=" << mainActualCenterX
				<< " mainActualCenterY=" << mainActualCenterY
				<< " mainHalfHeightSheet=" << mainHalfHeightSheet
				<< " bottomHalfHeightSheet=" << bottomHalfHeightSheet
				<< " gapY=" << kViewVerticalGap
				<< " bottomMidXSheet=" << bottomMidXSheet
				<< " bottomMidYSheet=" << bottomMidYSheet
				<< " updatedBottomRefX=" << updatedBottomRef.X
				<< " updatedBottomRefY=" << updatedBottomRef.Y
				<< " desiredBottomRefX=" << desiredBottomRefX
				<< " desiredBottomRefY=" << desiredBottomRefY;
			AppendLayoutDebug(moveOss.str());
		}
	}

	RequestWorkViewRegenerate(workPart);
	{
		std::ostringstream oss;
		oss << "[Place] layout=" << (layoutMode != NULL ? layoutMode : "(null)")
			<< " positions=unchanged"
			<< " scaleOnlyDen=" << newDenominator
			<< " lockToCurrentSheetScale=" << (lockToCurrentSheetScale ? "true" : "false")
			<< " scaleUpdateRatio=" << scaleUpdateRatio
			<< " mainWidthAfterScale=" << mainWidth * scaleUpdateRatio
			<< " mainHeightAfterScale=" << mainHeight * scaleUpdateRatio
			<< " rightWidthAfterScale=" << rightWidth * scaleUpdateRatio
			<< " rightHeightAfterScale=" << rightHeight * scaleUpdateRatio
			<< " bottomWidthAfterScale=" << bottomWidth * scaleUpdateRatio
			<< " bottomHeightAfterScale=" << bottomHeight * scaleUpdateRatio
			<< " adjustFirstBodyRightView=" << (adjustFirstBodyRightView ? "true" : "false");
		AppendLayoutDebug(oss.str());
	}
	RequestWorkViewRegenerate(workPart);
}

static void QueueOrRefitCurrentBodyViewsToSheet(
	NXOpen::Part* workPart,
	NXOpen::Body* targetBody,
	NXOpen::Drawings::BaseView* mainView,
	const std::vector<NXOpen::Drawings::BaseView*>& sideViews,
	NXOpen::Drawings::BaseView* isoView,
	const char* layoutMode,
	bool adjustFirstBodyRightView,
	bool useLegacyAabbAfterLayout = false)
{
	std::ostringstream perfLabel;
	perfLabel << "QueueOrRefitCurrentBodyViewsToSheet bodyTag=" << PerfTagOf(targetBody)
		<< " deferred=" << (g_deferPageRefit ? "true" : "false");
	ScopedPerfTimer perfTimer(perfLabel.str());
	if (g_manualPlacementNoRefit)
	{
		AppendLayoutDebug("[手动模式] 已按鼠标点位放置视图，跳过自动缩放和自动排版");
		return;
	}
	{
		std::ostringstream oss;
		oss << "[队列/缩放入口] defer=" << (g_deferPageRefit ? "true" : "false")
			<< " layout=" << (layoutMode != NULL ? layoutMode : "(null)")
			<< " targetBodyTag=" << (targetBody != NULL ? targetBody->Tag() : NULL_TAG)
			<< " mainViewTag=" << (mainView != NULL ? mainView->Tag() : NULL_TAG)
			<< " sideViewCount=" << sideViews.size()
			<< " isoViewTag=" << (isoView != NULL ? isoView->Tag() : NULL_TAG);
		AppendLayoutDebug(oss.str());
	}
	if (g_deferPageRefit)
	{
		PendingScaleRefit pending{};
		pending.targetBody = targetBody;
		pending.mainView = mainView;
		pending.sideViews = sideViews;
		pending.isoView = isoView;
		pending.layoutMode = (layoutMode != NULL) ? layoutMode : "";
		pending.adjustFirstBodyRightView = adjustFirstBodyRightView;
		pending.useLegacyAabbAfterLayout = useLegacyAabbAfterLayout;
		g_pendingScaleRefits.push_back(pending);
		return;
	}

	RefitCurrentBodyViewsToSheet(
		workPart,
		targetBody,
		mainView,
		sideViews,
		isoView,
		layoutMode,
		adjustFirstBodyRightView,
		false);
}

static void FinalizePendingGroupScaleAndLayout(NXOpen::Part* workPart)
{
	ScopedPerfTimer perfTimer("FinalizePendingGroupScaleAndLayout");
	if (workPart == NULL || g_pendingScaleRefits.empty())
	{
		std::ostringstream oss;
		oss << "[最终排版提前结束] workPart=" << (workPart != NULL ? "有效" : "空")
			<< " pendingCount=" << g_pendingScaleRefits.size()
			<< " 原因=工作部件为空或待排版实体组为空";
		AppendLayoutDebug(oss.str());
		return;
	}

	{
		std::ostringstream oss;
		oss << "[最终排版入口] pendingCount=" << g_pendingScaleRefits.size();
		AppendLayoutDebug(oss.str());
	}
	g_preparedIsoLayoutRects.clear();
	g_draftingBodyCache.clear();

	NXOpen::Drawings::DrawingSheet* currentSheet = workPart->DrawingSheets()->CurrentDrawingSheet();
	NXOpen::Drawings::DraftingDrawingSheet* draftingSheet = dynamic_cast<NXOpen::Drawings::DraftingDrawingSheet*>(currentSheet);
	if (currentSheet == NULL || draftingSheet == NULL)
	{
		std::ostringstream oss;
		oss << "[最终排版提前结束] 当前图纸页无效";
		AppendLayoutDebug(oss.str());
		return;
	}

	double currentNumerator = 1.0;
	double currentDenominator = 1.0;
	currentSheet->GetScale(&currentNumerator, &currentDenominator);
	if (currentNumerator <= 0.0 || currentDenominator <= 0.0)
	{
		std::ostringstream oss;
		oss << "[最终排版提前结束] 当前图纸比例非法 numerator=" << currentNumerator
			<< " denominator=" << currentDenominator;
		AppendLayoutDebug(oss.str());
		return;
	}

	std::vector<PendingGroupMetrics> metrics;
	metrics.reserve(g_pendingScaleRefits.size());
	for (size_t i = 0; i < g_pendingScaleRefits.size(); ++i)
	{
		PendingGroupMetrics item{};
		if (ComputePendingGroupMetrics(g_pendingScaleRefits[i], item))
		{
			std::ostringstream itemOss;
			itemOss << "[实体组尺寸] 序号=" << i
				<< " 布局=" << g_pendingScaleRefits[i].layoutMode
				<< " 展开图包围盒=" << RectToString(item.mainRect)
				<< " 展开图尺寸=(" << RectWidth(item.mainRect) << "," << RectHeight(item.mainRect) << ")"
				<< " 有右视图=" << (item.hasRight ? "是" : "否")
				<< " 右视图包围盒=" << (item.hasRight ? RectToString(item.rightRect) : "(无)")
				<< " 右视图尺寸=(" << (item.hasRight ? RectWidth(item.rightRect) : 0.0) << "," << (item.hasRight ? RectHeight(item.rightRect) : 0.0) << ")"
				<< " 有下视图=" << (item.hasBottom ? "是" : "否")
				<< " 下视图包围盒=" << (item.hasBottom ? RectToString(item.bottomRect) : "(无)")
				<< " 下视图尺寸=(" << (item.hasBottom ? RectWidth(item.bottomRect) : 0.0) << "," << (item.hasBottom ? RectHeight(item.bottomRect) : 0.0) << ")"
				<< " 组基础尺寸=(" << item.baseWidth << "," << item.baseHeight << ")"
				<< " 初算不带固定间距"
				<< " 校验固定间距=(" << item.fixedWidth << "," << item.fixedHeight << ")"
				<< " 校验用100比例组尺寸=(" << (item.baseWidth + item.fixedWidth) << "," << (item.baseHeight + item.fixedHeight) << ")";
			AppendLayoutDebug(itemOss.str());
			metrics.push_back(item);
		}
	}
	for (size_t i = 0; i < g_pendingScaleRefits.size(); ++i)
	{
		if (g_pendingScaleRefits[i].isoView == NULL)
		{
			continue;
		}
		LayoutRect isoRect{};
		if (!AskDisplayedCurveRectFromWholeView(g_pendingScaleRefits[i].isoView, isoRect))
		{
			AppendLayoutDebug("[轴测图比例项失败] 原始轴测图包围盒失败");
			continue;
		}
		double isoWidth = RectWidth(isoRect) * 0.70;
		double isoHeight = RectHeight(isoRect) * 0.70;
		bool swappedForLayout = false;
		if (isoHeight > isoWidth + 1.0e-6)
		{
			std::swap(isoWidth, isoHeight);
			swappedForLayout = true;
		}
		if (isoWidth <= 0.0 || isoHeight <= 0.0)
		{
			continue;
		}

		PendingGroupMetrics isoMetric{};
		isoMetric.valid = true;
		isoMetric.mainRect = MakeRect(RectCenter(isoRect), isoWidth, isoHeight);
		isoMetric.baseWidth = isoWidth;
		isoMetric.baseHeight = isoHeight;
		isoMetric.fixedWidth = 0.0;
		isoMetric.fixedHeight = 0.0;
		metrics.push_back(isoMetric);

		std::ostringstream isoMetricOss;
		isoMetricOss << "[轴测图比例项]"
			<< " 原始包围盒=" << RectToString(isoRect)
			<< " 原始尺寸=(" << RectWidth(isoRect) << "," << RectHeight(isoRect) << ")"
			<< " 70%布局尺寸=(" << isoWidth << "," << isoHeight << ")"
			<< " 是否换向交换XY=" << (swappedForLayout ? "是" : "否");
		AppendLayoutDebug(isoMetricOss.str());
		break;
	}
	if (metrics.empty())
	{
		AppendLayoutDebug("[最终排版提前结束] 所有实体组尺寸计算失败，metrics为空");
		return;
	}

	const LayoutRect safeBounds{ 18.0, 32.0, 297.0 - 18.0, 210.0 - 20.0 };
	PendingGroupLayoutPlan plan = ChoosePendingGroupLayoutPlan(
		metrics,
		RectWidth(safeBounds),
		RectHeight(safeBounds));
	double rawScaleRatio = std::max(
		plan.widthAtBaseScale / RectWidth(safeBounds),
		plan.heightAtBaseScale / RectHeight(safeBounds));
	double newDenominator = plan.denominator;
	double scaleRatio = newDenominator / 100.0;
	if (scaleRatio <= 0.0)
	{
		scaleRatio = 1.0;
	}

	if (newDenominator < 0.5)
	{
		newDenominator = 0.5;
	}
	else if (newDenominator > 0.5)
	{
		newDenominator = ceil(newDenominator);
	}

	NXOpen::Drawings::DraftingDrawingSheetBuilder* sheetBuilder = workPart->DraftingDrawingSheets()->CreateDraftingDrawingSheetBuilder(draftingSheet);
	sheetBuilder->SetStandardMetricScale(NXOpen::Drawings::DrawingSheetBuilder::SheetStandardMetricScaleCustom);
	sheetBuilder->SetScaleNumerator(currentNumerator);
	sheetBuilder->SetScaleDenominator(newDenominator);
	sheetBuilder->Commit();
	sheetBuilder->Destroy();
	RequestWorkViewRegenerate(workPart);

	std::ostringstream oss;
	oss << "[最终图纸比例] 实体组数量=" << metrics.size()
		<< " 排布模式=紧凑排版"
		<< " 当前比例分母=" << currentDenominator
		<< " 可用宽=" << RectWidth(safeBounds)
		<< " 可用高=" << RectHeight(safeBounds)
		<< " 100比例总宽=" << plan.widthAtBaseScale
		<< " 100比例总高=" << plan.heightAtBaseScale
		<< " X方向比例=" << (plan.widthAtBaseScale / RectWidth(safeBounds))
		<< " Y方向比例=" << (plan.heightAtBaseScale / RectHeight(safeBounds))
		<< " 初算采用比例=" << rawScaleRatio
		<< " 紧凑排版采用比例=" << scaleRatio
		<< " 新图纸比例=1:" << newDenominator;
	AppendLayoutDebug(oss.str());

	for (size_t i = 0; i < g_pendingScaleRefits.size(); ++i)
	{
		const PendingScaleRefit& pending = g_pendingScaleRefits[i];
		RefitCurrentBodyViewsToSheet(
			workPart,
			pending.targetBody,
			pending.mainView,
			pending.sideViews,
			pending.isoView,
			pending.layoutMode.c_str(),
			true,
			true);
	}

	if (HasPendingIsoView(g_pendingScaleRefits))
	{
		PreparePendingIsoViewsForLayout(workPart, g_pendingScaleRefits);
	}
	ArrangePendingGroupsOnSheet(workPart, g_pendingScaleRefits, plan);
	CenterPendingGroupsInSafeBounds(workPart, g_pendingScaleRefits, safeBounds);

	if (g_activeZiDonCuTuDialog != NULL)
	{
		for (size_t i = 0; i < g_pendingScaleRefits.size(); ++i)
		{
			const PendingScaleRefit& pending = g_pendingScaleRefits[i];
			if (!pending.useLegacyAabbAfterLayout || pending.targetBody == NULL || pending.mainView == NULL)
			{
				continue;
			}

			Body1 = pending.targetBody;
			ObZanKaiView = pending.mainView;
			BaseViewvector = pending.sideViews;
			Zen3DView = pending.isoView;

			{
				NXOpen::Drawings::DrawingSheet* currentSheet = workPart->DrawingSheets()->CurrentDrawingSheet();
				double beforeNumerator = 1.0;
				double beforeDenominator = 1.0;
				if (currentSheet != NULL)
				{
					currentSheet->GetScale(&beforeNumerator, &beforeDenominator);
				}
				LayoutRect beforeRect{};
				bool hasBeforeRect = AskDisplayedCurveRectFromWholeView(pending.mainView, beforeRect);
				NXOpen::Point3d beforeRef = GetViewReferencePoint(pending.mainView);
				std::ostringstream beforeOss;
				beforeOss << "[排版后回放前] bodyTag=" << pending.targetBody->Tag()
					<< " viewTag=" << pending.mainView->Tag()
					<< " sheetScale=" << beforeNumerator << ":" << beforeDenominator
					<< " ref=(" << beforeRef.X << "," << beforeRef.Y << "," << beforeRef.Z << ")";
				if (hasBeforeRect)
				{
					beforeOss << " rect=" << RectToString(beforeRect);
				}
				else
				{
					beforeOss << " rect=<invalid>";
				}
				AppendLayoutDebug(beforeOss.str());

				for (size_t sideIndex = 0; sideIndex < pending.sideViews.size(); ++sideIndex)
				{
					NXOpen::Drawings::BaseView* sideView = pending.sideViews[sideIndex];
					if (sideView == NULL)
					{
						continue;
					}
					LayoutRect sideRect{};
					bool hasSideRect = AskDisplayedCurveRect(sideView, pending.targetBody, sideRect);
					NXOpen::Point3d sideRef = GetViewReferencePoint(sideView);
					std::ostringstream sideOss;
					sideOss << "[排版后回放前-侧视图] bodyTag=" << pending.targetBody->Tag()
						<< " 序号=" << sideIndex
						<< " viewTag=" << sideView->Tag()
						<< " ref=(" << sideRef.X << "," << sideRef.Y << "," << sideRef.Z << ")";
					if (hasSideRect)
					{
						sideOss << " rect=" << RectToString(sideRect);
					}
					else
					{
						sideOss << " rect=<invalid>";
					}
					AppendLayoutDebug(sideOss.str());
				}
			}

			g_runLegacyAaaaAnnotationOnly = true;
			g_activeZiDonCuTuDialog->aaaa_cb();
			g_runLegacyAaaaAnnotationOnly = false;

			{
				NXOpen::Drawings::DrawingSheet* currentSheet = workPart->DrawingSheets()->CurrentDrawingSheet();
				double afterNumerator = 1.0;
				double afterDenominator = 1.0;
				if (currentSheet != NULL)
				{
					currentSheet->GetScale(&afterNumerator, &afterDenominator);
				}
				LayoutRect afterRect{};
				bool hasAfterRect = AskDisplayedCurveRectFromWholeView(pending.mainView, afterRect);
				NXOpen::Point3d afterRef = GetViewReferencePoint(pending.mainView);
				std::ostringstream afterOss;
				afterOss << "[排版后回放后] bodyTag=" << pending.targetBody->Tag()
					<< " viewTag=" << pending.mainView->Tag()
					<< " sheetScale=" << afterNumerator << ":" << afterDenominator
					<< " ref=(" << afterRef.X << "," << afterRef.Y << "," << afterRef.Z << ")";
				if (hasAfterRect)
				{
					afterOss << " rect=" << RectToString(afterRect);
				}
				else
				{
					afterOss << " rect=<invalid>";
				}
				AppendLayoutDebug(afterOss.str());

				for (size_t sideIndex = 0; sideIndex < pending.sideViews.size(); ++sideIndex)
				{
					NXOpen::Drawings::BaseView* sideView = pending.sideViews[sideIndex];
					if (sideView == NULL)
					{
						continue;
					}
					LayoutRect sideRect{};
					bool hasSideRect = AskDisplayedCurveRect(sideView, pending.targetBody, sideRect);
					NXOpen::Point3d sideRef = GetViewReferencePoint(sideView);
					std::ostringstream sideOss;
					sideOss << "[排版后回放后-侧视图] bodyTag=" << pending.targetBody->Tag()
						<< " 序号=" << sideIndex
						<< " viewTag=" << sideView->Tag()
						<< " ref=(" << sideRef.X << "," << sideRef.Y << "," << sideRef.Z << ")";
					if (hasSideRect)
					{
						sideOss << " rect=" << RectToString(sideRect);
					}
					else
					{
						sideOss << " rect=<invalid>";
					}
					AppendLayoutDebug(sideOss.str());
				}
			}

			ApplySideViewLayerIsolationForBody(pending.targetBody, pending.sideViews);
		}
	}
	for (size_t i = 0; i < g_pendingScaleRefits.size(); ++i)
	{
		const PendingScaleRefit& pending = g_pendingScaleRefits[i];
		ApplySideViewLayerIsolationForBody(pending.targetBody, pending.sideViews);
	}
}
