//------------------------------------------------------------------------------
//Callback Name: dialogShown_cb
//This callback is executed just before the dialog launch. Thus any value set
//here will take precedence and dialog will be launched showing that value.
//------------------------------------------------------------------------------
void ZiDonCuTu::dialogShown_cb()
{
	try
	{


		UF_terminate();

		Drawings::DrawingSheetCollection* DrawingSheet = workPart->DrawingSheets();
		Drawings::DrawingSheetCollection::iterator Ite = workPart->DrawingSheets()->begin();//定义迭代器
		if (Ite == DrawingSheet->end())
		{
			toggle0->SetValue(true);
		}
		else
		{
			toggle0->SetValue(false);
		}
		if (enumDrawingMode != NULL)
		{
			std::vector<NXString> drawingModeMembers;
			drawingModeMembers.push_back("自动");
			drawingModeMembers.push_back("手动");
			enumDrawingMode->SetEnumMembers(drawingModeMembers);
			if (std::string(GetEnumBlockValue(enumDrawingMode, "自动").GetLocaleText()).empty())
			{
				enumDrawingMode->SetValueAsString("自动");
			}
		}
		if (enumSheetLayout != NULL)
		{
			std::vector<NXString> sheetLayoutMembers;
			sheetLayoutMembers.push_back("部件里的零件在一张图纸页里");
			sheetLayoutMembers.push_back("一个零件一张图纸页");
			sheetLayoutMembers.push_back("自定义图纸页零件数");
			enumSheetLayout->SetEnumMembers(sheetLayoutMembers);
			if (std::string(GetEnumBlockValue(enumSheetLayout, "部件里的零件在一张图纸页里").GetLocaleText()).empty())
			{
				enumSheetLayout->SetValueAsString("部件里的零件在一张图纸页里");
			}
		}
		if (integerSheetPartCount != NULL && integerSheetPartCount->Value() < 1)
		{
			integerSheetPartCount->SetValue(2);
		}
		if (doubleRInnerThreshold != NULL && doubleRInnerThreshold->Value() < 0.0)
		{
			doubleRInnerThreshold->SetValue(0.5);
		}
		const bool hasDrawingSheet = HasAnyDrawingSheet(workPart);
		const bool manualMode = IsManualDrawingMode(enumDrawingMode);
		UpdateSheetLayoutControls(enumSheetLayout, integerSheetPartCount, toggle01, !manualMode);
		if (manualMode)
		{
			SetBodySelectionMode(selection0, true);
			if (toggle0 != NULL)
			{
				toggle0->SetShow(true);
			}
		}
		else
		{
			SetBodySelectionMode(selection0, false);
			if (toggle0 != NULL)
			{
				toggle0->SetShow(false);
			}
		}

		//获取创建图纸页开关值
		PropertyList* toggle0Props = toggle0->GetProperties();
		int Thetoggle0 = toggle0Props->GetLogical("Value");
		delete toggle0Props;
		toggle0Props = NULL;
		point0->SetShow(manualMode && Thetoggle0 == 0);
		if (enum01 != NULL)
		{
			enum01->SetValueAsString("无");
			enum01->SetShow(false);
		}
		UpdateHoleMarkerControls(toggleHoleAttribute, stringHoleMarker);
		if (enum01 != NULL)
		{
			enum01->SetShow(false);
		}

	}
	catch (exception& ex)
	{
		//---- Enter your exception handling code here -----
		ZiDonCuTu::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
	}
}

static bool PrepareBodyDraftingContext(NXOpen::Body* targetBody, NXOpen::BlockStyler::Enumeration* enum0Block, bool& acaFlag);
static void ApplyViewLayerIsolation(NXOpen::Drawings::BaseView* baseView, NXOpen::Body* body);
extern Point3d notPoint3d;
extern NXOpen::Body* Body1;
extern Drawings::BaseView* BaseView1A;
extern bool ACA;

//------------------------------------------------------------------------------
//Callback Name: apply_cb
//------------------------------------------------------------------------------
int ZiDonCuTu::apply_cb()
{
	int errorCode = 0;
	ScopedPerfTimer applyPerfTimer("apply_cb");
	try
	{
		theSession->ApplicationSwitchImmediate("UG_APP_DRAFTING");//转到绘图模式
		const bool manualMode = IsManualDrawingMode(enumDrawingMode);
		const bool hasDrawingSheet = HasAnyDrawingSheet(workPart);
		if (manualMode && g_manualActionCompleted)
		{
			return 0;
		}
		if (manualMode)
		{
			SetBodySelectionMode(selection0, true);
			if (!hasDrawingSheet && toggle0 != NULL)
			{
				toggle0->SetValue(true);
			}
			if (point0 != NULL)
			{
				int createSheet = !hasDrawingSheet ? 1 : 0;
				if (toggle0 != NULL)
				{
					PropertyList* manualToggleProps = toggle0->GetProperties();
					if (manualToggleProps != NULL)
					{
						createSheet = manualToggleProps->GetLogical("Value");
						delete manualToggleProps;
						manualToggleProps = NULL;
					}
				}
				point0->SetShow(createSheet == 0);
			}
		}
		PropertyList* selection0Props = selection0->GetProperties();
		std::vector<NXOpen::TaggedObject*> selectedObjects = selection0Props->GetTaggedObjectVector("SelectedObjects");
		delete selection0Props;
		selection0Props = NULL;
		auto processSelectedObjects = [&](std::vector<NXOpen::TaggedObject*> objectsToProcess) -> void
		{
			ScopedPerfTimer processPerfTimer("processSelectedObjects");
			DeduplicateTaggedObjectsByTag(objectsToProcess);
			if (objectsToProcess.empty())
			{
				return;
			}
			if (manualMode && objectsToProcess.size() > 1)
			{
				objectsToProcess.resize(1);
			}
			LayerStateSnapshot drawingLayerSnapshot = SaveCurrentLayerStates();
			const bool currentHasDrawingSheet = HasAnyDrawingSheet(workPart);
			const int automaticBodiesPerSheet = manualMode
				? 1
				: GetAutomaticBodiesPerSheet(enumSheetLayout, integerSheetPartCount, static_cast<int>(objectsToProcess.size()));
			const NXString automaticSheetLayoutValue = GetEnumBlockValue(enumSheetLayout, "部件里的零件在一张图纸页里");
			const bool automaticOneBodyPerSheet =
				!manualMode &&
				(std::string(automaticSheetLayoutValue.GetLocaleText()) == "一个零件一张图纸页");
			const bool automaticCustomSheetLayout =
				!manualMode &&
				(std::string(automaticSheetLayoutValue.GetLocaleText()) == "自定义图纸页零件数");
			const bool automaticMultiBodyPerSheet =
				!manualMode &&
				!automaticOneBodyPerSheet;
			{
				std::ostringstream perf;
				perf << "[perf] processSelectedObjects begin objectCount=" << objectsToProcess.size()
					<< " bodiesPerSheet=" << automaticBodiesPerSheet
					<< " manualMode=" << (manualMode ? "true" : "false")
					<< " oneBodyPerSheet=" << (automaticOneBodyPerSheet ? "true" : "false")
					<< " customSheetLayout=" << (automaticCustomSheetLayout ? "true" : "false");
				PerfDebugLog(perf.str());
			}
			if (automaticCustomSheetLayout)
			{
				SortSelectedObjectsByBodySizeDescending(objectsToProcess);
			}

			PropertyList* toggle0Props = toggle0->GetProperties();
			const int originalCreateSheet = toggle0Props->GetLogical("Value");
			delete toggle0Props;
			toggle0Props = NULL;

			const NXOpen::Point3d sheetCenter(297.0 / 2.0, 210.0 / 2.0, 0.0);
			const bool manualUseExistingSheet = manualMode && currentHasDrawingSheet && originalCreateSheet == 0;
			if (manualUseExistingSheet)
			{
				NXOpen::Body* manualBody = dynamic_cast<NXOpen::Body*>(NXOpen::NXObjectManager::Get(objectsToProcess[0]->Tag()));
				if (manualBody != NULL && PrepareBodyDraftingContext(manualBody, enum0, ACA))
				{
					Body1 = manualBody;
					g_manualPendingBody = manualBody;
					workPart->Drafting()->EnterDraftingApplication();
					ApplyDraftingDimensionStartupPreferences(workPart);
					if (point0 != NULL)
					{
						point0->SetShow(true);
					}
				}
				return;
			}
			g_hasAutoPlacementOverride = !manualUseExistingSheet;
			g_autoPlacementPoint = sheetCenter;
			g_hasPageScaleOverride = !manualUseExistingSheet;
			g_pageScaleOverride = 100.0;
			g_deferPageRefit = !manualUseExistingSheet;
			g_manualPlacementNoRefit = manualUseExistingSheet;
			g_sheetIsoAlreadyCreated = false;
			g_pendingScaleRefits.clear();
			const bool previousSuppressAaaaFlush = g_suppressAaaaWorkViewFlush;
			g_suppressAaaaWorkViewFlush = true;
			for (size_t batchStart = 0; batchStart < objectsToProcess.size(); batchStart += static_cast<size_t>(automaticBodiesPerSheet))
			{
				const size_t batchEnd = std::min(
					objectsToProcess.size(),
					batchStart + static_cast<size_t>(automaticBodiesPerSheet));
				std::vector<NXOpen::Body*> batchBodies;
				batchBodies.reserve(batchEnd - batchStart);
				for (size_t bodyIndex = batchStart; bodyIndex < batchEnd; ++bodyIndex)
				{
					NXOpen::Body* currentBody = dynamic_cast<NXOpen::Body*>(NXOpen::NXObjectManager::Get(objectsToProcess[bodyIndex]->Tag()));
					if (currentBody != NULL)
					{
						batchBodies.push_back(currentBody);
					}
				}
				g_deferPageRefit = !manualUseExistingSheet;
				g_pendingScaleRefits.clear();
				g_sheetIsoAlreadyCreated = false;
				LayerStateSnapshot automaticLayerSnapshot;
				bool automaticLayerIsolated = false;
				if (automaticMultiBodyPerSheet)
				{
					automaticLayerSnapshot = SaveCurrentLayerStates();
					ApplyBodyGroupLayerIsolation(batchBodies);
					automaticLayerIsolated = true;
				}
				for (size_t bodyIndex = batchStart; bodyIndex < batchEnd; ++bodyIndex)
				{
					NXOpen::Body* currentBody = dynamic_cast<NXOpen::Body*>(NXOpen::NXObjectManager::Get(objectsToProcess[bodyIndex]->Tag()));
					if (currentBody == NULL)
					{
						continue;
					}
					{
						std::ostringstream perf;
						perf << "[perf] body begin tag=" << PerfTagOf(currentBody)
							<< " batchStart=" << batchStart
							<< " bodyIndex=" << bodyIndex;
						PerfDebugLog(perf.str());
					}

					if (automaticOneBodyPerSheet && !automaticLayerIsolated)
					{
						automaticLayerSnapshot = SaveCurrentLayerStates();
						ApplyManualBodyLayerIsolation(currentBody);
						automaticLayerIsolated = true;
					}

					unsigned long long prepareStart = PerfNowMs();
					if (!PrepareBodyDraftingContext(currentBody, enum0, ACA))
					{
						std::ostringstream perf;
						perf << "[perf] PrepareBodyDraftingContext failed bodyTag=" << PerfTagOf(currentBody)
							<< " elapsedMs=" << (PerfNowMs() - prepareStart);
						PerfDebugLog(perf.str());
						if (automaticLayerIsolated)
						{
							RestoreLayerStates(automaticLayerSnapshot);
							automaticLayerIsolated = false;
						}
						continue;
					}
					{
						std::ostringstream perf;
						perf << "[perf] PrepareBodyDraftingContext bodyTag=" << PerfTagOf(currentBody)
							<< " elapsedMs=" << (PerfNowMs() - prepareStart);
						PerfDebugLog(perf.str());
					}
					if (automaticLayerIsolated)
					{
						ApplyBodyGroupLayerIsolation(batchBodies);
					}

					toggle0->SetValue(manualUseExistingSheet ? false : (bodyIndex == batchStart));
					unsigned long long aaaaStart = PerfNowMs();
					aaaa_cb();
					{
						std::ostringstream perf;
						perf << "[perf] aaaa_cb call bodyTag=" << PerfTagOf(currentBody)
							<< " elapsedMs=" << (PerfNowMs() - aaaaStart);
						PerfDebugLog(perf.str());
					}
				}
				g_deferPageRefit = false;
				if (!manualUseExistingSheet)
				{
					FinalizePendingGroupScaleAndLayout(workPart);
				}
				if (automaticLayerIsolated)
				{
					RestoreLayerStates(automaticLayerSnapshot);
					automaticLayerIsolated = false;
				}
			}
			g_suppressAaaaWorkViewFlush = previousSuppressAaaaFlush;
			FlushPendingWorkViewRegenerate(workPart);
			if (automaticOneBodyPerSheet || automaticCustomSheetLayout)
			{
				UpdateAllDraftingViewsOnAllSheets(workPart);
			}
			else
			{
				UpdateAllDraftingViewsOnCurrentSheet(workPart);
			}
			RestoreLayerStates(drawingLayerSnapshot);
			g_pendingScaleRefits.clear();
			g_sheetIsoAlreadyCreated = false;

			toggle0->SetValue(originalCreateSheet != 0);
			g_hasAutoPlacementOverride = false;
			g_autoPlacementPoint = { 0.0, 0.0, 0.0 };
			g_hasPageScaleOverride = false;
			g_pageScaleOverride = 20.0;
			g_manualPlacementNoRefit = false;
		};

		if (selectedObjects.empty())
		{
			if (!manualMode)
			{
				std::vector<NXOpen::Part*> assemblyParts = CollectDrawableAssemblyParts(workPart);
				if (!assemblyParts.empty())
				{
					NXOpen::BasePart* originalDisplayPart = theSession->Parts()->BaseDisplay();
					NXOpen::Part* originalWorkPart = theSession->Parts()->Work();
					for (size_t partIndex = 0; partIndex < assemblyParts.size(); ++partIndex)
					{
						NXOpen::Part* drawablePart = assemblyParts[partIndex];
						if (drawablePart == NULL)
						{
							continue;
						}

						NXOpen::PartLoadStatus* loadStatus = NULL;
						theSession->Parts()->SetDisplay(drawablePart, false, false, &loadStatus);
						if (loadStatus != NULL)
						{
							delete loadStatus;
							loadStatus = NULL;
						}
						workPart = theSession->Parts()->Work();
						displayPart = theSession->Parts()->Display();
						ApplyDraftingDimensionStartupPreferences(workPart);
						processSelectedObjects(CollectDrawableBodiesForPart(workPart));
					}

					NXOpen::PartLoadStatus* restoreLoadStatus = NULL;
					if (originalDisplayPart != NULL)
					{
						theSession->Parts()->SetDisplay(originalDisplayPart, false, false, &restoreLoadStatus);
					}
					if (restoreLoadStatus != NULL)
					{
						delete restoreLoadStatus;
						restoreLoadStatus = NULL;
					}
					if (originalWorkPart != NULL)
					{
						theSession->Parts()->SetWork(originalWorkPart);
					}
					workPart = theSession->Parts()->Work();
					displayPart = theSession->Parts()->Display();
					return 0;
				}

				selectedObjects = CollectDrawableBodiesForPart(workPart);
			}
			if (selectedObjects.empty())
			{
				return 0;
			}
		}

		processSelectedObjects(selectedObjects);

	}
	catch (exception& ex)
	{
		//---- Enter your exception handling code here -----
		errorCode = 1;
		g_suppressAaaaWorkViewFlush = false;
		FlushPendingWorkViewRegenerate(workPart);
		g_deferPageRefit = false;
		g_hasAutoPlacementOverride = false;
		g_hasPageScaleOverride = false;
		g_manualPlacementNoRefit = false;
		ZiDonCuTu::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
	}
	return errorCode;
}
