static NXOpen::Vector3d NormalizeVector(const NXOpen::Vector3d& value, const NXOpen::Vector3d& fallback)
{
	const double length = VectorLength(value);
	if (length > 1.0e-6)
	{
		return ScaleVector(value, 1.0 / length);
	}
	const double fallbackLength = VectorLength(fallback);
	if (fallbackLength > 1.0e-6)
	{
		return ScaleVector(fallback, 1.0 / fallbackLength);
	}
	return NXOpen::Vector3d(1.0, 0.0, 0.0);
}

static bool AskFaceUvFallbackDirection(NXOpen::Face* face, NXOpen::Vector3d& fallbackDirection)
{
	if (face == NULL)
	{
		return false;
	}

	double uvs[4];
	if (UF_MODL_ask_face_uv_minmax(face->Tag(), uvs) != 0)
	{
		return false;
	}

	double param[2];
	param[0] = (uvs[0] + uvs[1]) / 2.0;
	param[1] = (uvs[2] + uvs[3]) / 2.0;
	double point[3];
	double u1[3];
	double v1[3];
	double u2[3];
	double v2[3];
	double unitNorm[3];
	double radii[2];
	if (UF_MODL_ask_face_props(face->Tag(), param, point, u1, v1, u2, v2, unitNorm, radii) != 0)
	{
		return false;
	}

	NXOpen::Vector3d uDirection(u1[0], u1[1], u1[2]);
	NXOpen::Vector3d vDirection(v1[0], v1[1], v1[2]);
	if (VectorLength(uDirection) > 1.0e-6)
	{
		fallbackDirection = NormalizeVector(uDirection, NXOpen::Vector3d(1.0, 0.0, 0.0));
		return true;
	}
	if (VectorLength(vDirection) > 1.0e-6)
	{
		fallbackDirection = NormalizeVector(vDirection, NXOpen::Vector3d(0.0, 1.0, 0.0));
		return true;
	}
	return false;
}

static void ApplyPreferredIsoOrientation(NXOpen::Drawings::BaseViewBuilder* baseViewBuilder, bool useLongXAsVertical)
{
	if (baseViewBuilder == NULL || workPart == NULL)
	{
		return;
	}

	const NXOpen::Vector3d fallbackX(1.0, 0.0, 0.0);
	const NXOpen::Vector3d fallbackY(0.0, 1.0, 0.0);
	const NXOpen::Vector3d fallbackZ(0.0, 0.0, 1.0);

	NXOpen::Vector3d axisX = NormalizeVector(XDir, fallbackX);
	NXOpen::Vector3d axisY = NormalizeVector(YDir, fallbackY);
	NXOpen::Vector3d axisZ = CrossVector(axisX, axisY);
	if (VectorLength(axisZ) <= 1.0e-6)
	{
		axisZ = NormalizeVector(ZDire, fallbackZ);
	}
	else
	{
		axisZ = NormalizeVector(axisZ, fallbackZ);
	}

	const NXOpen::Vector3d upAxis = useLongXAsVertical ? axisX : axisY;
	const NXOpen::Vector3d acrossAxis = useLongXAsVertical ? axisY : axisX;

	NXOpen::Vector3d normalVector = NormalizeVector(AddVector(axisZ, acrossAxis), axisZ);
	NXOpen::Vector3d xDirectionVector = CrossVector(normalVector, upAxis);
	if (VectorLength(xDirectionVector) <= 1.0e-6)
	{
		xDirectionVector = acrossAxis;
	}
	xDirectionVector = NormalizeVector(xDirectionVector, acrossAxis);

	if (DotVector(xDirectionVector, acrossAxis) < 0.0)
	{
		xDirectionVector = ScaleVector(xDirectionVector, -1.0);
	}
	if (DotVector(normalVector, axisZ) < 0.0)
	{
		normalVector = ScaleVector(normalVector, -1.0);
		xDirectionVector = ScaleVector(xDirectionVector, -1.0);
	}

	const NXOpen::Point3d origin(0.0, 0.0, 0.0);
	NXOpen::Direction* normalDirection = workPart->Directions()->CreateDirection(origin, normalVector, NXOpen::SmartObject::UpdateOptionAfterModeling);
	NXOpen::Direction* xDirection = workPart->Directions()->CreateDirection(origin, xDirectionVector, NXOpen::SmartObject::UpdateOptionAfterModeling);
	baseViewBuilder->Style()->ViewStyleOrientation()->Ovt()->SetNormalDirection(normalDirection);
	baseViewBuilder->Style()->ViewStyleOrientation()->Ovt()->SetXDirection(xDirection);
}

static void ApplyTrimetricAxisSwapDirection(
	NXOpen::Drawings::BaseViewBuilder* baseViewBuilder,
	NXOpen::ModelingView* trimetricView)
{
	if (baseViewBuilder == NULL || trimetricView == NULL || workPart == NULL)
	{
		return;
	}

	const NXOpen::Vector3d fallbackZ(0.0, 0.0, 1.0);
	const NXOpen::Vector3d fallbackY(0.0, 1.0, 0.0);
	NXOpen::Vector3d normalVector = NormalizeVector(trimetricView->GetAxis(NXOpen::XYZAxisZAxis), fallbackZ);
	NXOpen::Vector3d swappedXVector = NormalizeVector(trimetricView->GetAxis(NXOpen::XYZAxisYAxis), fallbackY);

	const NXOpen::Point3d origin(0.0, 0.0, 0.0);
	NXOpen::Direction* normalDirection = workPart->Directions()->CreateDirection(origin, normalVector, NXOpen::SmartObject::UpdateOptionAfterModeling);
	NXOpen::Direction* xDirection = workPart->Directions()->CreateDirection(origin, swappedXVector, NXOpen::SmartObject::UpdateOptionAfterModeling);
	baseViewBuilder->Style()->ViewStyleOrientation()->Ovt()->SetNormalDirection(normalDirection);
	baseViewBuilder->Style()->ViewStyleOrientation()->Ovt()->SetXDirection(xDirection);
}


static bool PrepareBodyDraftingContext(NXOpen::Body* targetBody, NXOpen::BlockStyler::Enumeration* enum0Block, bool& acaFlag)
{
	std::ostringstream preparePerfLabel;
	preparePerfLabel << "PrepareBodyDraftingContext bodyTag=" << PerfTagOf(targetBody);
	ScopedPerfTimer preparePerfTimer(preparePerfLabel.str());

	if (targetBody == NULL)
	{

		return false;
	}

	g_skipSideViewsForCurrentBody = false;
	Body1 = targetBody;
	NXOpen::Face* face1 = NULL;
	NXOpen::CoordinateSystem* CoordinateSystem1 = NULL;
	NXOpen::Point3d origin5;
	const std::vector<FlatPatternDraftingInfo>& flatPatternInfos = GetFlatPatternDraftingInfos(workPart);
	vector<Face*>vFaces;
	NXMatrix* NXMatrix1 = NULL;
	bool hasValidFlatPatternFace = false;
	std::vector<NXOpen::Features::SheetMetal::SheetmetalBendState> cdcd;
	workPart->Features()->SheetmetalManager()->GetInnerBendFaces(Body1, vFaces, cdcd);

	for (size_t i = 0; i < flatPatternInfos.size(); i++)
	{
		const FlatPatternDraftingInfo& flatInfo = flatPatternInfos[i];
		if (flatInfo.upwardBody == NULL || Body1 == NULL || flatInfo.upwardBody->Tag() != Body1->Tag())
		{
			continue;
		}

		NXOpen::Features::FlatPattern* convertToSheetmetal1 = flatInfo.flatPattern;
		face1 = flatInfo.upwardFace;
		if (convertToSheetmetal1 == NULL || face1 == NULL)
		{
			continue;
		}

			Edge* Edge1 = NULL;
			Edge1 = flatInfo.xAxisEdge;

			NXOpen::Scalar* scalar1;
			scalar1 = workPart->Scalars()->CreateScalar(0.5, NXOpen::Scalar::DimensionalityTypeNone, NXOpen::SmartObject::UpdateOptionAfterModeling);

			NXOpen::Point* point1;
			point1 = workPart->Points()->CreatePoint(face1, scalar1, scalar1, NXOpen::SmartObject::UpdateOptionAfterModeling);

			NXOpen::Point3d origin5Local = point1->Coordinates();

			int Type, NormDir;
			double Point[3], Dir[3], Box[6], Radius[3], RadData[3];
			UF_MODL_ask_face_data(face1->Tag(), &Type, Point, Dir, Box, Radius, RadData, &NormDir);

			NXOpen::Vector3d normal5;
			if (Type != 16)
			{
				normal5 = { Dir[0],Dir[1],Dir[2] };
			}
			else
			{
				double uvs[4];
				UF_MODL_ask_face_uv_minmax(face1->Tag(), uvs);
				double param[2];
				param[0] = (uvs[0] + uvs[1]) / 2;
				param[1] = (uvs[2] + uvs[3]) / 2;
				double point[3];
				double u1[3];
				double v1[3];
				double u2[3];
				double v2[3];
				double unit_norm_local[3];
				double radii[2];
				UF_MODL_ask_face_props(face1->Tag(), param, point, u1, v1, u2, v2, unit_norm_local, radii);
				normal5 = { unit_norm_local[0] ,unit_norm_local[1],unit_norm_local[2] };
			}
			if (Edge1 != NULL)
			{
				Point3d P3d1, P3d2;
				Edge1->GetVertices(&P3d1, &P3d2);
				NXOpen::Vector3d edgeVector(P3d2.X - P3d1.X, P3d2.Y - P3d1.Y, P3d2.Z - P3d1.Z);
				if (VectorLength(edgeVector) <= 1.0e-6)
				{
					Edge1 = NULL;
				}
			}
			bool hasSideViewDirection = false;
			if (Edge1 != NULL)
			{
				Point3d P3d1, P3d2;
				Edge1->GetVertices(&P3d1, &P3d2);
				NXOpen::Point* Po1 = workPart->Points()->CreatePoint(P3d1);
				NXOpen::Point* Po2 = workPart->Points()->CreatePoint(P3d2);

				direction1 = workPart->Directions()->CreateDirection(Po2, Po1, SmartObject::UpdateOptionAfterModeling);
				hasSideViewDirection = (direction1 != NULL);
			}
			else
			{
				NXOpen::Vector3d faceUvDirection;
				if (AskFaceUvFallbackDirection(face1, faceUvDirection))
				{
					direction1 = workPart->Directions()->CreateDirection(origin5Local, faceUvDirection, NXOpen::SmartObject::UpdateOptionAfterModeling);
					hasSideViewDirection = (direction1 != NULL);
				}
				else
				{
					g_skipSideViewsForCurrentBody = true;
					direction1 = NULL;
				}
			}

			if (hasSideViewDirection)
			{
				NXOpen::Plane* plane1;
				plane1 = workPart->Planes()->CreatePlane(origin5Local, normal5, NXOpen::SmartObject::UpdateOptionAfterModeling);

				NXOpen::Xform* xform1;
				xform1 = workPart->Xforms()->CreateXformByPlaneXDirPoint(plane1, direction1, point1, NXOpen::SmartObject::UpdateOptionAfterModeling, 1.0, false, false);

				NXOpen::CartesianCoordinateSystem* cartesianCoordinateSystem1;
				cartesianCoordinateSystem1 = workPart->CoordinateSystems()->CreateCoordinateSystem(xform1, NXOpen::SmartObject::UpdateOptionAfterModeling);
				workPart->WCS()->SetCoordinateSystemCartesianAtCsys(cartesianCoordinateSystem1);
			}

			int aadd = 0;
			int aabb = 0;
			int aacc = 0;
			int aadd1 = 0;

			const bool flatPatternBelongsToBody = true;

			if (flatPatternBelongsToBody)
			{
				if (vFaces.empty())
				{
					aadd1 = 1;
				}
				doubleX = flatInfo.minimumX;
				doubleY = flatInfo.minimumY;
				StrZKname = flatInfo.flatPatternViewName;
				faceTag = face1->Tag();
				hasValidFlatPatternFace = true;
				NXOpen::Body* flatPatternFaceBody = (face1 != NULL) ? face1->GetBody() : NULL;
				const int flatPatternFaceBodyLayer = GetBodyLayer(flatPatternFaceBody);
				{
					std::ostringstream oss;
					oss << "[PrepareBodyDraftingContext] targetBodyTag=" << Body1->Tag()
						<< " targetBodyLayer=" << GetBodyLayer(Body1)
						<< " flatPatternFeatureTag=" << (flatInfo.feature != NULL ? flatInfo.feature->Tag() : NULL_TAG)
						<< " upwardFaceTag=" << (face1 != NULL ? face1->Tag() : NULL_TAG)
						<< " upwardFaceBodyTag=" << (flatPatternFaceBody != NULL ? flatPatternFaceBody->Tag() : NULL_TAG)
						<< " upwardFaceBodyLayer=" << flatPatternFaceBodyLayer
						<< " flatPatternViewName=" << StrZKname.GetLocaleText()
						<< " noBend=" << (vFaces.empty() ? "true" : "false");
					LayerDebugLog(oss.str());
				}
				if (flatPatternFaceBodyLayer >= UF_LAYER_MIN_LAYER && flatPatternFaceBodyLayer <= UF_LAYER_MAX_LAYER)
				{
					RememberBodyDraftingSourceBody(Body1, flatPatternFaceBody);
					std::vector<int> draftingLayers(1, flatPatternFaceBodyLayer);
					RememberBodyDraftingLayers(Body1, draftingLayers);
				}

				if (!g_skipSideViewsForCurrentBody)
				{
					CoordinateSystem1 = workPart->WCS()->CoordinateSystem();
					origin5 = CoordinateSystem1->Origin();
					NXMatrix1 = CoordinateSystem1->Orientation();
					CoordinateSystem1->GetDirections(&XDir, &YDir);
				}
				else
				{
					origin5 = NXOpen::Point3d(0.0, 0.0, 0.0);
					XDir = NXOpen::Vector3d(1.0, 0.0, 0.0);
					YDir = NXOpen::Vector3d(0.0, 1.0, 0.0);
					NXMatrix1 = NULL;
				}

				for (size_t C = 0; C < vFaces.size(); C++)
				{
					int type;
					double point[3];
					double dir[3];
					double box[6];
					double radius;
					double rad_data;
					int norm_dir;
					UF_MODL_ask_face_data(vFaces[C]->Tag(), &type, point, dir, box, &radius, &rad_data, &norm_dir);
					if (type == 16 && aadd == 0)
					{
						double dot = dir[0] * XDir.X + dir[1] * XDir.Y + dir[2] * XDir.Z;
						if (fabs(fabs(dot) - 1.0) < 0.0001)
						{
							aabb = 1;
						}
						if (fabs(dot) < 0.0001)
						{
							aacc = 1;
						}
					}
				}
			}
			if (acaFlag && enum0Block != NULL)
			{
				if (aabb == 1 && aacc == 0)
				{
					enum0Block->SetValueAsString("左");
				}
				if (aabb == 0 && aacc == 1)
				{
					enum0Block->SetValueAsString("下");
				}
				if (aabb == 1 && aacc == 1)
				{
					enum0Block->SetValueAsString("左下");
				}
				if (aadd1 == 1)
				{
					enum0Block->SetValueAsString("左");
				}
			}
			if (hasValidFlatPatternFace)
			{

				break;
			}
	}

	if (!hasValidFlatPatternFace || faceTag == NULL_TAG)
	{

		return false;
	}


	double uvs[4];
	UF_MODL_ask_face_uv_minmax(faceTag, uvs);
	double param[2];
	param[0] = (uvs[0] + uvs[1]) / 2;
	param[1] = (uvs[2] + uvs[3]) / 2;
	double u1[3];
	double v1[3];
	double u2[3];
	double v2[3];
	double radii[2];
	UF_MODL_ask_face_props(faceTag, param, pointAC, u1, v1, u2, v2, unit_norm, radii);

	if (NXMatrix1 != NULL)
	{
		NXOpen::CartesianCoordinateSystem* cartesianCoordinateSystem1;
		cartesianCoordinateSystem1 = workPart->CoordinateSystems()->CreateCoordinateSystem(origin5, NXMatrix1, true);
		workPart->WCS()->SetCoordinateSystemCartesianAtCsys(cartesianCoordinateSystem1);
	}
	else
	{
		NXOpen::Point3d orig(0.0, 0.0, 0.0);
		NXOpen::Matrix3x3 identityMatrix;
		identityMatrix.Xx = 1.0; identityMatrix.Xy = 0.0; identityMatrix.Xz = 0.0;
		identityMatrix.Yx = 0.0; identityMatrix.Yy = 1.0; identityMatrix.Yz = 0.0;
		identityMatrix.Zx = 0.0; identityMatrix.Zy = 0.0; identityMatrix.Zz = 1.0;
		workPart->WCS()->SetOriginAndMatrix(orig, identityMatrix);
	}
	workPart->WCS()->Rotate(NXOpen::WCS::AxisZAxis, 50.85988015);
	workPart->WCS()->Rotate(NXOpen::WCS::AxisXAxis, 67.94977390);

	NXOpen::NXMatrix* Matrix1 = workPart->WCS()->CoordinateSystem()->Orientation();
	NXOpen::Matrix3x3 Matrix3A = Matrix1->Element();
	XDir1.X = Matrix3A.Xx; XDir1.Y = Matrix3A.Xy; XDir1.Z = Matrix3A.Xz;
	ZDire.X = Matrix3A.Zx; ZDire.Y = Matrix3A.Zy; ZDire.Z = Matrix3A.Zz;

	NXOpen::Point3d orig(0.0, 0.0, 0.0);
	NXOpen::Matrix3x3 matrix1;
	matrix1.Xx = 1.0; matrix1.Xy = 0.0; matrix1.Xz = 0.0;
	matrix1.Yx = 0.0; matrix1.Yy = 1.0; matrix1.Yz = 0.0;
	matrix1.Zx = 0.0; matrix1.Zy = 0.0; matrix1.Zz = 1.0;
	workPart->WCS()->SetOriginAndMatrix(orig, matrix1);
	return true;
}

static void ApplyViewLayerIsolation(NXOpen::Drawings::BaseView* baseView, NXOpen::Body* body)
{
	if (baseView == NULL || body == NULL)
	{
		return;
	}
	const std::vector<int> draftingLayers = GetPreferredBodyDraftingLayers(body);
	if (draftingLayers.empty())
	{
		return;
	}
	{
		std::ostringstream oss;
		oss << "[ApplyViewLayerIsolation] viewTag=" << baseView->Tag()
			<< " bodyTag=" << body->Tag()
			<< " keepLayers=" << DebugLayers(draftingLayers)
			<< " plus=[1,230]";
		LayerDebugLog(oss.str());
	}
	std::vector<NXOpen::Layer::StateInfo> stateArray(256);
	for (int i = 0; i < 256; ++i)
	{
		const int layer = i + 1;
		const bool keepVisible = (std::find(draftingLayers.begin(), draftingLayers.end(), layer) != draftingLayers.end() || layer == 1 || layer == 230);
		stateArray[i] = NXOpen::Layer::StateInfo(layer, keepVisible ? NXOpen::Layer::StateVisible : NXOpen::Layer::StateHidden);
	}
	workPart->Layers()->SetObjectsVisibilityOnLayer(baseView, stateArray, true);

	int viewMask[256] = { 0 };
	for (int i = 0; i < 256; ++i)
	{
		const int layer = i + 1;
		viewMask[i] = (std::find(draftingLayers.begin(), draftingLayers.end(), layer) != draftingLayers.end() || layer == 1 || layer == 230) ? 1 : 0;
	}

	char viewName[UF_OBJ_NAME_BUFSIZE] = { 0 };
	if (UF_OBJ_ask_name(baseView->Tag(), viewName) == 0 && viewName[0] != '\0')
	{
		const int maskResult = uc6447(viewName, 2, viewMask);
		std::ostringstream oss;
		oss << "[ApplyViewLayerIsolation.uc6447] viewTag=" << baseView->Tag()
			<< " viewName=" << viewName
			<< " result=" << maskResult;
		LayerDebugLog(oss.str());
	}
	else
	{
		std::ostringstream oss;
		oss << "[ApplyViewLayerIsolation.uc6447] viewTag=" << baseView->Tag()
			<< " viewName=<empty> skipped";
		LayerDebugLog(oss.str());
	}
}

static void ApplyCurrentBodySideViewLayerIsolation()
{
	for (size_t viewIndex = 0; viewIndex < BaseViewvector.size(); ++viewIndex)
	{
		ApplyViewLayerIsolation(BaseViewvector[viewIndex], Body1);
	}
}

static void ApplySideViewLayerIsolationForBody(
	NXOpen::Body* body,
	const std::vector<NXOpen::Drawings::BaseView*>& sideViews)
{
	for (size_t viewIndex = 0; viewIndex < sideViews.size(); ++viewIndex)
	{
		ApplyViewLayerIsolation(sideViews[viewIndex], body);
	}
}

