//------------------------------------------------------------------------------
//Callback Name: update_cb
//------------------------------------------------------------------------------
int ZiDonCuTu::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
	const char* phase = "enter";
	const char* blockName = "unknown";
	try
	{
		if (block == toggle0)
		{
			blockName = "toggle0";
			phase = "toggle0.getProperties";
			if (IsManualDrawingMode(enumDrawingMode))
			{
				const bool hasDrawingSheet = HasAnyDrawingSheet(workPart);
				PropertyList* toggle0Props = toggle0->GetProperties();
				int Thetoggle0 = toggle0Props->GetLogical("Value");
				delete toggle0Props;
				toggle0Props = NULL;
				if (!hasDrawingSheet && Thetoggle0 == 0)
				{
					toggle0->SetValue(true);
					Thetoggle0 = 1;
				}
				point0->SetShow(Thetoggle0 == 0);
				return 0;
			}
			//获取创建图纸页开关值
			PropertyList* toggle0Props = toggle0->GetProperties();
			int Thetoggle0 = toggle0Props->GetLogical("Value");
			delete toggle0Props;
			toggle0Props = NULL;
			if (Thetoggle0)//创建图纸页为真
			{
				point0->SetShow(false);//关闭点选择控件
			}
			else
			{
				point0->SetShow(true);//显示点选择控件
			}
		}
		else if (block == enumDrawingMode)
		{
			blockName = "enumDrawingMode";
			phase = "enumDrawingMode";
			const bool manualMode = IsManualDrawingMode(enumDrawingMode);
			const bool hasDrawingSheet = HasAnyDrawingSheet(workPart);
			UpdateSheetLayoutControls(enumSheetLayout, integerSheetPartCount, toggle01, !manualMode);
			SetBodySelectionMode(selection0, manualMode);
			if (manualMode)
			{
				g_manualActionCompleted = false;
				toggle0->SetShow(true);
				toggle0->SetValue(!hasDrawingSheet);
				point0->SetShow(hasDrawingSheet);
			}
			else
			{
				g_manualActionCompleted = false;
				toggle0->SetShow(false);
				point0->SetShow(false);
			}
		}
		else if (block == enumSheetLayout)
		{
			blockName = "enumSheetLayout";
			phase = "enumSheetLayout";
			UpdateSheetLayoutControls(enumSheetLayout, integerSheetPartCount, toggle01, !IsManualDrawingMode(enumDrawingMode));
		}
		else if (block == enum01)
		{
			blockName = "enum01";
			phase = "enum01";
			//---------Enter your code here-----------
		}
		else if (block == toggle01)
		{
			blockName = "toggle01";
			phase = "toggle01";
			if (enum01 != NULL)
			{
				enum01->SetShow(false);
			}
		}
		else if (block == toggleHoleCoordinate)
		{
			blockName = "toggleHoleCoordinate";
			phase = "toggleHoleCoordinate";
		}
		else if (block == toggleHoleAttribute)
		{
			blockName = "toggleHoleAttribute";
			phase = "toggleHoleAttribute";
			UpdateHoleMarkerControls(toggleHoleAttribute, stringHoleMarker);
		}
		else if (block == buttonNoteFormatConfig)
		{
			blockName = "buttonNoteFormatConfig";
			phase = "buttonNoteFormatConfig";
			OpenBodyNoteConfigFile();
		}
		else if (block == enumProjection)
		{
			blockName = "enumProjection";
			phase = "enumProjection";
			//---------Enter your code here-----------
		}
		else if (block == enum0)
		{
			blockName = "enum0";
			phase = "enum0";
			//---------Enter your code here-----------
			ACA = false;
		}
		else if (block == selection0)
		{
			blockName = "selection0";
			phase = "selection0.changed";
			if (IsManualDrawingMode(enumDrawingMode))
			{
				PropertyList* selection0Props = selection0->GetProperties();
				std::vector<NXOpen::TaggedObject*> selectedObjects = selection0Props->GetTaggedObjectVector("SelectedObjects");
				delete selection0Props;
				selection0Props = NULL;
				if (selectedObjects.empty())
				{
					return 0;
				}

				NXOpen::Body* selectedBody = dynamic_cast<NXOpen::Body*>(NXOpen::NXObjectManager::Get(selectedObjects[0]->Tag()));
				if (selectedBody == NULL)
				{
					return 0;
				}
				if (!PrepareBodyDraftingContext(selectedBody, enum0, ACA))
				{
					return 0;
				}
				Body1 = selectedBody;
				g_manualPendingBody = selectedBody;
				g_manualActionCompleted = false;
				workPart->Drafting()->EnterDraftingApplication();
				ApplyDraftingDimensionStartupPreferences(workPart);

				const bool hasDrawingSheet = HasAnyDrawingSheet(workPart);
				int Thetoggle0 = hasDrawingSheet ? 0 : 1;
				if (toggle0 != NULL && point0 != NULL)
				{
					PropertyList* toggle0Props = toggle0->GetProperties();
					Thetoggle0 = toggle0Props->GetLogical("Value");
					delete toggle0Props;
					toggle0Props = NULL;
					if (!hasDrawingSheet && Thetoggle0 == 0)
					{
						toggle0->SetValue(true);
						Thetoggle0 = 1;
					}
					point0->SetShow(Thetoggle0 == 0);
				}
				if (Thetoggle0 != 0)
				{
					const NXOpen::Point3d sheetCenter(297.0 / 2.0, 210.0 / 2.0, 0.0);
					g_hasAutoPlacementOverride = true;
					g_autoPlacementPoint = sheetCenter;
					g_hasPageScaleOverride = true;
					g_pageScaleOverride = 100.0;
					g_deferPageRefit = true;
					g_manualPlacementNoRefit = false;
					g_sheetIsoAlreadyCreated = false;
					g_pendingScaleRefits.clear();
					LayerStateSnapshot layerSnapshot = SaveCurrentLayerStates();
					ApplyManualBodyLayerIsolation(selectedBody);
					try
					{
						aaaa_cb();
						g_deferPageRefit = false;
						FinalizePendingGroupScaleAndLayout(workPart);
					}
					catch (...)
					{
						RestoreLayerStates(layerSnapshot);
						g_deferPageRefit = false;
						g_hasAutoPlacementOverride = false;
						g_autoPlacementPoint = { 0.0, 0.0, 0.0 };
						g_hasPageScaleOverride = false;
						g_manualPlacementNoRefit = false;
						throw;
					}
					RestoreLayerStates(layerSnapshot);
					g_pendingScaleRefits.clear();
					g_sheetIsoAlreadyCreated = false;
					g_hasAutoPlacementOverride = false;
					g_autoPlacementPoint = { 0.0, 0.0, 0.0 };
					g_hasPageScaleOverride = false;
					g_pageScaleOverride = 20.0;
					g_manualPlacementNoRefit = false;
					g_manualActionCompleted = true;
				}
			}
		}

		else if (block == point0)
		{
			blockName = "point0";
			phase = "point0.changed";
			if (IsManualDrawingMode(enumDrawingMode))
			{
				if (g_manualActionCompleted)
				{
					return 0;
				}
				NXOpen::Body* selectedBody = g_manualPendingBody;
				if (selectedBody == NULL)
				{
					PropertyList* selection0Props = selection0->GetProperties();
					std::vector<NXOpen::TaggedObject*> selectedObjects = selection0Props->GetTaggedObjectVector("SelectedObjects");
					delete selection0Props;
					selection0Props = NULL;
					if (!selectedObjects.empty())
					{
						selectedBody = dynamic_cast<NXOpen::Body*>(NXOpen::NXObjectManager::Get(selectedObjects[0]->Tag()));
					}
				}
				if (selectedBody == NULL)
				{
					return 0;
				}
				if (!PrepareBodyDraftingContext(selectedBody, enum0, ACA))
				{
					return 0;
				}
				Body1 = selectedBody;
				NXOpen::Point3d manualPlacementPoint(297.0 / 2.0, 210.0 / 2.0, 0.0);
				TryReadSpecifyPoint(point0, manualPlacementPoint);
				g_hasAutoPlacementOverride = true;
				g_autoPlacementPoint = manualPlacementPoint;
				g_hasPageScaleOverride = false;
				g_deferPageRefit = false;
				g_manualPlacementNoRefit = true;
				if (toggle0 != NULL)
				{
					toggle0->SetValue(false);
				}
				LayerStateSnapshot layerSnapshot = SaveCurrentLayerStates();
				ApplyManualBodyLayerIsolation(selectedBody);
				try
				{
					aaaa_cb();
				}
				catch (...)
				{
					RestoreLayerStates(layerSnapshot);
					g_hasAutoPlacementOverride = false;
					g_autoPlacementPoint = { 0.0, 0.0, 0.0 };
					g_manualPlacementNoRefit = false;
					throw;
				}
				RestoreLayerStates(layerSnapshot);
				g_hasAutoPlacementOverride = false;
				g_autoPlacementPoint = { 0.0, 0.0, 0.0 };
				g_manualPlacementNoRefit = false;
				g_manualActionCompleted = true;
			}
		}


		return 0;
	}
	catch (NXOpen::NXException& ex)
	{
		(void)ex;
		return 1;
	}
	catch (exception& ex)
	{
		(void)ex;
		return 1;
	}
	catch (...)
	{
		return 1;
	}
}

int ZiDonCuTu::filter_cb(NXOpen::BlockStyler::UIBlock* block, NXOpen::TaggedObject* selectedObject)
{
	try
	{
		if (block != selection0)
		{
			return UF_UI_SEL_ACCEPT;
		}
		NXOpen::Body* body = dynamic_cast<NXOpen::Body*>(selectedObject);
		if (body == NULL)
		{
			return UF_UI_SEL_REJECT;
		}
		return IsSheetMetalBody(body) ? UF_UI_SEL_ACCEPT : UF_UI_SEL_REJECT;
	}
	catch (const NXOpen::NXException&)
	{
		return UF_UI_SEL_REJECT;
	}
	catch (...)
	{
		return UF_UI_SEL_REJECT;
	}
}

//------------------------------------------------------------------------------
//Callback Name: ok_cb
//------------------------------------------------------------------------------
int ZiDonCuTu::ok_cb()
{
	int errorCode = 0;
	try
	{
		if (IsManualDrawingMode(enumDrawingMode))
		{
			if (g_manualActionCompleted)
			{
				if (toggle0 != NULL)
				{
					PropertyList* toggle0Props = toggle0->GetProperties();
					int createSheet = toggle0Props->GetLogical("Value");
					delete toggle0Props;
					toggle0Props = NULL;
					if (createSheet != 0)
					{
						theSession->ApplicationSwitchImmediate("UG_APP_MODELING");
						return 0;
					}
				}
				workPart->Drafting()->EnterDraftingApplication();
				return 0;
			}
			if (toggle0 != NULL && HasAnyDrawingSheet(workPart))
			{
				PropertyList* toggle0Props = toggle0->GetProperties();
				int createSheet = toggle0Props->GetLogical("Value");
				delete toggle0Props;
				toggle0Props = NULL;
				if (createSheet == 0)
				{
					workPart->Drafting()->EnterDraftingApplication();
					return 0;
				}
			}
		}
		errorCode = apply_cb();
		if (IsManualDrawingMode(enumDrawingMode))
		{
			workPart->Drafting()->EnterDraftingApplication();
		}
	}
	catch (exception& ex)
	{
		//---- Enter your exception handling code here -----
		errorCode = 1;
		ZiDonCuTu::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
	}
	return errorCode;
}

