						rapidDimensionBuilder1->Measurement()->SetMethod(NXOpen::Annotations::DimensionMeasurementBuilder::MeasurementMethodVertical);
						NXOpen::Point3d Originpoint1;
						Originpoint1 = { aMin_X - 8,aMin_Y - 8,0 };
