void ZiDonCuTu::UF_MODL_ask_edge_is_outer_boundary(NXOpen::Face* face1, std::vector<Edge*> &AllEdge)//获得面的外围边
{
	if (face1 == NULL)
	{
		return;
	}

	std::vector<Edge*> faceEdges = face1->GetEdges();
	for (size_t i = 0; i < faceEdges.size(); ++i)
	{
		if (faceEdges[i] != NULL)
		{
			AllEdge.push_back(faceEdges[i]);
		}
	}
}
